def resolve_project_logs_base_directory(
    optional_override_base_directory_path: str | None = None
) -> str:
    """
    Resolves the base directory under which all game log subdirectories
    (per-game timestamped folders, per-round folders, screenplay HTML, zip
    archives) will be written.

    Resolution order (first match wins):
        1. If `optional_override_base_directory_path` is provided, use it.
        2. If running inside Google Colab, use '/content/logs'
           (Colab's standard writable working directory, visible in
           the Colab file browser).
        3. Otherwise (local machine, server, CI, etc.), use a 'logs'
           directory placed next to the currently running script file.
           If __file__ is not available (e.g. interactive REPL),
           fall back to a 'logs' directory under the current working
           directory.

    The directory is created if it does not exist.

    Args:
        optional_override_base_directory_path (str | None):
            Explicit path to use instead of auto-detection. Useful for
            tests or for users who want logs written to a specific drive.

    Returns:
        str: An absolute path to an existing, writable base logs directory.

    Raises:
        OSError: If the chosen directory cannot be created or is not writable.
    """
    try:
        # 1. Explicit override always wins
        if optional_override_base_directory_path is not None:
            chosen_base_directory_path = os.path.abspath(
                optional_override_base_directory_path
            )

        # 2. Detect Google Colab by checking for its module
        elif "google.colab" in sys.modules:
            chosen_base_directory_path = "/content/logs"

        # 3. Local fallback: 'logs' next to the script file
        else:
            try:
                script_file_directory_path = os.path.dirname(
                    os.path.abspath(__file__)
                )
            except NameError:
                # __file__ undefined (e.g. interactive Python session)
                script_file_directory_path = os.getcwd()

            chosen_base_directory_path = os.path.join(
                script_file_directory_path, "logs"
            )

        # Ensure the directory exists
        os.makedirs(chosen_base_directory_path, exist_ok=True)

        # Verify writability with a clear error message if not writable
        if not os.access(chosen_base_directory_path, os.W_OK):
            raise OSError(
                f"Resolved logs base directory is not writable: "
                f"{chosen_base_directory_path}"
            )

        return chosen_base_directory_path

    except Exception as base_directory_resolution_error:
        print(
            f"[Critical Error] Could not resolve project logs base directory: "
            f"{base_directory_resolution_error}"
        )
        traceback.print_exc()
        raise

