def make_round_set_bundles(action_dict_list: list) -> tuple:
    """
    Bundles a linear list of action dictionaries into sets representing a full round of turns.

    For a 5-player game, each round consists of 5 player actions. This function takes
    a flat list of player actions (formatted as one_player_action_data_dict) and chunks them
    into lists of 5. It then appends the necessary game-engine steps ('NPC moves',
    'resonance_effect', 'check_end_of_game') to each round bundle to complete the sequence.

    Args:
        action_dict_list (list): A list of dictionaries, where each dict represents
                                 one player's action for a turn.

    Returns:
        tuple: ('success', list_of_round_bundles) if successful,
               ('error', error_message_string) if the list length is not divisible by 5.
    """
    try:
        new_rounds_bundle_list_of_lists = []

        # 1. Check if the total number of actions is a multiple of 5 (one per player)
        modulo_five = len(action_dict_list) % 5
        if modulo_five != 0:
            return "error", "move sequence error: not one move per player"

        # 2. Determine how many rounds (bundles) we have
        number_of_sections = len(action_dict_list) // 5
        from_index = 0
        to_index = 5

        # 3. Create each bundle
        for _ in range(number_of_sections):
            new_round_bundle = []

            # Extract the 5 player actions for this round
            this_slice = action_dict_list[from_index:to_index]
            new_round_bundle.append(this_slice)

            # Append engine-level phases that happen after players act
            new_round_bundle.append("NPC moves")
            new_round_bundle.append("resonance_effect")
            new_round_bundle.append("check_end_of_game")

            # Add the completed bundle to our master list
            new_rounds_bundle_list_of_lists.append(new_round_bundle)

            # Increment indices for the next round
            from_index += 5
            to_index += 5

        return "success", new_rounds_bundle_list_of_lists

    except:
        return "error", "move sequence error"

