# Uses, not replaces, make_dungeon_room()

def generate_deterministic_dungeon_room(
    random_seed_integer: int,
    number_of_treasures_integer: int = 1,
    number_of_npc_integer: int = 1,
    types_of_npc_integer: int = 1,
    number_of_items_integer: int = 0
) -> tuple:
    """
    Generates a deterministic dungeon room by setting a random seed before calling
    the underlying room generation function.

    Args:
        random_seed_integer (int): The seed value to ensure deterministic, reproducible generation.
        number_of_treasures_integer (int): Quantity of treasures to place.
        number_of_npc_integer (int): Quantity of NPCs to place.
        types_of_npc_integer (int): Number of NPC types available.
        number_of_items_integer (int): Quantity of miscellaneous items.

    Returns:
        tuple: (room_array_list, room_metadata_dict)
    """
    try:
        print(f"[Setup] Initializing random seed to: {random_seed_integer}")
        random.seed(random_seed_integer)

        # Call the existing room generation function
        generated_room_array, generated_room_metadata_dict = make_dungeon_room(
            number_of_treasures=number_of_treasures_integer,
            number_of_npc=number_of_npc_integer,
            types_of_npc=types_of_npc_integer,
            number_of_items=number_of_items_integer
        )

        return generated_room_array, generated_room_metadata_dict

    except Exception as room_generation_error:
        print(f"[Critical Error] Failed to generate deterministic room: {room_generation_error}")
        traceback.print_exc()
        return [], {}

def build_initial_roomstory_statedictionary(
    starting_room_array: list,
    starting_room_metadata_dict: dict
) -> dict:
    """
    Acts as the 'Bridge' to translate raw generation output into the
    room_story_state_dict required by the game loop.

    Updated Version: Implements 'Direct Name Storage' to ensure player labels
    ('a', 'b', etc.) are stored directly within the state object for easier inspection.

    Args:
        starting_room_array (list): The 2D grid of the room.
        starting_room_metadata_dict (dict): The metadata defining object elements and properties.

    Returns:
        dict: A complete room_story_state_dict
    """
    try:
        print("[Setup] Building initial room_story_state_dict with Direct Name Storage...")

        # Initialize the core structure
        room_story_state_dict = {
            'turn_number_from_1': 1,
            'turn_number_from_0': 0,
            'room_array': copy.deepcopy(starting_room_array),
            'player_move_list': [],
            'piece_player_movements': [],
            'resonance_interactions_this_turn_start_items': {},
            'resonance_interactions_this_turn_start_map': {},
            'room_goal_status': False,
            'left_room_status': False,
            'error_log': [],
            'object_state': {
                'player_character_state': {},
                'npc_state': {},
                'treasure_chest_state': {}
            }
        }

        # Retrieve the mappings and data dictionaries from metadata
        all_objects_data_dictionary = starting_room_metadata_dict.get('all_room_objects_data_dict', {})
        player_id_to_label_map = {v: k for k, v in starting_room_metadata_dict.get('player_turn_map', {}).items()}

        # Parse the raw metadata to populate specific state sub-dictionaries
        for object_id_integer, object_properties_dictionary in all_objects_data_dictionary.items():
            object_id_string = str(object_id_integer)
            object_type_string = object_properties_dictionary.get('type', 'unknown')
            object_element_string = object_properties_dictionary.get('element', 'none')
            starting_energy_integer = object_properties_dictionary.get('energy', 1)

            if object_type_string == 'player_character':
                # Retrieve the human-readable label ('a', 'b', etc.) from the inverse map
                player_label = player_id_to_label_map.get(object_id_integer, f"PC_{object_id_string}")

                # Store state using the integer ID as the key, but include the label in 'name'
                room_story_state_dict['object_state']['player_character_state'][object_id_string] = {
                    'name': player_label,
                    'absorbed': False,
                    'inventory': [],
                    'element': object_element_string,
                    'energy': starting_energy_integer,
                    'exited_room': False
                }

            elif object_type_string == 'npc':

                # use seed to pick random starting direction
                start_directions_list = ['south', 'west', 'north', 'east', ]
                start_direction_pick = random.choice(start_directions_list)

                # use seed to pick random collision-bounce-direction
                colision_directions_list = ['left', 'right', 'opposite', ]
                colision_direction_pick = random.choice(colision_directions_list)

                room_story_state_dict['object_state']['npc_state'][object_id_string] = {
                    'absorbed': False,
                    'inventory': [],
                    'element': object_element_string,
                    'energy': starting_energy_integer,
                    'movement': {
                        'speed_1': 1,
                        'current_direction': start_direction_pick, # e.g. 'east'
                        'colision_behavior': colision_direction_pick, # e.g. 'opposite'
                    }
                }

            elif object_type_string == 'treasure':
                room_story_state_dict['object_state']['treasure_chest_state'][object_id_string] = {
                    'absorbed': False,
                    'inventory': ['treasure'],
                    'element': object_element_string,
                    'energy': starting_energy_integer
                }

        print("[Setup] room_story_state_dict successfully built with integrated player names.")
        return room_story_state_dict

    except Exception as dictionary_build_error:
        print(f"[Critical Error] Failed to build state dictionary: {dictionary_build_error}")
        traceback.print_exc()
        return {}



def test_initial_energy_assignment():
    """
    Tests the initial state generation to ensure all players start with 1 energy.
    """
    try:
        print("--- Testing Initial Energy Assignment ---")

        # 1. Generate a deterministic room
        room_array, room_meta = generate_deterministic_dungeon_room(
            random_seed_integer=99,
            number_of_treasures_integer=1,
            number_of_npc_integer=1,
            types_of_npc_integer=1
        )

        # 2. Build the initial state dictionary
        state_dict = build_initial_roomstory_statedictionary(room_array, room_meta)

        # 3. Check player energies
        pc_state = state_dict.get('object_state', {}).get('player_character_state', {})

        all_have_one_energy = True
        for p_id, p_data in pc_state.items():
            energy = p_data.get('energy')
            print(f"Player ID {p_id} initial energy: {energy}")
            if energy != 1:
                all_have_one_energy = False
                print(f"[ERROR] Player {p_id} did not start with 1 energy!")

        if all_have_one_energy:
            print("[SUCCESS] All players initialized with exactly 1 energy.")
        else:
            print("[FAILURE] One or more players have incorrect initial energy.")

    except Exception as e:
        print(f"Test failed: {e}")
        traceback.print_exc()

test_initial_energy_assignment()

