def validate_exit_room(
        player_id: str,
        current_coord: list,
        room_story_state_dict: dict,
) -> bool:
    """
    Validates an 'exit_room' action, checking if a player can successfully leave the dungeon room.

    To successfully exit, a player must be standing exactly on the designated door coordinate
    and must expend 1 energy to perform the exiting maneuver.

    Validation Rules Enforced:
    1. Energy Check: The player must have at least 1 energy point remaining to exit.
    2. Position Verification: The player's current coordinates must exactly match the room's door coordinates.

    Args:
        player_id (str): The string identifier of the player attempting to exit (e.g., 'a').
        current_coord (list): The [row, column] current coordinates of the player.
        room_story_state_dict (dict): The master state dictionary containing entity energy and metadata.

    Returns:
        bool: True if the player is at the door with sufficient energy, False otherwise.
    """
    try:
        from_row, from_col = current_coord
        room_metadata_dict = room_story_state_dict['room_metadata_dict']

        # 1. Check if player has enough energy using internal ID
        pc_state = room_story_state_dict.get('object_state', {}).get('player_character_state', {})
        expected_id = room_metadata_dict.get('player_turn_map', {}).get(player_id, player_id)
        if pc_state.get(str(expected_id), {}).get('energy', 0) < 1:
            print(f"Move invalid: Player {player_id} has insufficient energy to exit.")
            return False

        # 2. Get door location
        door_row, door_col = room_metadata_dict['door_relative_position']

        # 3. Check if the player is at the door location
        if from_row != door_row or from_col != door_col:
            print(f"Move invalid: Player {player_id} is not at the door location ({door_row}, {door_col}).")
            return False

        return True
    except Exception as e:
        print(f"Error in validate_exit_room: {e}")
        traceback.print_exc()
        return False

def validatemove_self(
    player_id: str,
    move_from_coord: list,
    move_to_coord: list,
    room_story_state_dict: dict,
    room_array: list,
    room_metadata_dict: dict = None
) -> bool:
    """
    Validates a 'move' (or 'move_self') action for a player character.

    This function rigorously checks the physical and energy constraints required
    for a player to move from one adjacent cell to another within the room.

    Validation Rules Enforced:
    1. Energy Check: The player must have at least 1 energy point to perform a physical move.
    2. Boundary Check: The intended destination must fall strictly within the 8x8 grid (indices 0-7).
    3. Occupancy Check: The intended destination cell must be entirely empty (an empty string '').
    4. Adjacency Check: The destination cell must be exactly one step away (horizontally, vertically, or diagonally).
    5. Origin Verification: The player must actually reside at the specified starting coordinates.

    Args:
        player_id (str): The string identifier of the player attempting to move (e.g., 'a', 'b').
        move_from_coord (list): The [row, column] starting coordinates of the player.
        move_to_coord (list): The [row, column] intended destination coordinates.
        room_story_state_dict (dict): The master dictionary containing current game state, including entity energy.
        room_array (list): The 2D grid array representing physical space in the room.
        room_metadata_dict (dict, optional): Metadata mapping string IDs to internal integer IDs.

    Returns:
        bool: True if the move strictly adheres to all constraints, False otherwise.
    """
    try:
        pc_state = room_story_state_dict.get('object_state', {}).get('player_character_state', {})

        expected_id = player_id
        if room_metadata_dict:
            expected_id = room_metadata_dict.get('player_turn_map', {}).get(player_id, player_id)

        # 1. Check if player has enough energy
        if pc_state.get(str(expected_id), {}).get('energy', 0) < 1:
            print(f"Move invalid: Player {player_id} has insufficient energy to move.")
            return False

        from_row, from_col = move_from_coord
        to_row, to_col = move_to_coord

        # 2. Check if the move is within the room bounds
        if not (0 <= to_row < len(room_array) and 0 <= to_col < len(room_array[0])):
            print(f"Move invalid: Move_to location ({to_row}, {to_col}) is out of bounds.")
            return False

        # 3. Check if the target location is empty
        if room_array[to_row][to_col] != '':
            print(f"Move invalid: Move_to location ({to_row}, {to_col}) is not empty.")
            return False

        # 4. Check if the move is to an adjacent square
        if abs(from_row - to_row) > 1 or abs(from_col - to_col) > 1:
            print(f"Move invalid: Player {player_id} can only move to an adjacent square.")
            return False

        # 5. Check if the player is actually at the starting position
        actual_id = room_array[from_row][from_col]
        if str(actual_id) != str(expected_id):
            print(f"Move invalid: Player {player_id} (expected array ID {expected_id}) is not at starting location ({from_row}, {from_col}). Found {actual_id} instead.")
            return False

        return True
    except Exception as e:
        print(f"Error in validatemove_self: {e}")
        traceback.print_exc()
        return False

def validate_throw(
    player_id: str,
    throw_from_coord: list | None,
    throw_to_coord: list,
    current_room_grid_array_list: list,
    room_metadata_dict: dict,
    room_story_state_dict: dict,
    throw_inventory_index: int | None = None
) -> bool:
    """
    Validates the physical and logical requirements for a player to throw an object.

    A player can throw an object from two sources:
    1. From the grid: The target object must be directly adjacent to the player.
    2. From inventory: The player must have a valid item at the specified index.
    In both cases, the destination landing zone must be strictly within the 8x8 grid
    and completely empty.

    Args:
        player_id (str): The string identifier of the player attempting to throw (e.g., 'a').
        throw_from_coord (list | None): The [row, column] coordinates of the target object on the grid.
        throw_to_coord (list): The [row, column] coordinates where the object should land.
        current_room_grid_array_list (list): The 2D grid array representing physical space.
        room_metadata_dict (dict): Metadata mapping string IDs to internal integer IDs.
        room_story_state_dict (dict): Master state dictionary to access inventory and status.
        throw_inventory_index (int | None): The index of the item in the player's inventory to throw.

    Returns:
        bool: True if the throw action is physically and logically valid, False otherwise.
    """
    try:
        # 1. Landing Zone Validation (Common to both throw types)
        destination_row_integer, destination_column_integer = throw_to_coord
        grid_size_integer = len(current_room_grid_array_list)

        if not (0 <= destination_row_integer < grid_size_integer and 0 <= destination_column_integer < len(current_room_grid_array_list[0])):
            print(f"[Validation Error] Destination ({destination_row_integer}, {destination_column_integer}) is outside grid boundaries.")
            return False

        if current_room_grid_array_list[destination_row_integer][destination_column_integer] != '':
            print(f"[Validation Error] Destination ({destination_row_integer}, {destination_column_integer}) is already occupied.")
            return False

        # 2. Player Presence / State Verification
        internal_player_id_string = str(room_metadata_dict.get('player_turn_map', {}).get(player_id, player_id))
        player_state_dictionary = room_story_state_dict.get('object_state', {}).get('player_character_state', {}).get(internal_player_id_string)

        if not player_state_dictionary:
            print(f"[Validation Error] Player {player_id} state data could not be found.")
            return False

        # 3. Branch A: Throwing from Inventory
        if throw_inventory_index is not None:
            player_inventory_list = player_state_dictionary.get('inventory', [])
            if not (0 <= throw_inventory_index < len(player_inventory_list)):
                print(f"[Validation Error] Player {player_id} has no item at inventory index {throw_inventory_index}.")
                return False
            print(f"[Validation Success] Player {player_id} is authorized to throw from inventory index {throw_inventory_index}.")
            return True

        # 4. Branch B: Throwing from Grid
        elif throw_from_coord is not None:
            target_row_integer, target_column_integer = throw_from_coord

            try:
                player_id_integer = int(internal_player_id_string)
            except ValueError:
                player_id_integer = internal_player_id_string

            player_position_tuple = find_object_position(current_room_grid_array_list, player_id_integer)
            if not player_position_tuple:
                print(f"[Validation Error] Player {player_id} is not present on the board to initiate a throw.")
                return False

            player_row_integer, player_column_integer = player_position_tuple

            # Validate Adjacency
            row_displacement_integer = abs(player_row_integer - target_row_integer)
            column_displacement_integer = abs(player_column_integer - target_column_integer)

            if row_displacement_integer > 1 or column_displacement_integer > 1 or (row_displacement_integer == 0 and column_displacement_integer == 0):
                print(f"[Validation Error] Target object at ({target_row_integer}, {target_column_integer}) is not adjacent to player.")
                return False

            if current_room_grid_array_list[target_row_integer][target_column_integer] == '':
                print(f"[Validation Error] The target square ({target_row_integer}, {target_column_integer}) is empty; nothing to throw.")
                return False

            print(f"[Validation Success] Player {player_id} is authorized to throw object from grid to ({destination_row_integer}, {destination_column_integer}).")
            return True

        else:
            print("[Validation Error] Must provide either 'throw_from_coord' or 'throw_inventory_index'.")
            return False

    except Exception as throw_validation_error:
        print(f"[Critical Error] An unexpected error occurred during throw validation: {throw_validation_error}")
        traceback.print_exc()
        return False

