def validate_neighbor_lookup(lookup_table):
    print("Starting validation of neighbor lookup table...")
    errors = []

    # 1. Basic structure checks
    def check_grid_coverage():
        # Verify all 64 positions (8x8) are present
        positions = set(lookup_table.keys())
        expected_positions = {(x,y) for x in range(8) for y in range(8)}
        missing = expected_positions - positions
        extra = positions - expected_positions

        if missing:
            errors.append(f"Missing positions: {missing}")
        if extra:
            errors.append(f"Unexpected positions: {extra}")

    # 2. Type validation
    def check_cell_types():
        type_counts = {
            'corner_top_left': 0,
            'corner_top_right': 0,
            'corner_bottom_left': 0,
            'corner_bottom_right': 0,
            'edge_top': 0,
            'edge_bottom': 0,
            'edge_left': 0,
            'edge_right': 0,
            'interior': 0
        }

        for pos, data in lookup_table.items():
            cell_type = data['type']
            if cell_type not in type_counts:
                errors.append(f"Invalid cell type '{cell_type}' at position {pos}")
            else:
                type_counts[cell_type] += 1

        # Verify counts
        expected_counts = {
            'corner_top_left': 1,
            'corner_top_right': 1,
            'corner_bottom_left': 1,
            'corner_bottom_right': 1,
            'edge_top': 6,
            'edge_bottom': 6,
            'edge_left': 6,
            'edge_right': 6,
            'interior': 36
        }

        for cell_type, count in type_counts.items():
            if count != expected_counts[cell_type]:
                errors.append(f"Wrong count for {cell_type}: got {count}, expected {expected_counts[cell_type]}")

    # 3. Neighbor count validation
    def check_neighbor_counts():
        for pos, data in lookup_table.items():
            neighbors = data['neighbors']
            expected_count = {
                'corner_top_left': 3,
                'corner_top_right': 3,
                'corner_bottom_left': 3,
                'corner_bottom_right': 3,
                'edge_top': 5,
                'edge_bottom': 5,
                'edge_left': 5,
                'edge_right': 5,
                'interior': 8
            }[data['type']]

            if len(neighbors) != expected_count:
                errors.append(f"Wrong neighbor count at {pos}: got {len(neighbors)}, expected {expected_count}")

    # 4. Neighbor validity check
    def check_neighbor_validity():
        for pos, data in lookup_table.items():
            for neighbor in data['neighbors']:
                # Check if neighbor coordinates are valid
                if not (0 <= neighbor[0] < 8 and 0 <= neighbor[1] < 8):
                    errors.append(f"Invalid neighbor coordinate {neighbor} for position {pos}")
                # Check if neighbor is adjacent
                x_diff = abs(pos[0] - neighbor[0])
                y_diff = abs(pos[1] - neighbor[1])
                if not (x_diff <= 1 and y_diff <= 1 and (x_diff != 0 or y_diff != 0)):
                    errors.append(f"Non-adjacent neighbor {neighbor} for position {pos}")

    # Run all checks
    check_grid_coverage()
    check_cell_types()
    check_neighbor_counts()
    check_neighbor_validity()

    # Report results
    if errors:
        print("[NO] Validation failed with following errors:")
        for error in errors:
            print(f"  - {error}")
    else:
        print("[OK] All validation checks passed!")

    return len(errors) == 0

import json

def inspect_game_state_schema(state_dict, array):
    """Inspects and prints the schema of the game state for alignment."""
    print("--- NPC State Schema Inspection ---")
    npc_state = state_dict.get('object_state', {}).get('npc_state', {})

    if not npc_state:
        print("Warning: 'npc_state' is empty or missing.")
    else:
        for npc_id, data in npc_state.items():
            print(f"NPC ID: {npc_id}")
            print(f"  Movement Keys: {list(data.get('movement', {}).keys())}")
            print(f"  Required Keys ('speed_1', 'current_direction'): ",
                  'speed_1' in data.get('movement', {}) and 'current_direction' in data.get('movement', {}))

    print("\n--- Room Array & Helper Compatibility ---")
    sample_id = next(iter(npc_state.keys())) if npc_state else None
    if sample_id:
        # Check if IDs in array are strings or ints
        found_type = None
        for row in array:
            for cell in row:
                if cell != '' and str(cell) == str(sample_id):
                    found_type = type(cell)
                    break
        print(f"ID type in room_array: {found_type}")
        print(f"ID type in npc_state keys: {type(sample_id)}")

