def calculate_cell_resonance_maps_reports(
    room_array: list,
    room_metadata_dict: dict
) -> tuple:
    """
    Outputs a resonance report, detailing the resonance effect on each object
    based on neighboring elemental objects.

    This function evaluates how neighboring cells affect the current cell's element,
    returning both an item-based dictionary and a map-based dictionary of the calculated resonance deltas.

    Args:
        room_array (list): A 2D list/array representing the spatial grid of the dungeon room.
        room_metadata_dict (dict): Dictionary containing room metadata, specifically
                                   the 'all_room_objects_data_dict' which maps integer IDs to elemental types.

    Returns:
        tuple: A tuple containing two dictionaries:
            - item_resonance_report_dictionary (dict): Maps object integer IDs to their calculated resonance delta (int).
            - map_resonance_report_dictionary (dict): Maps coordinate tuples (row_int, col_int) to their calculated resonance delta (int).
    """
    try:
        # Initialize the reporting dictionaries that will be returned
        item_resonance_report_dictionary = {}
        map_resonance_report_dictionary = {}

        # Determine the dimensions of the square dungeon room grid
        dungeon_room_grid_size_integer = len(room_array)

        # Define the strict rules for elemental interactions.
        # 'helps' means the target element gains +1 energy delta.
        # 'harms' means the target element loses -1 energy delta.
        elemental_interaction_rules_dictionary = {
            'water': {'helps': 'forest', 'harms': 'fire'},
            'forest': {'helps': 'fire', 'harms': 'void'},
            'fire': {'helps': 'void', 'harms': 'ice'},
            'void': {'helps': 'ice', 'harms': 'water'},
            'ice': {'helps': 'water', 'harms': 'forest'},
        }

        # Iterate through every single row in the dungeon room grid
        for current_row_index_integer in range(dungeon_room_grid_size_integer):

            # Iterate through every single column in the current row
            for current_column_index_integer in range(dungeon_room_grid_size_integer):

                # Retrieve the contents of the current cell
                current_cell_occupant_id = room_array[current_row_index_integer][current_column_index_integer]

                # Determine if the cell actually contains an object (represented by an integer ID)
                if isinstance(current_cell_occupant_id, int):

                    # Retrieve the elemental alignment of the object currently in this cell
                    current_occupant_element_string = room_metadata_dict['all_room_objects_data_dict'][current_cell_occupant_id].get('element')

                    # Formulate the coordinate tuple for lookup
                    current_cell_coordinate_tuple = (current_row_index_integer, current_column_index_integer)

                    # Retrieve the pre-calculated list of valid neighbor coordinates from the global lookup table
                    valid_neighbor_coordinates_list = NEIGHBOR_LOOKUP[current_cell_coordinate_tuple]['neighbors']

                    # Initialize the running total for resonance effects acting ON this cell
                    calculated_total_resonance_delta_integer = 0

                    # Iterate through each valid neighbor coordinate to calculate its effect on the current cell
                    for neighbor_coordinate_tuple in valid_neighbor_coordinates_list:

                        # Extract the specific row and column for the neighbor
                        neighbor_row_index_integer = neighbor_coordinate_tuple[0]
                        neighbor_column_index_integer = neighbor_coordinate_tuple[1]

                        # Retrieve the occupant ID of the neighbor cell
                        neighbor_occupant_id = room_array[neighbor_row_index_integer][neighbor_column_index_integer]

                        # Only process the neighbor if it contains an actual object (integer ID)
                        if isinstance(neighbor_occupant_id, int):

                            # Retrieve the elemental alignment of the neighbor object
                            neighbor_element_string = room_metadata_dict['all_room_objects_data_dict'][neighbor_occupant_id].get('element')

                            # Ensure both the current object and the neighbor object have valid elemental alignments
                            if current_occupant_element_string and neighbor_element_string:

                                # Rule Check 1: Does the NEIGHBOR's element HELP the CURRENT cell's element?
                                if current_occupant_element_string == elemental_interaction_rules_dictionary[neighbor_element_string]['helps']:
                                    calculated_total_resonance_delta_integer += 1

                                # Rule Check 2: Does the NEIGHBOR's element HARM the CURRENT cell's element?
                                elif current_occupant_element_string == elemental_interaction_rules_dictionary[neighbor_element_string]['harms']:
                                    calculated_total_resonance_delta_integer -= 1

                    # Record the final calculated resonance delta in both reporting dictionaries
                    map_resonance_report_dictionary[current_cell_coordinate_tuple] = calculated_total_resonance_delta_integer
                    item_resonance_report_dictionary[current_cell_occupant_id] = calculated_total_resonance_delta_integer

        # Successfully return both reports
        return item_resonance_report_dictionary, map_resonance_report_dictionary

    except KeyError as missing_dictionary_key_error:
        print(f"Critical Error in calculate_cell_resonance_maps_reports: A required dictionary key was missing: {missing_dictionary_key_error}")
        traceback.print_exc()
        return {}, {}
    except Exception as function_execution_error:
        print(f"Critical Error in calculate_cell_resonance_maps_reports: An unexpected failure occurred: {function_execution_error}")
        traceback.print_exc()
        return {}, {}

