def apply_resonance_energy_to_state(state_dict: dict, item_resonance_report: dict) -> dict:
    """
    Updates object energy levels based on resonance deltas, clamping values at a minimum of 0.

    Args:
        state_dict (dict): The master state dictionary.
        item_resonance_report (dict): Map of {object_id: change_in_energy_state_int}.

    Returns:
        dict: Updated state dictionary.
    """
    try:
        obj_state = state_dict.get('object_state', {})
        pc_state = obj_state.get('player_character_state', {})
        npc_state = obj_state.get('npc_state', {})
        treasure_state = obj_state.get('treasure_chest_state', {})

        for obj_id, change_in_energy_state in item_resonance_report.items():
            obj_id_str = str(obj_id)

            # Identify the target dictionary for the object ID
            target_entry = None
            if obj_id_str in pc_state:
                target_entry = pc_state[obj_id_str]
            elif obj_id_str in npc_state:
                target_entry = npc_state[obj_id_str]
            elif obj_id_str in treasure_state:
                target_entry = treasure_state[obj_id_str]

            if target_entry is not None:
                current_energy = target_entry.get('energy', 0)
                # Apply delta and clamp at 0
                new_energy = max(0, current_energy + change_in_energy_state)
                target_entry['energy'] = new_energy
                print(f"ID {obj_id_str}: Energy {current_energy} -> {new_energy} (Delta: {change_in_energy_state})")

        return state_dict
    except Exception as e:
        print(f"Error in resonance pipeline: {e}")
        traceback.print_exc()
        return state_dict

