def check_for_end_of_game(room_story_state_dict):
    """
    Evaluates the current state of the game to determine if the party has won, lost, or is still playing.

    Logic Flow:
    1. Executes modular checkers for monsters, treasure, and player positions.
    2. Returns 'solved puzzle' if all winning conditions are met.
    3. Evaluates if all active players (those who haven't exited) are absorbed or have 0 energy; if so, returns 'lost'.
    4. Defaults to 'still playing' if neither win nor loss conditions are finalized.

    Args:
        room_story_state_dict (dict): The master state dictionary containing object_state and room_array.

    Returns:
        str: One of 'solved puzzle', 'lost', or 'still playing'.
    """
    try:
        room_metadata_dict = room_story_state_dict.get('room_metadata_dict', {})

        # 1. Call modular checkers
        monsters_cleared = check_monsters_cleared(room_story_state_dict)
        treasure_collected = check_treasure_collected(room_story_state_dict)
        players_at_exit = check_players_at_exit(room_story_state_dict, room_metadata_dict)

        # 2. Check for 'solved puzzle' (Win condition)
        if monsters_cleared and treasure_collected and players_at_exit:
            return 'solved puzzle'

        # 3. Check for 'lost' (Loss condition)
        pc_state = room_story_state_dict.get('object_state', {}).get('player_character_state', {})
        active_players_with_energy = 0
        total_active_players = 0

        for pc_id, metadata in pc_state.items():
            if not metadata.get('exited_room', False):
                total_active_players += 1
                # A player is active if they have energy and are not absorbed
                if metadata.get('energy', 0) > 0 and not metadata.get('absorbed', False):
                    active_players_with_energy += 1

        # If there are active players but none of them are capable of moving (all absorbed or 0 energy), the game is lost
        if total_active_players > 0 and active_players_with_energy == 0:
            return 'lost'

        # 4. Default state
        return 'still playing'

    except Exception as e:
        print(f"Error in check_for_end_of_game: {e}")
        traceback.print_exc()
        return 'error'

