def get_row_and_column_offset_from_direction(direction):
    """
    Maps a cardinal direction string to its corresponding (row_offset, col_offset) tuple.

    The coordinate system assumes:
    - Row 0 is at the top of the grid.
    - Increasing row index moves 'south' (down).
    - Increasing column index moves 'east' (right).

    Args:
        direction (str): One of 'north', 'south', 'east', or 'west' (case-insensitive).

    Returns:
        tuple: A (delta_row, delta_col) tuple representing the movement offset.

    Raises:
        ValueError: If the provided direction is not one of the supported strings.
    """
    # Normalize input for robustness
    direction_clean = str(direction).strip().lower()

    # Mapping of directions to coordinate deltas
    offsets = {
        'north': (-1, 0),
        'south': (1, 0),
        'east': (0, 1),
        'west': (0, -1)
    }

    if direction_clean in offsets:
        return offsets[direction_clean]
    else:
        raise ValueError(f"Invalid direction '{direction}'. Supported directions are: {list(offsets.keys())}")

# Verification test
