print(f"Direction: {test_dir} -> Offset: {offset}")

def get_opposite_direction(direction):
    """
    Returns the literal opposite cardinal direction for a given input.

    Args:
        direction (str): One of 'north', 'south', 'east', or 'west'.

    Returns:
        str: The opposite direction string.

    Raises:
        ValueError: If the input direction is not recognized.
    """
    # Clean input: strip whitespace and convert to lowercase
    direction_clean = str(direction).strip().lower()

    # Mapping of opposites
    opposites = {
        'north': 'south',
        'south': 'north',
        'east': 'west',
        'west': 'east'
    }

    if direction_clean in opposites:
        return opposites[direction_clean]
    else:
        raise ValueError(f"Invalid direction '{direction}'. Supported directions are: {list(opposites.keys())}")

# Verification test
