def NPC_actions(state_dict: dict) -> dict:
    """
    Processes movement and actions for all NPCs (Non-Player Characters) based on their current state.

    This unified function iterates over all NPCs defined in the state dictionary.
    It skips any NPC that is marked as 'absorbed' or has an 'energy' level of 0 or less.
    For active NPCs, it calculates their intended next position based on their current
    direction and speed, and on settings for collision behevior.
    If the intended move is valid (within boundaries and the target
    cell is empty), the NPC moves. If the move is invalid (e.g., hitting a wall or another
    object), the NPC 'bounces' by changing its current direction using the
    `get_opposite_direction`, 'get_righthand_turn_direction' or
    'get_lefthand_turn_direction' helper functions.

    Args:
        state_dict (dict): The master state dictionary containing the 'room_array'
                           and the nested 'object_state' -> 'npc_state'.

    Returns:
        dict: The updated state dictionary reflecting the new positions and directions of the NPCs.
    """
    try:
        print("\n--- Executing unified NPC_actions ---")
        # 1. Retrieve the current room array and NPC state dictionary safely
        current_room_array = state_dict.get('room_array', [])
        if not current_room_array:
            print("[Warning] 'room_array' not found or empty in state_dict.")
            return state_dict

        npc_state_dictionary = state_dict.get('object_state', {}).get('npc_state', {})
        if not npc_state_dictionary:
            print("[Info] No NPCs found in state_dict. Skipping NPC actions.")
            return state_dict

        # 2. Process each NPC
        for npc_id_string, npc_metadata in npc_state_dictionary.items():
            try:
                # Convert ID to integer as it is stored in the room_array
                npc_id_integer = int(npc_id_string)
            except ValueError:
                print(f"[Error] NPC ID '{npc_id_string}' is not a valid integer. Skipping.")
                continue

            # Skip NPCs that are dead (energy <= 0) or absorbed
            npc_energy = npc_metadata.get('energy', 0)
            is_absorbed = npc_metadata.get('absorbed', False)
            if npc_energy <= 0 or is_absorbed:
                # print(f"[Skip] NPC {npc_id_string} skipped (Energy: {npc_energy}, Absorbed: {is_absorbed})")
                continue

            # Find the NPC's current position in the array
            current_position_tuple = find_object_position(current_room_array, npc_id_integer)
            if not current_position_tuple:
                print(f"[Warning] NPC {npc_id_integer} not found in room_array despite being active.")
                continue

            current_row_index, current_column_index = current_position_tuple

            # Retrieve movement parameters
            movement_configuration = npc_metadata.get('movement', {})
            current_direction_string = movement_configuration.get('current_direction', 'east')
            npc_speed_integer = movement_configuration.get('speed_1', 1)

            # 3. Calculate target position
            try:
                delta_row, delta_column = get_row_and_column_offset_from_direction(current_direction_string)
            except ValueError as direction_error:
                print(f"[Error] Invalid direction for NPC {npc_id_string}: {direction_error}")
                continue

            target_row_index = current_row_index + (delta_row * npc_speed_integer)
            target_column_index = current_column_index + (delta_column * npc_speed_integer)

            # 4. Validate the intended move
            grid_size = len(current_room_array)
            is_within_boundaries_boolean = (
                0 <= target_row_index < grid_size and
                0 <= target_column_index < len(current_room_array[0])
            )

            is_target_cell_empty_boolean = False
            if is_within_boundaries_boolean:
                is_target_cell_empty_boolean = (current_room_array[target_row_index][target_column_index] == '')

            # 5. Execute move or handle collision (bounce)
            if is_within_boundaries_boolean and is_target_cell_empty_boolean:
                # Move the NPC
                current_room_array[current_row_index][current_column_index] = ''
                current_room_array[target_row_index][target_column_index] = npc_id_integer
                # print(f"[Move] NPC {npc_id_integer} moved {current_direction_string} to ({target_row_index}, {target_column_index}).")
            else:
                """
                room_story_state_dict['object_state']['npc_state'][object_id_string] = {
                ...
                    'movement': {
                        'speed_1': 1,
                        'current_direction': e.g. 'east'
                        'colision_behavior': e.g. opposite, left, right
                    }
                """
                if state_dict['object_state']['npc_state'][npc_id_string]['movement']['colision_behavior'] == 'opposite':
                    # Collision detected: bounce back
                    new_direction_string = get_opposite_direction(current_direction_string)

                elif state_dict['object_state']['npc_state'][npc_id_string]['movement']['colision_behavior'] == 'left':
                    # Collision detected: bounce back
                    new_direction_string = get_lefthand_turn_direction(current_direction_string)

                elif state_dict['object_state']['npc_state'][npc_id_string]['movement']['colision_behavior'] == 'right':
                    # Collision detected: bounce back
                    new_direction_string = get_righthand_turn_direction(current_direction_string)

                else:
                    raise ValueError(f"Invalid collision behavior '{state_dict['object_state']['npc_state'][npc_id_string]['movement']['colision_behavior']}' for NPC {npc_id_string}.")

                state_dict['object_state']['npc_state'][npc_id_string]['movement']['current_direction'] = new_direction_string
                # print(f"[Collision] NPC {npc_id_integer} blocked moving {current_direction_string}. Bounced to {new_direction_string}.")

        # 6. Save updated array back to state
        state_dict['room_array'] = current_room_array
        return state_dict

    except Exception as execution_error:
        print(f"[Critical Error] Unexpected failure in unified NPC_actions: {execution_error}")
        traceback.print_exc()
        return state_dict

print("Unified NPC_actions function defined successfully.")

import copy

def test_unified_npc_actions():
    """
    A comprehensive test suite for the unified NPC_actions function.
    """
    print("\n--- Starting Tests for Unified NPC_actions ---")

    # Setup a baseline test state
    base_state = {
        'room_array': [['' for _ in range(8)] for _ in range(8)],
        'object_state': {
            'npc_state': {
                '1': { # Normal movement (East)
                    'energy': 1,
                    'absorbed': False,
                    'movement': {'speed_1': 1, 'current_direction': 'east',
                                 'colision_behavior': 'opposite',}
                },
                '2': { # Collision / Bounce at boundary (West)
                    'energy': 1,
                    'absorbed': False,
                    'movement': {'speed_1': 1, 'current_direction': 'west',
                                 'colision_behavior': 'opposite',}
                },
                '3': { # Ignored: Zero energy
                    'energy': 0,
                    'absorbed': False,
                    'movement': {'speed_1': 1, 'current_direction': 'south',
                                 'colision_behavior': 'opposite',}
                },
                '4': { # Ignored: Absorbed
                    'energy': 1,
                    'absorbed': True,
                    'movement': {'speed_1': 1, 'current_direction': 'north',
                                 'colision_behavior': 'opposite',}
                }
            }
        }
    }

    # Place NPCs on the board
    base_state['room_array'][4][4] = 1 # Middle of the board, going east. Should end up at (4, 5)
    base_state['room_array'][2][0] = 2 # Left edge, going west. Should bounce and face east.
    base_state['room_array'][6][6] = 3 # Zero energy, going south. Should remain at (6, 6)
    base_state['room_array'][1][1] = 4 # Absorbed, going north. Should remain at (1, 1)

    # Run the function
    updated_state = NPC_actions(copy.deepcopy(base_state))
    updated_array = updated_state['room_array']
    updated_npc_state = updated_state['object_state']['npc_state']

    # Assertions

    # 1. Normal Movement
    assert updated_array[4][5] == 1, "Failed normal movement test. NPC 1 did not move east."
    assert updated_array[4][4] == '', "Failed normal movement test. NPC 1's old position is not empty."
