    # 2. Boundary Collision (Bouncing)
    assert updated_array[2][0] == 2, "Failed bounce test. NPC 2 moved out of bounds."
    assert updated_npc_state['2']['movement']['current_direction'] == 'east', "Failed bounce test. NPC 2 did not change direction."
    print("[OK] Boundary collision (bounce) verified.")

    # 3. Ignored: Zero Energy
    assert updated_array[6][6] == 3, "Failed zero energy test. NPC 3 moved unexpectedly."
    assert updated_npc_state['3']['movement']['current_direction'] == 'south', "Failed zero energy test. NPC 3 changed direction unexpectedly."
    print("[OK] Ignored zero-energy NPC verified.")

    # 4. Ignored: Absorbed
    assert updated_array[1][1] == 4, "Failed absorbed test. NPC 4 moved unexpectedly."
    assert updated_npc_state['4']['movement']['current_direction'] == 'north', "Failed absorbed test. NPC 4 changed direction unexpectedly."
    print("[OK] Ignored absorbed NPC verified.")

    print("\n--- All tests passed successfully! ---")

