"""## Main Wrapper Functions"""

def execute_throw_action(
    one_player_only_round_action_datadict: dict,
    room_story_state_dict: dict
) -> bool:
    """
    Executes a 'throw' action where a player relocates an object to a new coordinate.

    This function handles the physical state mutations required to move an object
    from either the player's immediate physical adjacency (the grid) or from the
    player's personal inventory, placing it onto the target grid destination.

    Validation is assumed to have already occurred prior to execution.

    Args:
        one_player_only_round_action_datadict (dict): A dictionary containing the
            player's action details. Expected keys: 'player_id', 'throw_to_coord',
            and EITHER 'throw_from_coord' OR 'throw_inventory_index'.
        room_story_state_dict (dict): The master game state containing grid,
            entity metadata, and inventory lists.

    Returns:
        bool: True if the throw was successfully executed and state updated;
              False if execution failed or inputs were structurally invalid.
    """
    try:
        # 1. Extract core references from the master state dictionary
        room_array_list = room_story_state_dict.get('room_array', [])
        player_character_states_dictionary = room_story_state_dict.get('object_state', {}).get('player_character_state', {})
        room_metadata_dictionary = room_story_state_dict.get('room_metadata_dict', {})

        # 2. Extract action details
        throwing_player_id_string = one_player_only_round_action_datadict.get('player_id')
        target_object_coordinates_list = one_player_only_round_action_datadict.get('throw_from_coord')
        destination_coordinates_list = one_player_only_round_action_datadict.get('throw_to_coord')
        throw_inventory_index_integer = one_player_only_round_action_datadict.get('throw_inventory_index')

        # 3. Resolve internal player ID and fetch data
        internal_player_character_id_string = str(room_metadata_dictionary.get('player_turn_map', {}).get(throwing_player_id_string, throwing_player_id_string))
        player_data_dictionary = player_character_states_dictionary.get(internal_player_character_id_string)

        # 4. Final safety checks
        if not player_data_dictionary or player_data_dictionary.get('energy', 0) < 1:
            print(f"[Execution Error] Player {throwing_player_id_string} lacks energy or state data.")
            return False

        if not destination_coordinates_list:
            print(f"[Execution Error] Missing throw destination for player {throwing_player_id_string}.")
            return False

        destination_row_integer, destination_column_integer = destination_coordinates_list
        object_to_place_id_any = None

        # 5. Branch A: Execute throw from Inventory
        if throw_inventory_index_integer is not None:
            try:
                # Safely pop the item from the player's inventory list
                object_to_place_id_any = player_data_dictionary['inventory'].pop(throw_inventory_index_integer)
                print(f"[Action Executed] Player {throwing_player_id_string} threw item '{object_to_place_id_any}' from inventory index {throw_inventory_index_integer}.")
            except IndexError as inventory_index_error:
                print(f"[Execution Error] Invalid inventory index {throw_inventory_index_integer} for player {throwing_player_id_string}: {inventory_index_error}")
                return False

        # 6. Branch B: Execute throw from Grid
        elif target_object_coordinates_list is not None:
            origin_row_integer, origin_column_integer = target_object_coordinates_list
            object_to_place_id_any = str(room_array_list[origin_row_integer][origin_column_integer])

            # Vacate the origin cell
            room_array_list[origin_row_integer][origin_column_integer] = ''
            print(f"[Action Executed] Player {throwing_player_id_string} threw item '{object_to_place_id_any}' from grid location {target_object_coordinates_list}.")

        else:
            print(f"[Execution Error] Player {throwing_player_id_string} provided neither a grid origin nor an inventory index.")
            return False

        # 7. Normalize object ID type (prefer integer for consistency)
        try:
            object_to_place_id_integer = int(object_to_place_id_any)
        except ValueError:
            object_to_place_id_integer = object_to_place_id_any

        # 8. Place the object onto the target destination
        room_array_list[destination_row_integer][destination_column_integer] = object_to_place_id_integer

        # 9. Un-absorb the object if it was an entity, so it isn't immediately removed by cleanup
        object_to_place_id_str = str(object_to_place_id_integer)
        for category in ['player_character_state', 'npc_state', 'treasure_chest_state']:
            category_state = room_story_state_dict.get('object_state', {}).get(category, {})
            if object_to_place_id_str in category_state:
                category_state[object_to_place_id_str]['absorbed'] = False
                break

        # 10. Deduct the action's energy cost
        player_data_dictionary['energy'] -= 1
        return True

    except Exception as throw_execution_failure:
        print(f"[Critical Error] execute_throw_action failed unexpectedly: {throw_execution_failure}")
        traceback.print_exc()
        return False


