def run_integrated_game_simulation(
    solution_action_dict_list: list,
    master_room_story_state_dictionary: dict,
) -> tuple:
    """
    The fully integrated game loop. Replaces earlier processing loops for specific tests.
    This loop actively calls resonance updates and handles NPC movements, utilizing
    the new unified one_player_action_data_dict.

    Args:
        solution_action_dict_list (list): The list of planned action dicts.
        master_room_story_state_dictionary (dict): The integrated state dictionary.

    Returns:
        tuple: (game_end_status_string, game_timeline_dictionary, standard_error_string)
    """
    try:
        print("\n=== Starting Integrated Game Simulation ===")
        game_end_status_string = 'still playing'
        standard_error_string = None
        game_timeline_dictionary = {}

        # Ensure we are working with an isolated copy of the state
        current_state_dictionary = copy.deepcopy(master_room_story_state_dictionary)
        room_metadata_dict = current_state_dictionary.get('room_metadata_dict', {})

        # Bundle the flat list of actions into chunks of 5 per round
        bundle_status_string, bundled_move_list = make_round_set_bundles(solution_action_dict_list)
        if bundle_status_string == "error":
            return "error", {}, bundled_move_list

        # Iterate through Rounds
        for round_index_integer, round_bundle_list in enumerate(bundled_move_list):
            print(f"\n--- Beginning Round {round_index_integer + 1} ---")

            for round_section_item in round_bundle_list:
                # NPC Actions Phase
                if round_section_item in ["NPC actions", "NPC moves"]:
                    print("[Action] Executing NPC behaviors...")
                    current_state_dictionary = NPC_actions(current_state_dictionary)

                # Player Actions Phase
                elif isinstance(round_section_item, list):
                    print("[Action] Executing Player moves...")
                    current_state_dictionary = update_dungeon_room_array_one_round(
                        this_round_player_actions_list=round_section_item,
                        room_story_state_dict=current_state_dictionary,
                        starting_move_index_from_0_integer=round_index_integer * 5
                    )

                # Resonance Effect Phase
                elif round_section_item == "resonance_effect":
                    print("[Action] Applying global resonance effects...")
                    item_resonance_report, map_resonance_report = calculate_cell_resonance_maps_reports(
                        current_state_dictionary['room_array'], room_metadata_dict
                    )
                    current_state_dictionary = apply_resonance_energy_to_state(
                        current_state_dictionary, item_resonance_report
                    )

                # Game End Checking Phase
                elif round_section_item in ["check_end_of_game", "check for end"]:
                    print("[Action] Checking game end conditions...")
                    game_end_status_string = check_for_end_of_game(
                        current_state_dictionary
                    )
                    print(f"[Status] Current game status: {game_end_status_string}")

            # Execute end-of-round absorption
            print("Processing Elemental Absorption...")
            current_state_dictionary = process_elemental_absorption(current_state_dictionary)

            # Clean up zero-energy entities that have been absorbed
            print("Cleaning up absorbed (zero-energy) entities...")
            current_state_dictionary = cleanup_absorbed_entities(current_state_dictionary)

            # Snapshot the state for this round
            game_timeline_dictionary[round_index_integer] = copy.deepcopy(current_state_dictionary)

            # Halt simulation if game concluded
            if game_end_status_string in ['solved puzzle', 'lost']:
                print(f"\n=== Simulation Terminated: {game_end_status_string.upper()} ===")
                break

        return game_end_status_string, game_timeline_dictionary, standard_error_string

    except Exception as simulation_error:
        print(f"[Critical Error] Simulation failed: {simulation_error}")
        traceback.print_exc()
        return "error", {}, str(simulation_error)



"""## Design: Elemental Absorption Logic (`process_elemental_absorption`)

### 1. The Problem with the Old Logic
The previous cleanup logic incorrectly treated zero-energy as an immediate removal condition (absorption/elimination). In the new "Soft Exhaustion" model, characters simply become `exhausted` when they reach 0 energy, remaining on the grid to allow strategic interactions.

### 2. Core Mechanism
The new `process_elemental_absorption` function will handle the actual absorption of exhausted entities. It iterates over all entities in the `object_state` dictionary.

### 3. Finding Exhausted Entities
For each active, unabsorbed entity that is `exhausted` (energy == 0), the function will locate its coordinates on the `room_array` using the `find_object_position` helper.

### 4. Identifying Neighbors
Using the `NEIGHBOR_LOOKUP` table, the function will retrieve all valid 8-neighbor cells surrounding the exhausted entity.

### 5. Checking for Absorbers
The function will examine each valid neighbor cell to see if it contains an active entity (energy > 0 and not absorbed).

### 6. Elemental Interaction Check
For each adjacent active entity, it will check the elemental interaction rule. An absorption can only occur if the exhausted entity's element **helps** the adjacent active entity's element based on the `element_interactions` dictionary:
*   `water` helps `forest`
*   `forest` helps `fire`
*   `fire` helps `void`
*   `void` helps `ice`
*   `ice` helps `water`

### 7. Executing the Absorption Action
If a valid absorber is found:
*   The exhausted entity's integer ID string is appended to the absorber's `inventory` list.
*   The exhausted entity's `absorbed` flag is set to `True`.
*   The exhausted entity's integer ID is removed from the `room_array` (replaced with `''`).

### 8. Tie-Breaking Rule
If multiple valid absorbers exist in the neighboring cells, the function will simply use the **first valid absorber found** during the neighbor iteration process as the designated absorber.

### Refinement: Exhaustion vs. Absorption

To ensure the puzzle remains a 'Social Story' and not a 'Pointless Exercise' in immediate failure, we define what happens at zero energy.

**Proposed STEM Logic:**
1. **Zero Energy** = *Exhaustion*. The character remains on the grid but cannot perform actions until energy > 0.
2. **Exactly 1 other Negative Resonance + Zero Energy** = *Absorption*. Only then is the character removed.

Below is the experimental code to override the strict removal policy.
"""

def cleanup_absorbed_entities(state_dict: dict) -> dict:
    """
    NEW RULE: Soft Exhaustion.

    Players and objects that reach 0 energy are marked as 'exhausted'.
    They are NOT removed from the board automatically. This allows teammates
    to rescue exhausted players by moving nearby to provide positive resonance.

    Entities are only removed if their 'absorbed' flag is explicitly set to True
    (e.g., by a specific game action, not just by running out of energy).
    """
    try:
        print("\n--- Executing soft_cleanup_entities (Exhaustion Mode) ---")
        room_array = state_dict.get('room_array', [])
        object_state = state_dict.get('object_state', {})

        categories = ['player_character_state', 'npc_state', 'treasure_chest_state']

        for category in categories:
            category_state = object_state.get(category, {})
            for entity_id_str, metadata in category_state.items():
                current_energy = metadata.get('energy', 1)

                # If energy is 0, they stay on board but are Exhausted
                if current_energy == 0 and not metadata.get('absorbed', False):
                    metadata['status'] = 'exhausted'
                    # print(f"[Info] Entity {entity_id_str} is exhausted but remains on board.")
                elif current_energy > 0:
                    metadata['status'] = 'active'

                # Only remove from the board if explicitly marked as absorbed
                # (e.g. by a future 'absorb' action, not just by passive energy drain)
                if metadata.get('absorbed', False):
                    print(f"[Action] Entity {entity_id_str} was absorbed. Removing from board.")

                    try:
                        entity_id_int = int(entity_id_str)
                    except ValueError:
                        entity_id_int = entity_id_str

                    pos = find_object_position(room_array, entity_id_int)
                    if pos:
                        r, c = pos
                        room_array[r][c] = ''

        state_dict['room_array'] = room_array
        return state_dict

    except Exception as e:
        print(f"Error in experimental cleanup: {e}")
        traceback.print_exc()
        return state_dict

print("Soft cleanup logic defined for testing.")

def process_elemental_absorption(
    state_dict: dict
) -> dict:
    """
    Processes elemental absorption for exhausted entities (energy == 0).

    An exhausted entity can be absorbed by an adjacent active entity (energy > 0)
    if the exhausted entity's element 'helps' the active entity's element.
    Absorption ONLY occurs if there is EXACTLY ONE valid adjacent absorber.

    When absorbed, any items in the exhausted entity's inventory are flattened
    into the absorber's inventory.

    Args:
        state_dict (dict): The master state dictionary.

    Returns:
        dict: The updated state dictionary.
    """
    try:
        print("\n--- Executing process_elemental_absorption (Updated Tie-breaking & Flattening) ---")
        room_array = state_dict.get('room_array', [])
        object_state = state_dict.get('object_state', {})

        element_interactions = {
            'water': {'helps': 'forest', 'harms': 'fire'},
            'forest': {'helps': 'fire', 'harms': 'void'},
            'fire': {'helps': 'void', 'harms': 'ice'},
            'void': {'helps': 'ice', 'harms': 'water'},
            'ice': {'helps': 'water', 'harms': 'forest'},
        }

        categories = ['player_character_state', 'npc_state', 'treasure_chest_state']

        # Iterate through all entities to find exhausted ones
        for category in categories:
            category_state = object_state.get(category, {})
            for entity_id_str, metadata in category_state.items():
                if metadata.get('energy', 1) == 0 and not metadata.get('absorbed', False):
                    exhausted_element = metadata.get('element')

                    try:
                        entity_id_int = int(entity_id_str)
                    except ValueError:
                        entity_id_int = entity_id_str

                    pos = find_object_position(room_array, entity_id_int)
                    if pos:
                        row, col = pos
                        valid_neighbors = NEIGHBOR_LOOKUP[(row, col)]['neighbors']

                        potential_absorbers = []

                        # Check all neighbors for potential absorbers
                        for n_pos in valid_neighbors:
                            neighbor_id = room_array[n_pos[0]][n_pos[1]]
                            if isinstance(neighbor_id, int):
                                # Find neighbor metadata to check if active
                                neighbor_meta = None
                                neighbor_cat = None
                                neighbor_id_str = str(neighbor_id)

                                for cat in categories:
                                    if neighbor_id_str in object_state.get(cat, {}):
                                        neighbor_meta = object_state[cat][neighbor_id_str]
                                        neighbor_cat = cat
                                        break

                                if neighbor_meta and neighbor_meta.get('energy', 0) > 0 and not neighbor_meta.get('absorbed', False):
                                    neighbor_element = neighbor_meta.get('element')

                                    # Check absorption rule: exhausted helps neighbor
                                    if exhausted_element and neighbor_element:
                                        if element_interactions.get(exhausted_element, {}).get('helps') == neighbor_element:
                                            potential_absorbers.append((neighbor_id_str, neighbor_element, neighbor_meta))

                        # Apply absorption ONLY if there is exactly one valid absorber
                        if len(potential_absorbers) == 1:
                            absorber_id_str, absorber_element, absorber_meta = potential_absorbers[0]
                            print(f"[Absorption] {entity_id_str} ({exhausted_element}) absorbed by {absorber_id_str} ({absorber_element}).")

                            metadata['absorbed'] = True
                            room_array[row][col] = ''

                            inventory = absorber_meta.get('inventory', [])

                            # Add the entity itself
                            inventory.append(entity_id_str)

                            # FLATTEN: Take anything the absorbed entity was holding and extend it
                            absorbed_inventory = metadata.get('inventory', [])
                            if absorbed_inventory:
                                print(f"[Absorption] Flattening inventory: adding {absorbed_inventory} to absorber.")
                                inventory.extend(absorbed_inventory)
                                # Clear it from the original entity to be safe
                                metadata['inventory'] = []

                            absorber_meta['inventory'] = inventory
                        elif len(potential_absorbers) > 1:
                            print(f"[Absorption Tie] {entity_id_str} ({exhausted_element}) has {len(potential_absorbers)} potential absorbers. No absorption occurs.")

        state_dict['room_array'] = room_array
        return state_dict

    except Exception as e:
        print(f"[Critical Error] Failure in process_elemental_absorption: {e}")
        traceback.print_exc()
        return state_dict


def test_process_elemental_absorption_flattening():
    """
    Tests the flattening of an inventory during an absorption event.
    """
    print("\n--- Testing Elemental Absorption Flattening ---")
    try:
        mock_grid = [['' for _ in range(8)] for _ in range(8)]
        mock_grid[0][0] = 1 # Exhausted entity (Water)
        mock_grid[0][1] = 2 # Absorber entity (Forest)

        state = {
            'room_array': mock_grid,
            'object_state': {
                'player_character_state': {
                    '1': {'energy': 0, 'element': 'water', 'absorbed': False, 'inventory': ['treasure_1', 'magic_bean']},
                    '2': {'energy': 1, 'element': 'forest', 'absorbed': False, 'inventory': ['starting_item']}
                }
            }
        }

        updated_state = process_elemental_absorption(state)

        p2_inventory = updated_state['object_state']['player_character_state']['2']['inventory']
        p1_inventory = updated_state['object_state']['player_character_state']['1']['inventory']

        assert '1' in p2_inventory, "Entity 1 was not added to inventory."
        assert 'treasure_1' in p2_inventory, "treasure_1 was not flattened into absorber's inventory."
        assert 'magic_bean' in p2_inventory, "magic_bean was not flattened into absorber's inventory."
        assert len(p1_inventory) == 0, "Absorbed entity's inventory was not cleared."
        assert updated_state['object_state']['player_character_state']['1']['absorbed'] is True, "Entity 1 not marked absorbed."

        print("[SUCCESS] Inventory flattening verified during absorption.")
    except Exception as e:
        print(f"[FAILURE] Test crashed: {e}")
        traceback.print_exc()

test_process_elemental_absorption_flattening()

"""## Summary of Absorption Mechanics

### Tie-Breaking Rule Modification
* **New Rule:** An exhausted entity (0 energy) is **only** absorbed if there is **exactly one** valid adjacent absorber.
* If multiple adjacent entities are eligible to absorb the exhausted entity (a tie), **no absorption occurs**. The exhausted entity remains on the board.
* This prevents arbitrary tie-breaking and forces players to be precise with their positioning for rescues or absorptions.

"""

def test_process_elemental_absorption():
    """
    Tests the process_elemental_absorption function for various scenarios including successful,
    failed, and multi-absorber tie-breaking logic.
    """
    try:
        print("\n--- Testing Elemental Absorption Mechanics ---")

        # Scenario 1: Successful Absorption (Exhausted Water helps Active Forest)
        print("\n[Test 1] Successful Absorption")
        grid1 = [['' for _ in range(8)] for _ in range(8)]
        grid1[0][0] = 1 # Exhausted Water
        grid1[0][1] = 2 # Active Forest

        state1 = {
            'room_array': grid1,
            'object_state': {
                'player_character_state': {
                    '1': {'energy': 0, 'element': 'water', 'absorbed': False, 'status': 'exhausted'},
                    '2': {'energy': 1, 'element': 'forest', 'absorbed': False, 'inventory': [], 'status': 'active'}
                }
            }
        }

        updated_state1 = process_elemental_absorption(copy.deepcopy(state1))

        assert updated_state1['object_state']['player_character_state']['1']['absorbed'] == True, "Entity 1 should be absorbed"
        assert updated_state1['room_array'][0][0] == '', "Entity 1 should be removed from board"
        assert '1' in updated_state1['object_state']['player_character_state']['2']['inventory'], "Entity 1 should be in Entity 2's inventory"
        print("[OK] Successful Absorption verified.")

        # Scenario 2: Failed Absorption (Exhausted Water harms Active Fire)
        print("\n[Test 2] Failed Absorption (Harms)")
        grid2 = [['' for _ in range(8)] for _ in range(8)]
        grid2[0][0] = 1 # Exhausted Water
        grid2[0][1] = 3 # Active Fire

        state2 = {
            'room_array': grid2,
            'object_state': {
                'player_character_state': {
                    '1': {'energy': 0, 'element': 'water', 'absorbed': False, 'status': 'exhausted'},
                    '3': {'energy': 1, 'element': 'fire', 'absorbed': False, 'inventory': [], 'status': 'active'}
                }
            }
        }

        updated_state2 = process_elemental_absorption(copy.deepcopy(state2))

        assert updated_state2['object_state']['player_character_state']['1']['absorbed'] == False, "Entity 1 should NOT be absorbed"
        assert updated_state2['room_array'][0][0] == 1, "Entity 1 should remain on board"
        assert len(updated_state2['object_state']['player_character_state']['3']['inventory']) == 0, "Inventory should be empty"
        print("[OK] Failed Absorption verified.")

        # Scenario 3: Multiple Potential Absorbers (Tie-breaking)
        print("\n[Test 3] Multiple Potential Absorbers (No Absorption)")
        grid3 = [['' for _ in range(8)] for _ in range(8)]
        grid3[1][1] = 1 # Exhausted Water
        grid3[0][1] = 2 # Active Forest A
        grid3[1][0] = 4 # Active Forest B

        state3 = {
            'room_array': grid3,
            'object_state': {
                'player_character_state': {
                    '1': {'energy': 0, 'element': 'water', 'absorbed': False, 'status': 'exhausted'},
                    '2': {'energy': 1, 'element': 'forest', 'absorbed': False, 'inventory': [], 'status': 'active'},
                    '4': {'energy': 1, 'element': 'forest', 'absorbed': False, 'inventory': [], 'status': 'active'}
                }
            }
        }

        updated_state3 = process_elemental_absorption(copy.deepcopy(state3))

        # New rule: No absorption should occur in case of a tie
        assert updated_state3['object_state']['player_character_state']['1']['absorbed'] == False, "Entity 1 should NOT be absorbed"
        assert updated_state3['room_array'][1][1] == 1, "Entity 1 should remain on board"

        inv2 = updated_state3['object_state']['player_character_state']['2']['inventory']
        inv4 = updated_state3['object_state']['player_character_state']['4']['inventory']

        assert len(inv2) == 0 and len(inv4) == 0, "No entity should absorb the exhausted entity"
        print("[OK] Multiple Absorbers tie-breaking verified (No Absorption).")

        print("\n--- All Elemental Absorption Tests Passed ---")

    except AssertionError as ae:
        print(f"[Assertion Error] Test Failed: {ae}")
        traceback.print_exc()
    except Exception as e:
        print(f"[Critical Error] Test Failed: {e}")
        traceback.print_exc()

# Execute tests
test_process_elemental_absorption()

