"""## Game Iteration Code:"""

def process_whole_room_game_all_rounds(
        solution_action_dict_list: list,
        room_story_state_dict: dict,
        max_rounds: int = 100
) -> tuple:
    """
    'round's and 'turn's
    resonance

    solution sets

    game-end conditions

    This function coordinates the sequential execution of a full game simulation,
    processing bundles of rounds that contain NPC actions, player actions, resonance effects,
    and game-end condition checks.
    Now includes a maximum round limit to enforce a 'lost' condition if exceeded.

    This revised version consumes a single unified list of action dictionaries
    (solution_action_dict_list) in place of the previous parallel list + metadata-dict
    design. Each action dict carries both the move information and the actor/action-type
    metadata that used to live in solution_meta_data_dic.

    Args:
        solution_action_dict_list (list): A chronologically ordered list of unified
            action dictionaries representing the players' proposed solution. Each dict
            contains both the move tuple data and the metadata describing the intended
            actor and action type (replacing the former parallel
            solution_move_tuple_list / solution_meta_data_dic pair).
        room_story_state_dict (dict): The master state dictionary holding all entity
            energies, inventories, statuses, and the room array itself. Also contains
            the embedded 'room_metadata_dict' (immutable metadata detailing door
            locations, element mappings, and persistent ID associations) and the
            'room_array' (a 2D grid, e.g. 8x8, representing the spatial grid of the room).
        max_rounds (int, optional): The absolute upper limit of rounds the simulation will
            execute before forcing a 'lost' condition to prevent infinite loops. Defaults to 100.

    Returns:
        tuple: A 4-element tuple containing:
            - game_end_status (str): The final outcome ('solved puzzle', 'lost', or 'error').
            - game_timeline_history_dictionary (dict): A round-by-round deep copy history of the state.
            - object state (e.g. player stuff) (dict): room_story_state_dict['object_state']
              at end of simulation.
            - std_error (str or None): String describing the error if a failure occurred, else None.

    Notes on changes from the previous version:
        1. SIGNATURE: consolidated solution_move_tuple_list + solution_meta_data_dic into
           a single solution_action_dict_list of unified action dicts.
        2. BUNDLING: make_round_set_bundles is called on solution_action_dict_list and
           we iterate over the resulting bundled_rounds_list.
        3. PLAYER MOVES: update_dungeon_room_array_one_round now receives the action dict
           list directly (no separate meta_data_dic argument).
        4. END-OF-ROUND PHASES: process_elemental_absorption and cleanup_absorbed_entities
           are strictly invoked at the end of each round, before archiving the timeline.
    """
    try:

        # Pull embedded room metadata and room array from the master state dict.
        room_array = room_story_state_dict['room_array']
        room_metadata_dict = room_story_state_dict['room_metadata_dict']

        # preset reset
        # Default to 'still playing' so the round-end evaluator has a valid baseline.
        game_end_status = 'still playing'

        print(f"\nStarting process_whole_room_game_all_rounds() with a maximum of {max_rounds} rounds.")

        # No error captured initially.
        std_error = None

        # preset / reset
        # end_or_fail is the per-iteration halt flag; set True when the game concludes.
        end_or_fail = False

        print("Initial room_array state:")
        for row in room_array:
            print(row)

        ################################################
        # 1. Bundle and preprocess the player action list
        ################################################
        """
        Convert the flat list of unified action dicts into a structured list of
        round-bundles. Each bundle contains the ordered sequence of per-round
        phases (NPC actions, player moves list, resonance_effect, check_end_of_game).
        """
        status_string, bundled_rounds_list = make_round_set_bundles(solution_action_dict_list)

        ############################################
        # 2. prescreen player move-order for errors
        ############################################
        # If bundling reported an error, bundled_rounds_list contains the error message.
        if status_string == "error":
            error_message = bundled_rounds_list
            print(f"Move order prescreening failed with error: {error_message}")
            # return: solution failed (Pass-fail = False), empty timeline, no object state, error message
            return False, {}, None, error_message

        #####################
        # Make Game Timeline
        #####################
        # Round-indexed archive of deep-copied state snapshots.
        game_timeline_history_dictionary = {}

        ####################################################
        # 3. Iterate through each round of individual-turns
        ####################################################
        """
        In the bundled list of lists,
        each macro-list is a bundle of one round
        of move/turn/actions, etc.

        Note: type of whisp determines the move-heuristic
        """
        for this_round_index_from_zero, this_round_bundle in enumerate(bundled_rounds_list):
            current_round_number = this_round_index_from_zero + 1
            print(f"\n--- Round {current_round_number} ---")

            # Walk each phase section within this round's bundle.
            for this_index, this_round_section_identifier in enumerate(this_round_bundle):

                # print(f"this_round_section -> {this_round_section_identifier}")

                # --- Phase: NPC actions ---
                if this_round_section_identifier in ["NPC actions", "NPC moves"]:
                    """
                    whisps heuristic moves
                    """
                    print("Executing NPC actions phase...")
                    try:
                        # Invoke the integrated NPC_actions function to mutate state.
                        room_story_state_dict = NPC_actions(room_story_state_dict)
                    except Exception as npc_error:
                        print(f"Error during NPC Actions phase: {npc_error}")
                        traceback.print_exc()

                # --- Phase: Player moves (list payload) ---
                elif isinstance(this_round_section_identifier, list):
                    # A list section identifier indicates the player actions sub-bundle.
                    # In the new design each element is a unified action dict; we pass
                    # them directly to the per-round player-action executor.
                    print("Processing Player Moves phase...")
                    try:
                        room_story_state_dict = update_dungeon_room_array_one_round(
                            this_round_player_actions_list=this_round_section_identifier,
                            room_story_state_dict=room_story_state_dict,
                            # solution_meta_data_dic removed: metadata now lives inside each action dict.
                            starting_move_index_from_0_integer=this_round_index_from_zero * 5
                        )
                        # print(f"room_story_state_dict updated for player moves.")
                    except Exception as player_error:
                        print(f"Error during Player Moves phase: {player_error}")
                        traceback.print_exc()

                # --- Phase: Elemental resonance effects ---
                elif this_round_section_identifier == "resonance_effect":
                    print("Applying Elemental Resonance Effects phase...")
                    try:
                        # Recompute resonance from the current room array snapshot.
                        current_room_array_state = room_story_state_dict.get("room_array", [])
                        item_resonance_report_dict, map_resonance_report_dict = calculate_cell_resonance_maps_reports(
                            current_room_array_state, room_metadata_dict
                        )

                        # Archive resonance reports into the state for possible visualization / validation.
                        room_story_state_dict["resonance_interactions_this_turn_start_items"] = item_resonance_report_dict
                        room_story_state_dict["resonance_interactions_this_turn_start_map"] = map_resonance_report_dict

                        # Apply the computed resonance energy deltas to object energies.
                        room_story_state_dict = apply_resonance_energy_to_state(
                            room_story_state_dict, item_resonance_report_dict
                        )
                    except Exception as resonance_error:
                        print(f"Error during Resonance Effects phase: {resonance_error}")
                        traceback.print_exc()

                # --- Phase: End-of-game check ---
                elif this_round_section_identifier in ["check_end_of_game", "check for end"]:
                    # all conditions for game-ended are met?
                    print("Checking for End of Game conditions...")
                    try:
                        game_end_status = check_for_end_of_game(room_story_state_dict)
                        print(f"Current game status resolved to: {game_end_status}")
                    except Exception as endgame_error:
                        print(f"Error during End of Game Evaluation phase: {endgame_error}")
                        traceback.print_exc()

                else:
                    # Unknown section identifier: log and skip rather than crash.
                    print(f"Unrecognized round section identifier encountered: {this_round_section_identifier}. Ignoring.")

                # =======================
                #  Check for End of Game
                # =======================
                # def check_for_end_of_game(room_story_state_dict):

                # initially False; flip True if the game has reached a terminal state.
                end_or_fail = False

                # --- Update `end_or_fail` based on the current game status ---
                if game_end_status == 'solved puzzle':
                    end_or_fail = True
                    print("Game is successfully solved!")
                elif game_end_status == 'lost':
                    end_or_fail = True
                    print("Game is lost.")
                else:
                    # 'still playing' path: keep iterating phases / rounds.
                    end_or_fail = False
                    # print("Game status is 'still playing'.")

                # print(f"Final `end_or_fail` variable state: {end_or_fail}")

                # Exit the phase loop immediately on terminal state.
                if end_or_fail is True:
                    break

            #############
            # Absorption
            #############
            # End-of-round absorption MUST run before cleanup so zero-energy entities
            # can be detected and removed in the same round.
            print("Processing Elemental Absorption...")
            try:
                room_story_state_dict = process_elemental_absorption(room_story_state_dict)
            except Exception as absorption_error:
                print(f"Error during Elemental Absorption phase: {absorption_error}")
                traceback.print_exc()

            ##########
            # Cleanup
            ##########
            # Execute cleanup once all sections of the round are complete.
            print("Cleaning up absorbed (zero-energy) entities...")
            try:
                room_story_state_dict = cleanup_absorbed_entities(room_story_state_dict)
            except Exception as cleanup_error:
                print(f"Error during Entity Cleanup phase: {cleanup_error}")
                traceback.print_exc()

            ##########################
            # update timeline archive
            ##########################
            """
            TODO
            this is probably too minimal
            what should be recorded?
            """
            # Deep-copy the state so the snapshot is isolated from future mutations.
            game_timeline_history_dictionary[this_round_index_from_zero] = copy.deepcopy(room_story_state_dict)

            # Terminal state: stop processing further rounds.
            if end_or_fail is True:
                break

            # Hard round-limit safety: force 'lost' if we've hit max_rounds without a win.
            if current_round_number >= max_rounds and game_end_status != 'solved puzzle':
                print(f"Game lost: Absolute maximum round limit ({max_rounds}) reached without puzzle resolution.")
                game_end_status = 'lost'
                end_or_fail = True
                break

        print(f"\niterate_through_whole_room_game() finished execution. Final Status: {game_end_status}")

        # Return the final status, timeline archive, final object state, and any std_error.
        return game_end_status, game_timeline_history_dictionary, room_story_state_dict['object_state'], std_error

    except Exception as execution_error:
        # Catch-all for any unhandled structural failure in the round orchestration.
        print(f"Complete structural failure within process_whole_room_game_all_rounds. Exception details: {execution_error}")
        traceback.print_exc()
        return "error", {}, None, str(execution_error)

