def test_npc_collision_with_obstacles():
    """
    Tests NPC behavior when blocked by other objects (non-empty cells).
    """
    try:
        print("\n--- Testing NPC vs Obstacle Interactions ---")

        # 1. Setup grid with an NPC and various obstacles
        test_grid = [['' for _ in range(8)] for _ in range(8)]

        # NPC 7 at (2, 2) moving East toward a Player (ID 5) at (2, 3)
        test_grid[2][2] = 7
        test_grid[2][3] = 5  # Player ID 5 acts as an obstacle

        # NPC 8 at (4, 4) moving South toward a Treasure (ID 2) at (5, 4)
        test_grid[4][4] = 8
        test_grid[5][4] = 2  # Treasure ID 2 acts as an obstacle

        state_dict = {
            'room_array': test_grid,
            'object_state': {
                'npc_state': {
                    '7': {'energy': 1, 'absorbed': False, 'movement': {'speed_1': 1, 'current_direction': 'east'}},
                    '8': {'energy': 1, 'absorbed': False, 'movement': {'speed_1': 1, 'current_direction': 'south'}}
                }
            }
        }

        # 2. Execute NPC actions
        updated_state = NPC_actions(state_dict)

        # 3. Assertions
        # NPC 7 should stay at (2, 2) and flip to West
        assert updated_state['room_array'][2][2] == 7, "NPC 7 moved into Player space!"
        assert updated_state['object_state']['npc_state']['7']['movement']['current_direction'] == 'west', "NPC 7 didn't bounce off Player!"

        # NPC 8 should stay at (4, 4) and flip to North
        assert updated_state['room_array'][4][4] == 8, "NPC 8 moved into Treasure space!"
        assert updated_state['object_state']['npc_state']['8']['movement']['current_direction'] == 'north', "NPC 8 didn't bounce off Treasure!"

        print("[SUCCESS] NPCs correctly bounced off Players and Treasures.")

    except Exception as error:
        print(f"[FAILURE] NPC Obstacle test failed: {error}")
        traceback.print_exc()

def test_npc_to_npc_collision():
    """
    Tests two NPCs attempting to move into the same square.
    NPCs are processed in ID order in our current NPC_actions loop.
    """
    try:
        print("\n--- Testing NPC to NPC Collisions ---")
        grid = [['' for _ in range(8)] for _ in range(8)]

        # NPC 1 at (0,0) moving East to (0,1)
        # NPC 2 at (0,2) moving West to (0,1)
        grid[0][0] = 1
        grid[0][2] = 2

        state = {
            'room_array': grid,
            'object_state': {
                'npc_state': {
                    '1': {'energy': 1, 'absorbed': False, 'movement': {'speed_1': 1, 'current_direction': 'east'}},
                    '2': {'energy': 1, 'absorbed': False, 'movement': {'speed_1': 1, 'current_direction': 'west'}}
                }
            }
        }

        # Processing:
        # 1. NPC 1 moves to (0,1).
        # 2. NPC 2 tries to move to (0,1), find it occupied by 1, and bounces.
        final_state = NPC_actions(state)

        assert final_state['room_array'][0][1] == 1, "NPC 1 failed to move to empty target cell."
        assert final_state['room_array'][0][2] == 2, "NPC 2 moved into occupied cell (0,1)."
        assert final_state['object_state']['npc_state']['2']['movement']['current_direction'] == 'east', "NPC 2 failed to bounce off NPC 1."

        print("[SUCCESS] NPC-to-NPC collision handled correctly by move order.")

    except Exception as error:
        print(f"[FAILURE] NPC-to-NPC test failed: {error}")
        traceback.print_exc()

