def run_end_game_tests():
    """
    Tests the check_for_end_of_game function across three primary scenarios:
    1. Ongoing game (still playing)
    2. Victory (solved puzzle)
    3. Defeat (lost)
    """
    # 1. Setup standard metadata
    standard_meta = {'door_relative_position': (7, 7)}

    # 2. Define 'Still Playing' scenario
    state_playing = {
        'room_array': [['' for _ in range(8)] for _ in range(8)],
        'room_metadata_dict': standard_meta,
        'object_state': {
            'npc_state': {'7': {'energy': 1, 'absorbed': False}},
            'treasure_chest_state': {'10': {'absorbed': False}},
            'player_character_state': {'a': {'energy': 1, 'exited_room': False}}
        }
    }
    state_playing['room_array'][0][0] = 'a'
    res_playing = check_for_end_of_game(state_playing)
    print(f"Scenario: Ongoing Game -> Result: {res_playing} (Expected: still playing)")
    assert res_playing == 'still playing', "Failed Still Playing check"

    # 3. Define 'Solved Puzzle' scenario
    state_won = {
        'room_array': [['' for _ in range(8)] for _ in range(8)],
        'room_metadata_dict': standard_meta,
        'object_state': {
            'npc_state': {'7': {'energy': 0, 'absorbed': True}},
            'treasure_chest_state': {'10': {'absorbed': True}},
            'player_character_state': {'a': {'energy': 1, 'exited_room': True}}
        }
    }
    res_won = check_for_end_of_game(state_won)
    print(f"Scenario: Victory -> Result: {res_won} (Expected: solved puzzle)")
    assert res_won == 'solved puzzle', "Failed Solved Puzzle check"

    # 4. Define 'Lost' scenario
    state_lost = {
        'room_array': [['' for _ in range(8)] for _ in range(8)],
        'room_metadata_dict': standard_meta,
        'object_state': {
            'npc_state': {},
            'treasure_chest_state': {},
            'player_character_state': {'a': {'energy': 0, 'exited_room': False}}
        }
    }
    state_lost['room_array'][2][2] = 'a' # Player is trapped away from exit with 0 energy
    res_lost = check_for_end_of_game(state_lost)
    print(f"Scenario: Defeat -> Result: {res_lost} (Expected: lost)")
    assert res_lost == 'lost', "Failed Lost check"

    print("\n[SUCCESS] All game-end logic assertions passed!")

# 5. Execute testing function
run_end_game_tests()

