def visualize_game_timeline(game_timeline: dict, room_metadata_dict: dict):
    """
    Visualizes the room_array state for each round in the game timeline,
    including a detailed legend of elements, statuses, and INVENTORIES for all objects.

    Args:
        game_timeline (dict): The history of the game state by round index.
        room_metadata_dict (dict): Room metadata for contextual info (like player mappings).
    """
    print("\n=== Game Timeline Visualization ===\n")
    if not game_timeline:
        print("Timeline is empty.")
        return

    # Invert the player turn map for better display (ID -> player letter)
    player_map = room_metadata_dict.get('player_turn_map', {})
    id_to_player = {v: k for k, v in player_map.items()}

    for round_index, state in sorted(game_timeline.items()):

        print(f"    --- End of Round {round_index + 1} ---")

        # column numbers
        print("    0  1  2  3  4  5  6  7")

        room_array = state.get('room_array', [])

        # Print the grid
        print("  +" + "---" * len(room_array[0]) + "+")
        row_counter = 0
        for row in room_array:
            # row numbers
            row_str = f"{row_counter} "

            row_str += "|"
            for cell in row:
                if cell == '':
                    row_str += " . "
                else:
                    # Format cell: if it's a player, show their letter, else show ID
                    display_val = id_to_player.get(cell, cell)
                    row_str += f"{str(display_val):>2} "
            row_str += "|"
            print(row_str)

            # increment
            row_counter += 1

        print("  +" + "---" * len(room_array[0]) + "+")

        # Print brief energy summary for players
        pc_state = state.get('object_state', {}).get('player_character_state', {})

        print("\n[ Player Status ]")
        for p_letter, p_data in pc_state.items():
            name = p_data.get('name', "unknown-namey")
            energy = p_data.get('energy', 0)
            exited = p_data.get('exited_room', False)
            element = p_data.get('element', 'unknown')
            status = p_data.get('status', 'active' if energy > 0 else 'exhausted')
            inventory = p_data.get('inventory [zero-based indices]', [])
            print(f" {name} {p_letter}: Element [{element:<6}] | Energy: {energy} | Status: {status} | Exited: {exited} | Inv: {inventory}")

        # Print status for NPCs and Treasures
        npc_state = state.get('object_state', {}).get('npc_state', {})
        treasure_state = state.get('object_state', {}).get('treasure_chest_state', {})

        print("\n[ Non-Player Objects on Board ]")
        for t_id, t_data in treasure_state.items():
            element = t_data.get('element', 'unknown')
            energy = t_data.get('energy', 0)
            absorbed = t_data.get('absorbed', False)
            print(f"  ID {t_id:<2}: Treasure | Element [{element:<6}] | Energy: {energy} | Absorbed: {absorbed}")

        for n_id, n_data in npc_state.items():
            element = n_data.get('element', 'unknown')
            energy = n_data.get('energy', 0)
            absorbed = n_data.get('absorbed', False)
            print(f"  ID {n_id:<2}: NPC      | Element [{element:<6}] | Energy: {energy} | Absorbed: {absorbed}")
        print("\n")

import traceback
from io import StringIO


def format_game_timeline_as_string(game_timeline: dict, room_metadata_dict: dict) -> str:
    """
    Builds a human-readable string representation of the room_array state for each
    round in the game timeline, including a detailed legend of elements, statuses,
    and INVENTORIES for all objects.

    This is a string-returning version of `visualize_game_timeline`. Instead of
    printing to stdout, it accumulates all output lines into a single string and
    returns that string. The textual content produced is identical (line-for-line)
    to what the original printing function emits to the terminal/notebook.

    Args:
        game_timeline (dict):
            The history of the game state, keyed by round index (int).
            Each value is a dict containing at minimum:
              - 'room_array': 2D list (rows of cells) describing the board layout.
              - 'object_state': dict with sub-dicts:
                  * 'player_character_state'
                  * 'npc_state'
                  * 'treasure_chest_state'
        room_metadata_dict (dict):
            Room metadata for contextual info. Expected to contain
            'player_turn_map' which maps player letters (e.g. 'A', 'B') to
            internal IDs. The mapping is inverted internally for display.

    Returns:
        str: A multi-line string containing the full timeline visualization.

    Raises:
        TypeError: If `game_timeline` or `room_metadata_dict` is not a dict.
    """
    # Defensive type checking with explicit, helpful error messages
    if not isinstance(game_timeline, dict):
        raise TypeError(
            f"format_game_timeline_as_string: 'game_timeline' must be a dict, "
            f"got {type(game_timeline).__name__}."
        )
    if not isinstance(room_metadata_dict, dict):
        raise TypeError(
            f"format_game_timeline_as_string: 'room_metadata_dict' must be a dict, "
            f"got {type(room_metadata_dict).__name__}."
        )

    # Use a StringIO buffer to accumulate output. We append lines as we go and
    # return the joined contents at the end.
    output_buffer: StringIO = StringIO()

    # Local helper that writes a line (with trailing newline) to our buffer.
    # This mirrors the behavior of `print(...)` in the original function.
    def write_line(text_to_append: str = "") -> None:
        """
        Append a single line of text (followed by a newline) to the output buffer.

        Args:
            text_to_append (str): Text content of the line. Defaults to empty.
        """
        output_buffer.write(text_to_append)
        output_buffer.write("\n")

    try:
        # Header
        write_line("\n=== Game Timeline Visualization ===\n")

        # Empty timeline early-exit, matching the original function's behavior
        if not game_timeline:
            write_line("Timeline is empty.")
            return output_buffer.getvalue()

        # Invert the player turn map for display (internal ID -> player letter).
        # Original behavior: player_map keys are player letters, values are IDs.
        player_letter_to_id_map: dict = room_metadata_dict.get('player_turn_map', {})
        id_to_player_letter_map: dict = {
            internal_id_value: player_letter_key
            for player_letter_key, internal_id_value in player_letter_to_id_map.items()
        }

        # Iterate timeline in ascending round order
        for round_index_int, state_dict in sorted(game_timeline.items()):

            # Round delimiter
            write_line(f"    --- End of Round {round_index_int + 1} ---")

            # Column header (assumes up to 8 columns; preserves original output)
            write_line("    0  1  2  3  4  5  6  7")

            # Pull the 2D room array; default to empty list if not present
            room_array_2d_list: list = state_dict.get('room_array', [])

            # If the room array is empty or has no first row, we still need to
            # produce a sensible top/bottom border. We compute width carefully.
            if room_array_2d_list and len(room_array_2d_list[0]) > 0:
                grid_width_columns: int = len(room_array_2d_list[0])
            else:
                # Fallback width of 0 produces just the corner markers
                grid_width_columns = 0

            # Top border of grid
            write_line("  +" + "---" * grid_width_columns + "+")

            # Render each row with leading row index
            row_index_counter_int: int = 0
            for row_list in room_array_2d_list:
                # Build the row line as a single string in the same format as original
                row_display_string: str = f"{row_index_counter_int} "
                row_display_string += "|"
                for cell_value in row_list:
                    if cell_value == '':
                        # Empty cell renders as a dot
                        row_display_string += " . "
                    else:
                        # If cell holds a player ID, show that player's letter;
                        # otherwise show the raw cell value.
                        cell_display_value = id_to_player_letter_map.get(cell_value, cell_value)
                        row_display_string += f"{str(cell_display_value):>2} "
                row_display_string += "|"
                write_line(row_display_string)

                # Advance row counter
                row_index_counter_int += 1

            # Bottom border of grid
            write_line("  +" + "---" * grid_width_columns + "+")

            # ---------- Player status section ----------
            player_character_state_dict: dict = (
                state_dict.get('object_state', {}).get('player_character_state', {})
            )

            write_line("\n[ Player Status ]")
            for player_letter_key, player_data_dict in player_character_state_dict.items():
                player_name_str = player_data_dict.get('name', "unknown-namey")
                player_energy_value = player_data_dict.get('energy', 0)
                player_exited_flag = player_data_dict.get('exited_room', False)
                player_element_str = player_data_dict.get('element', 'unknown')
                # Status default mirrors original logic: 'active' if energy > 0 else 'exhausted'
                player_status_str = player_data_dict.get(
                    'status',
                    'active' if player_energy_value > 0 else 'exhausted'
                )
                player_inventory_list = player_data_dict.get('inventory [zero-based indices]', [])
                write_line(
                    f" {player_name_str} {player_letter_key}: "
                    f"Element [{player_element_str:<6}] | "
                    f"Energy: {player_energy_value} | "
                    f"Status: {player_status_str} | "
                    f"Exited: {player_exited_flag} | "
                    f"Inv: {player_inventory_list}"
                )

            # ---------- NPC and Treasure section ----------
            npc_state_dict: dict = state_dict.get('object_state', {}).get('npc_state', {})
            treasure_chest_state_dict: dict = (
                state_dict.get('object_state', {}).get('treasure_chest_state', {})
            )

            write_line("\n[ Non-Player Objects on Board ]")

            # Treasures first (preserving original ordering)
            for treasure_id_key, treasure_data_dict in treasure_chest_state_dict.items():
                treasure_element_str = treasure_data_dict.get('element', 'unknown')
                treasure_energy_value = treasure_data_dict.get('energy', 0)
                treasure_absorbed_flag = treasure_data_dict.get('absorbed', False)
                write_line(
                    f"  ID {treasure_id_key:<2}: Treasure | "
                    f"Element [{treasure_element_str:<6}] | "
                    f"Energy: {treasure_energy_value} | "
                    f"Absorbed: {treasure_absorbed_flag}"
                )

            # Then NPCs
            for npc_id_key, npc_data_dict in npc_state_dict.items():
                npc_element_str = npc_data_dict.get('element', 'unknown')
                npc_energy_value = npc_data_dict.get('energy', 0)
                npc_absorbed_flag = npc_data_dict.get('absorbed', False)
                write_line(
                    f"  ID {npc_id_key:<2}: NPC      | "
                    f"Element [{npc_element_str:<6}] | "
                    f"Energy: {npc_energy_value} | "
                    f"Absorbed: {npc_absorbed_flag}"
                )

            # Trailing blank line between rounds (matches original print("\n"))
            write_line("\n")

        # Return the assembled multi-line string
        return output_buffer.getvalue()

    except Exception as caught_exception:
        # Surface a descriptive error including a traceback. We do not silently
        # swallow the error; we re-raise after annotating context.
        formatted_traceback_str: str = traceback.format_exc()
        raise RuntimeError(
            "format_game_timeline_as_string: failed while building timeline string.\n"
            f"Original exception type: {type(caught_exception).__name__}\n"
            f"Original exception message: {caught_exception}\n"
            f"Traceback:\n{formatted_traceback_str}"
        ) from caught_exception

