def build_move_action_dict(
        player_id_string: str,
        move_from_row_col_list: list,
        move_to_row_col_list: list
) -> dict:
    """
    Construct a single one_player_action_data_dict for a 'move' action.

    Args:
        player_id_string (str): The player identifier (e.g. 'a').
        move_from_row_col_list (list): [row_int, col_int] source cell.
        move_to_row_col_list (list):   [row_int, col_int] destination cell.

    Returns:
        dict: A one_player_action_data_dict representing this move action.
    """
    move_action_dict = {
        "player_id":        player_id_string,
        "action_type":      "move_self",
        "throw_from_coord": None,
        "throw_to_coord":   None,
        "move_from_coord":  list(move_from_row_col_list),
        "move_to_coord":    list(move_to_row_col_list),
    }
    return move_action_dict

