def generate_legend(room_story_state_dict):
    """
    Generates a human-readable legend mapping integer IDs
    in the room_array to entity details.
    Iterates over the player_turn_map to guarantee
    that only true players ('a'-'e') are shown.
    """
    try:
        room_meta = room_story_state_dict.get('room_metadata_dict', {})
        object_state = room_story_state_dict.get('object_state', {})

        legend_lines = ["=== Room Legend ==="]

        # Process players explicitly using the player_turn_map (a-e)
        player_map = room_meta.get('player_turn_map', {})
        legend_lines.append("\n-- Players --")
        pc_state = object_state.get('player_character_state', {})

        for p_label, p_id_int in player_map.items():
            p_id_str = str(p_id_int)
            p_data = pc_state.get(p_id_str, {})  # The letter A, B, C, D, E
            element = p_data.get('element', 'None')
            name = p_data.get('name', 'Unknown-namey')
            energy = p_data.get('energy', 0)
            inventory = p_data.get('inventory [zero-based indices]', [])
            legend_lines.append(f"{name} ID {p_id_str} -> Player '{p_label}' | Element: {element} | Energy: {energy} | Inventory: {inventory}")

        # Process NPCs
        legend_lines.append("\n-- NPCs --")
        npc_state = object_state.get('npc_state', {})
        for n_id, n_data in npc_state.items():
            element = n_data.get('element', 'None')
            energy = n_data.get('energy', 0)
            legend_lines.append(f"ID {n_id} -> NPC | Element: {element} | Energy: {energy}")

        # Process Treasures
        legend_lines.append("\n-- Treasures --")
        treasure_state = object_state.get('treasure_chest_state', {})
        for t_id, t_data in treasure_state.items():
            element = t_data.get('element', 'None')
            energy = t_data.get('energy', 0)
            legend_lines.append(f"ID {t_id} -> Treasure | Element: {element} | Energy: {energy}")

        legend_str = "\n".join(legend_lines)
        print(legend_str)
        return legend_str

    except Exception as e:
        print(f"Error generating legend: {e}")
        traceback.print_exc()
        return ""

