def execute_v3_puzzle_simulation(
    random_seed_integer: int,
    number_of_treasures_integer: int,
    number_of_npc_integer: int,
    types_of_npc_integer: int,
    solution_action_dict_list: list,
    max_rounds_integer: int = 100
) -> tuple:
    """
    Executes the V3 puzzle simulation workflow.

    Args:
        random_seed_integer (int): Seed for reproducible room generation.
        number_of_treasures_integer (int): Number of treasures to place in the room.
        number_of_npc_integer (int): Number of NPCs to place in the room.
        types_of_npc_integer (int): Variety of NPC types.
        solution_action_dict_list (list): Chronological list of action dictionaries.
        max_rounds_integer (int, optional): Absolute maximum round limit. Defaults to 100.

    Returns:
        tuple: A tuple containing:
            - final_game_status_string (str): Final outcome ('solved puzzle', 'lost', etc.).
            - game_timeline_history_dictionary (dict): Round-by-round state history.
            - execution_error_string (str or None): Error message if any, else None.
    """
    try:
        print(f"\n=== Starting V3 Puzzle Simulation (Seed: {random_seed_integer}) ===")

        # Generate room
        generated_room_array, generated_room_metadata_dict = generate_deterministic_dungeon_room(
            random_seed_integer=random_seed_integer,
            number_of_treasures_integer=number_of_treasures_integer,
            number_of_npc_integer=number_of_npc_integer,
            types_of_npc_integer=types_of_npc_integer
        )
        if not generated_room_array: return "error", {}, "Room generation failed."

        # Build state
        room_story_state_dict = build_initial_roomstory_statedictionary(
            starting_room_array=generated_room_array,
            starting_room_metadata_dict=generated_room_metadata_dict
        )
        room_story_state_dict['room_array'] = generated_room_array
        room_story_state_dict['room_metadata_dict'] = generated_room_metadata_dict

        # Run simulation
        final_game_status, timeline, obj_state, execution_error = process_whole_room_game_all_rounds(
            solution_action_dict_list=solution_action_dict_list,
            room_story_state_dict=room_story_state_dict,
            max_rounds=max_rounds_integer
        )

        # Visualize
        if timeline:
            visualize_game_timeline(timeline, generated_room_metadata_dict)

        return final_game_status, timeline, execution_error

    except Exception as error:
        print(f"Critical error: {error}")
        traceback.print_exc()
        return "error", {}, str(error)

def execute_v4_puzzle_evaluation(
    random_seed_integer: int,
    number_of_treasures_integer: int,
    number_of_npc_integer: int,
    types_of_npc_integer: int,
    solution_action_dict_list: list,
    max_rounds_integer: int = 100
) -> tuple:
    """
    Executes the V3 puzzle simulation workflow.

    Args:
        random_seed_integer (int): Seed for reproducible room generation.
        number_of_treasures_integer (int): Number of treasures to place in the room.
        number_of_npc_integer (int): Number of NPCs to place in the room.
        types_of_npc_integer (int): Variety of NPC types.
        solution_action_dict_list (list): Chronological list of action dictionaries.
        max_rounds_integer (int, optional): Absolute maximum round limit. Defaults to 100.

    Returns:
        tuple: A tuple containing:
            - final_game_status_string (str): Final outcome ('solved puzzle', 'lost', etc.).
            - game_timeline_history_dictionary (dict): Round-by-round state history.
            - execution_error_string (str or None): Error message if any, else None.
    """
    try:
        print(f"\n=== Starting V3 Puzzle Simulation (Seed: {random_seed_integer}) ===")

        # Generate room
        generated_room_array, generated_room_metadata_dict = generate_deterministic_dungeon_room(
            random_seed_integer=random_seed_integer,
            number_of_treasures_integer=number_of_treasures_integer,
            number_of_npc_integer=number_of_npc_integer,
            types_of_npc_integer=types_of_npc_integer
        )
        if not generated_room_array: return "error", "failed", {}, "Room generation failed."

        # Build state
        room_story_state_dict = build_initial_roomstory_statedictionary(
            starting_room_array=generated_room_array,
            starting_room_metadata_dict=generated_room_metadata_dict
        )
        room_story_state_dict['room_array'] = generated_room_array
        room_story_state_dict['room_metadata_dict'] = generated_room_metadata_dict

        # Run simulation
        final_game_status, raw_timeline, obj_state, execution_error = process_whole_room_game_all_rounds(
            solution_action_dict_list=solution_action_dict_list,
            room_story_state_dict=room_story_state_dict,
            max_rounds=max_rounds_integer
        )

        # format as string
        if raw_timeline:
            # visualize_game_timeline(timeline, generated_room_metadata_dict)
            string_formatted_timeline = format_game_timeline_as_string(timeline, generated_room_metadata_dict)

        return final_game_status, string_formatted_timeline, raw_timeline, execution_error

    except Exception as error:
        print(f"Critical error: {error}")
        traceback.print_exc()
        return "error", {}, str(error)

