def get_player_id_coordinates(
    player_id_string: str,
    room_story_state_dictionary: dict
) -> tuple | None:
    """
    Retrieves the 2D grid coordinates (row, column) for a specific player character.

    This function extracts the necessary metadata and physical grid array from the
    master state dictionary. It translates the human-readable player string identifier
    (e.g., 'a', 'b') into its internal integer representation, and then locates that
    integer ID within the physical room array.

    Args:
        player_id_string (str): The string identifier for the player (e.g., 'a').
        room_story_state_dictionary (dict): The master game state dictionary containing
            the 'room_array' and 'room_metadata_dict'.

    Returns:
        tuple | None: A tuple containing (row_index_integer, column_index_integer) if the
            player is found on the board. Returns None if the player is not found or
            if an error occurs during processing.
    """
    try:
        # 1. Extract the physical grid and metadata mapping from the master state
        current_room_array_list = room_story_state_dictionary.get('room_array')
        current_room_metadata_dictionary = room_story_state_dictionary.get('room_metadata_dict')

        # Guard clause to ensure required data structures exist
        if not current_room_array_list or not current_room_metadata_dictionary:
            print(f"Error in get_player_id_coordinates: Missing 'room_array' or 'room_metadata_dict' for player '{player_id_string}'.")
            return None

        # 2. Retrieve the mapping dictionary that connects string IDs to integer IDs
        player_turn_mapping_dictionary = current_room_metadata_dictionary.get('player_turn_map', {})

        # 3. Translate the string ID to the internal integer ID
        # Fallback to the string itself if it is not found in the map (defensive programming)
        internal_player_integer_id = player_turn_mapping_dictionary.get(player_id_string, player_id_string)

        # 4. Utilize the existing helper function to locate the object on the grid
        player_coordinate_tuple = find_object_position(
            room_array=current_room_array_list,
            target_id=internal_player_integer_id
        )

        if not player_coordinate_tuple:
            print(f"Notice: Player '{player_id_string}' (Internal ID: {internal_player_integer_id}) is currently not on the board.")
            return None

        # 5. Return the successfully found coordinate tuple
        return player_coordinate_tuple

    except Exception as coordinate_lookup_error:
        # Production safe error handling: print clear message and full traceback
        print(f"Critical error in get_player_id_coordinates while looking up player '{player_id_string}': {coordinate_lookup_error}")
        traceback.print_exc()
        return None

