def generate_single_text_response_from_google_ai_studio(
    user_prompt_text: str,
    google_ai_studio_api_key: str,
    gemini_model_name: str,
    maximum_output_tokens: int = 1024,
    sampling_temperature: float = 0.9,
) -> str:
    """
    Generate a single text completion from Google AI Studio's Gemini API.

    This function performs ONE non-streaming, non-chat (no history) text
    generation call against the Google AI Studio endpoint
    (generativelanguage.googleapis.com), using the official `google-genai`
    Python SDK. It returns the model's text output as a single string.

    This function intentionally does NOT:
      - maintain any chat history
      - stream tokens
      - perform tool / function calling
      - upload files or images
      - use Vertex AI (which would require a Google Cloud project, region,
        and service-account or ADC credentials).

    Authentication:
        Google AI Studio requires only an API key (a single string starting
        with "AIza..."). You do NOT need a project name or project number;
        those are for Vertex AI, which is a different product.

        In Google Colab, retrieve the key like this BEFORE calling this
        function:

            from google.colab import userdata
            api_key_string = userdata.get("GOOGLE_AI_STUDIO_API_KEY")

        Then pass `api_key_string` as the `google_ai_studio_api_key` argument.

    Args:
        user_prompt_text:
            The prompt to send to the model. A plain string. No role tags,
            no system message, no prior turns.
        google_ai_studio_api_key:
            The Google AI Studio API key string (e.g. "AIza..."). This is
            the only credential required. Must be non-empty.
        gemini_model_name:
            The Gemini model identifier to use. Defaults to
            "gemini-2.5-flash". Other examples: "gemini-2.5-pro",
            "gemini-2.0-flash". Pick whichever your key has access to.
        maximum_output_tokens:
            Hard upper bound on the number of tokens the model is allowed
            to generate in its response. Defaults to 1024.
        sampling_temperature:
            Sampling temperature in the range [0.0, 2.0]. Lower values
            produce more deterministic output; higher values produce more
            varied output. Defaults to 0.7.

    Returns:
        A single string containing the model's generated text response.
        Trailing/leading whitespace is preserved exactly as returned by
        the API.

    Raises:
        ValueError:
            If `user_prompt_text` is empty/whitespace-only, or if
            `google_ai_studio_api_key` is empty/whitespace-only, or if
            the API returns a response that contains no usable text.
        RuntimeError:
            If the underlying SDK call fails for any reason (network
            error, authentication error, quota error, invalid model
            name, safety blocking, etc.). The original traceback is
            included in the error message to aid debugging.
    """

    # ---- 1. Validate inputs explicitly (fail fast, clear messages) ----
    if not isinstance(user_prompt_text, str) or not user_prompt_text.strip():
        raise ValueError(
            "Argument `user_prompt_text` must be a non-empty, "
            "non-whitespace string. Got: "
            f"{user_prompt_text!r}"
        )

    if (
        not isinstance(google_ai_studio_api_key, str)
        or not google_ai_studio_api_key.strip()
    ):
        raise ValueError(
            "Argument `google_ai_studio_api_key` must be a non-empty "
            "string. In Colab, retrieve it with "
            "`from google.colab import userdata; "
            "userdata.get('GOOGLE_AI_STUDIO_API_KEY')` after storing it "
            "in the Colab Secrets panel."
        )

    if not isinstance(gemini_model_name, str) or not gemini_model_name.strip():
        raise ValueError(
            "Argument `gemini_model_name` must be a non-empty string, "
            f"e.g. 'gemini-2.5-flash'. Got: {gemini_model_name!r}"
        )

    if not isinstance(maximum_output_tokens, int) or maximum_output_tokens <= 0:
        raise ValueError(
            "Argument `maximum_output_tokens` must be a positive int. "
            f"Got: {maximum_output_tokens!r}"
        )

    if (
        not isinstance(sampling_temperature, (int, float))
        or sampling_temperature < 0.0
        or sampling_temperature > 2.0
    ):
        raise ValueError(
            "Argument `sampling_temperature` must be a number in the "
            f"closed range [0.0, 2.0]. Got: {sampling_temperature!r}"
        )

    # ---- 2. Build the SDK client (Google AI Studio mode, NOT Vertex) ----
    try:
        google_genai_client = genai.Client(api_key=google_ai_studio_api_key)
    except Exception as client_construction_exception:
        # Catch broadly because constructing the client can fail for
        # several distinct reasons (bad key format, missing dependency,
        # etc.) and we want a single clear surfaced message.
        raise RuntimeError(
            "Failed to construct the google-genai Client for Google AI "
            "Studio. Check that the `google-genai` package is installed "
            "and that the API key is a valid Google AI Studio key.\n"
            f"Original exception: {client_construction_exception!r}\n"
            f"Traceback:\n{traceback.format_exc()}"
        ) from client_construction_exception

    # ---- 3. Build the per-call generation configuration ----
    generation_configuration_object = google_genai_types.GenerateContentConfig(
        temperature=float(sampling_temperature),
        max_output_tokens=int(maximum_output_tokens),
    )

    # ---- 4. Perform the single non-streaming generation call ----
    try:
        gemini_api_response_object = google_genai_client.models.generate_content(
            model=gemini_model_name,
            contents=user_prompt_text,
            config=generation_configuration_object,
        )
    except Exception as api_call_exception:
        raise RuntimeError(
            "Google AI Studio `generate_content` call failed. Possible "
            "causes: invalid API key, model name not available to this "
            "key, network error, quota exceeded, or safety blocking.\n"
            f"Model requested: {gemini_model_name!r}\n"
            f"Original exception: {api_call_exception!r}\n"
            f"Traceback:\n{traceback.format_exc()}"
        ) from api_call_exception

    # ---- 5. Extract the text safely ----
    # The SDK exposes a convenience attribute `.text` that concatenates
    # any text parts in the first candidate. It can be None if the model
    # returned no text (e.g. fully blocked by safety filters).
    generated_text_or_none = getattr(gemini_api_response_object, "text", None)

    if generated_text_or_none is None or not isinstance(
        generated_text_or_none, str
    ):
        # Surface as much diagnostic info as we reasonably can.
        prompt_feedback_value = getattr(
            gemini_api_response_object, "prompt_feedback", None
        )
        candidates_value = getattr(
            gemini_api_response_object, "candidates", None
        )
        raise ValueError(
            "Google AI Studio returned a response with no usable text. "
            "This commonly indicates safety blocking or an empty "
            "completion.\n"
            f"prompt_feedback: {prompt_feedback_value!r}\n"
            f"candidates: {candidates_value!r}"
        )

    return generated_text_or_none

