"""### Anthropic API"""

"""
Minimal Anthropic API text generation helper for Google Colab.

Requires:
    - The `anthropic` package installed: `!pip install anthropic`
    - An Anthropic API key stored in Colab user secrets under a known name,
      retrievable via `google.colab.userdata.get(secret_name)`.
"""

# import traceback
# from google.colab import userdata

# try:
#     import anthropic
# except Exception as e:
#     print(str(e))
#     !pip install anthropic
#     import anthropic

def generate_text_from_anthropic_api(
    user_prompt_text: str,
    anthropic_api_key: str,
    anthropic_model_name: str,
    maximum_output_tokens: int = 1024,
    sampling_temperature: float = 1.0,
    optional_system_instruction_text: str | None = None,
) -> str:
    """
    Send a single user prompt to the Anthropic Messages API and return the
    generated text as a string. No chat history is maintained; each call is
    a single, independent, stateless request.

    Arguments:
        user_prompt_text (str):
            The text prompt to send to the model as the single user message.
            Must be a non-empty string.

        anthropic_api_key (str):

        anthropic_model_name (str):
            The Anthropic model identifier to use for generation
            (for example "claude-sonnet-4-5" or "claude-opus-4-5").
            Defaults to "claude-sonnet-4-5".

        maximum_output_tokens (int):
            The maximum number of tokens the model is allowed to generate
            in its response. Must be a positive integer.
            Defaults to 1024.

        sampling_temperature (float):
            The sampling temperature passed to the API. Typically in the
            range [0.0, 1.0]. Lower values produce more deterministic output.
            Defaults to 1.0.

        optional_system_instruction_text (str | None):
            An optional system-level instruction string that conditions the
            model's behavior (e.g. "You are a concise assistant.").
            If None, no system instruction is sent.
            Defaults to None.

    Returns:
        str:
            The concatenated plain-text content returned by the model for
            this single request.

    Raises:
        ValueError:
            If `user_prompt_text` is empty, if `maximum_output_tokens` is not
            a positive integer, or if the API key cannot be retrieved from
            Colab user secrets.
        RuntimeError:
            If the Anthropic API call fails for any reason, or if the
            response does not contain any text content blocks. The original
            traceback is printed to aid debugging.
    """

    # ---- Input validation (fail loudly with specific messages) -------------
    if not isinstance(user_prompt_text, str) or len(user_prompt_text.strip()) == 0:
        raise ValueError(
            "generate_text_from_anthropic_api: 'user_prompt_text' must be a "
            "non-empty string. Received: {!r}".format(user_prompt_text)
        )

    if not isinstance(maximum_output_tokens, int) or maximum_output_tokens <= 0:
        raise ValueError(
            "generate_text_from_anthropic_api: 'maximum_output_tokens' must be "
            "a positive integer. Received: {!r}".format(maximum_output_tokens)
        )

    # ---- Build Anthropic client --------------------------------------------
    try:
        anthropic_api_client = anthropic.Anthropic(api_key=anthropic_api_key)
    except Exception as client_construction_error:
        traceback.print_exc()
        raise RuntimeError(
            "generate_text_from_anthropic_api: Failed to construct the "
            "Anthropic client. Underlying error: {}".format(client_construction_error)
        ) from client_construction_error

    # ---- Build kwargs for the messages.create call -------------------------
    # Single-turn, stateless: exactly one user message, no prior history.
    messages_create_keyword_arguments: dict = {
        "model": anthropic_model_name,
        "max_tokens": maximum_output_tokens,
        "temperature": sampling_temperature,
        "messages": [
            {
                "role": "user",
                "content": user_prompt_text,
            }
        ],
    }

    # Only include the system instruction if explicitly provided.
    if optional_system_instruction_text is not None:
        if not isinstance(optional_system_instruction_text, str):
            raise ValueError(
                "generate_text_from_anthropic_api: "
                "'optional_system_instruction_text' must be a string or None. "
                "Received: {!r}".format(optional_system_instruction_text)
            )
        messages_create_keyword_arguments["system"] = optional_system_instruction_text

    # ---- Make the API call -------------------------------------------------
    try:
        anthropic_api_response = anthropic_api_client.messages.create(
            **messages_create_keyword_arguments
        )
    except Exception as anthropic_api_call_error:
        traceback.print_exc()
        raise RuntimeError(
            "generate_text_from_anthropic_api: Anthropic API call failed. "
            "Model: {!r}. Underlying error: {}".format(
                anthropic_model_name, anthropic_api_call_error
            )
        ) from anthropic_api_call_error

    # ---- Extract text content from response blocks -------------------------
    # The response contains a list of content blocks. We collect text from
    # blocks whose `type` attribute is "text".
    collected_text_segments_list: list[str] = []
    try:
        for response_content_block in anthropic_api_response.content:
            content_block_type_string = getattr(response_content_block, "type", None)
            if content_block_type_string == "text":
                content_block_text_string = getattr(response_content_block, "text", "")
                collected_text_segments_list.append(content_block_text_string)
    except Exception as response_parsing_error:
        traceback.print_exc()
        raise RuntimeError(
            "generate_text_from_anthropic_api: Failed to parse Anthropic API "
            "response content. Underlying error: {}".format(response_parsing_error)
        ) from response_parsing_error

    if len(collected_text_segments_list) == 0:
        raise RuntimeError(
            "generate_text_from_anthropic_api: Anthropic API response "
            "contained no text content blocks. Full response: {!r}".format(
                anthropic_api_response
            )
        )

    # Concatenate all text blocks into a single string and return.
    final_generated_text_string: str = "".join(collected_text_segments_list)
    return final_generated_text_string

