def _find_all_balanced_brace_substrings_in_text(
    raw_text_input_string: str,
) -> list[str]:
    """
    Scan raw text and return every top-level balanced { ... } substring.

    This is a simple brace-depth scanner; it does NOT understand strings
    containing literal braces, but it is sufficient for typical LLM JSON
    object output. Returned substrings appear in the order they were found.

    Args:
        raw_text_input_string: Arbitrary text potentially containing JSON-like objects.

    Returns:
        List of substrings, each starting with '{' and ending with the matching '}'.
    """
    collected_brace_substrings_list: list[str] = []
    current_open_brace_start_index: int | None = None
    current_brace_nesting_depth_count: int = 0

    # Walk character-by-character tracking brace depth.
    for character_index_in_text, current_character in enumerate(raw_text_input_string):
        if current_character == "{":
            if current_brace_nesting_depth_count == 0:
                current_open_brace_start_index = character_index_in_text
            current_brace_nesting_depth_count += 1
        elif current_character == "}":
            if current_brace_nesting_depth_count > 0:
                current_brace_nesting_depth_count -= 1
                if (
                    current_brace_nesting_depth_count == 0
                    and current_open_brace_start_index is not None
                ):
                    collected_brace_substrings_list.append(
                        raw_text_input_string[
                            current_open_brace_start_index : character_index_in_text + 1
                        ]
                    )
                    current_open_brace_start_index = None

    return collected_brace_substrings_list


def _attempt_parse_json_object_from_substring(
    candidate_json_substring: str,
) -> dict | None:
    """
    Try to parse a candidate substring as a JSON object dict.

    Performs minor tolerant cleanup:
    - Replaces Python literals 'None'/'True'/'False' with JSON 'null'/'true'/'false'.
    - Replaces single quotes with double quotes ONLY as a fallback if strict parse fails.

    Args:
        candidate_json_substring: A '{ ... }' substring to parse.

    Returns:
        Parsed dict if successful, otherwise None.
    """
    # Strict attempt first (preferred path).
    try:
        strict_parse_result_object = json.loads(candidate_json_substring)
        if isinstance(strict_parse_result_object, dict):
            return strict_parse_result_object
        return None
    except json.JSONDecodeError:
        pass  # Fall through to tolerant attempt below.

    # Tolerant attempt: normalize Python-style literals to JSON-style.
    tolerant_candidate_string = candidate_json_substring
    tolerant_candidate_string = re.sub(r"\bNone\b", "null", tolerant_candidate_string)
    tolerant_candidate_string = re.sub(r"\bTrue\b", "true", tolerant_candidate_string)
    tolerant_candidate_string = re.sub(r"\bFalse\b", "false", tolerant_candidate_string)

    try:
        tolerant_parse_result_object = json.loads(tolerant_candidate_string)
        if isinstance(tolerant_parse_result_object, dict):
            return tolerant_parse_result_object
        return None
    except json.JSONDecodeError:
        pass

    # Last-resort: swap single quotes for double quotes.
    last_resort_candidate_string = tolerant_candidate_string.replace("'", '"')
    try:
        last_resort_parse_result_object = json.loads(last_resort_candidate_string)
        if isinstance(last_resort_parse_result_object, dict):
            return last_resort_parse_result_object
        return None
    except json.JSONDecodeError:
        return None


def extract_last_player_action_dict_from_raw_text(
    raw_generative_ai_output_text: str,
) -> dict | None:
    """
    Extract the LAST valid one_player_action_data_dict from raw LLM output text.

    Expected schema of returned dict:
        {
            "player_id":        str,                       # required, non-empty
            "action_type":      str,                       # required, one of:
                                                           #   "throw", "move",
                                                           #   "exit_room", "skip_turn"
            "throw_from_coord": [int, int] | None,         # optional
            "throw_to_coord":   [int, int] | None,         # optional
            "move_from_coord":  [int, int] | None,         # optional
            "move_to_coord":    [int, int] | None,         # optional
        }

    Behavior:
    - Scans the input for all balanced '{ ... }' substrings.
    - Attempts strict + tolerant JSON parsing on each.
    - Validates each parsed dict against the schema.
    - Returns the LAST schema-valid dict (because the LLM output may contain
      multiple candidates, e.g., examples earlier in the text).
    - Returns None if no valid dict is found.

    Args:
        raw_generative_ai_output_text: Full text emitted by the generative AI.

    Returns:
        Validated/normalized dict (last valid occurrence) or None.

    Raises:
        TypeError: If the input is not a string.
    """
    if not isinstance(raw_generative_ai_output_text, str):
        raise TypeError(
            "extract_last_player_action_dict_from_raw_text: "
            "raw_generative_ai_output_text must be a str, got "
            f"{type(raw_generative_ai_output_text).__name__}"
        )

    try:
        all_brace_substrings_list = _find_all_balanced_brace_substrings_in_text(
            raw_generative_ai_output_text
        )

        last_valid_player_action_dict_found: dict | None = None

        # Iterate in textual order; keep overwriting -> ends up as LAST valid one.
        for one_brace_substring in all_brace_substrings_list:
            parsed_candidate_dict_or_none = _attempt_parse_json_object_from_substring(
                one_brace_substring
            )
            if parsed_candidate_dict_or_none is None:
                continue
            normalized_or_none = _validate_and_normalize_player_action_dict(
                parsed_candidate_dict_or_none
            )
            if normalized_or_none is not None:
                last_valid_player_action_dict_found = normalized_or_none

        return last_valid_player_action_dict_found

    except Exception as unexpected_extraction_error:
        # Surface a clear specific error message; do not hide.
        traceback.print_exc()
        raise RuntimeError(
            "extract_last_player_action_dict_from_raw_text: unexpected failure "
            f"while parsing player action dict: {unexpected_extraction_error!r}"
        ) from unexpected_extraction_error


