# ---------------------------------------------------------------------------
# 3. start_round=true boolean signal detection
# ---------------------------------------------------------------------------

# Regex to keep ONLY ASCII letters; everything else is stripped.
_NON_ALPHABET_CHARACTERS_REMOVAL_REGEX: re.Pattern = re.compile(r"[^A-Za-z]+")

# The canonical signal we look for after lowercase + strip-non-alpha.
START_ROUND_TRUE_CANONICAL_SIGNAL_TOKEN: str = "startroundtrue"


def detect_start_round_true_signal_in_raw_text(
    raw_generative_ai_output_text: str,
) -> bool:
    """
    Detect whether the raw text contains a 'start_round = true' signal.

    This is intentionally a LOOSE signal-detection match (NOT strict JSON).
    Procedure:
      1. Lowercase the input text.
      2. Remove every character that is not an ASCII letter A-Z / a-z.
      3. Test whether the resulting string contains 'startroundtrue'.

    Examples that ALL evaluate to True:
        '"start_round": true'
        '"start_Round":True'
        'start round = True'
        'startRound: TRUE'
        '<<start_round=true>>'

    Args:
        raw_generative_ai_output_text: Full text emitted by the generative AI.

    Returns:
        True if any variation of start_round + true is detected; otherwise False.

    Raises:
        TypeError: If the input is not a string.
    """
    if not isinstance(raw_generative_ai_output_text, str):
        raise TypeError(
            "detect_start_round_true_signal_in_raw_text: "
            "raw_generative_ai_output_text must be a str, got "
            f"{type(raw_generative_ai_output_text).__name__}"
        )

    try:
        lowercased_input_text_string = raw_generative_ai_output_text.lower()
        alphabet_only_collapsed_text_string = _NON_ALPHABET_CHARACTERS_REMOVAL_REGEX.sub(
            "", lowercased_input_text_string
        )
        return (
            START_ROUND_TRUE_CANONICAL_SIGNAL_TOKEN
            in alphabet_only_collapsed_text_string
        )

    except Exception as unexpected_signal_detection_error:
        traceback.print_exc()
        raise RuntimeError(
            "detect_start_round_true_signal_in_raw_text: unexpected failure "
            f"while detecting start_round signal: {unexpected_signal_detection_error!r}"
        ) from unexpected_signal_detection_error

