def log_player_turn_output(
    player_id_string: str,
    raw_output_string: str,
    raw_input_prompt: str,
    extracted_action_dict: dict,
    extracted_memo_string: str,
    extracted_start_round_boolean: bool,
    game_timestamp_string: str = "default_game",
    round_number_int: int = 0
) -> None:
    """
    Logs the raw LLM output and the extracted structured data to a timestamped file.
    This provides an audit trail for what the bot 'thought' versus what the system 'understood'.

    Args:
        player_id_string (str): The bot's ID (e.g., 'a', 'b').
        raw_output_string (str): The exact string returned by the LLM.
        extracted_action_dict (dict): The parsed JSON action dictionary.
        extracted_memo_string (str): The parsed memo text.
        extracted_start_round_boolean (bool): Whether the bot voted to start the round.
        game_timestamp_string (str): The timestamp of the current game session.
        round_number_int (int): The current round number.

    Returns:
        None
    """
    try:
        # Ensure a directory exists for the logs to prevent clutter
        # # Using /content/logs makes it easily visible in the Colab file browser
        # log_directory_string = f"/content/logs/game_{game_timestamp_string}/round_{round_number_int}"
        # os.makedirs(log_directory_string, exist_ok=True)

        project_logs_base_directory_path = resolve_project_logs_base_directory()

        # Build the per-round log directory from the supplied base path.
        # No more hard-coded '/content/...'.
        log_directory_string = os.path.join(
            project_logs_base_directory_path,
            f"game_{game_timestamp_string}",
            f"round_{round_number_int}",
        )
        os.makedirs(log_directory_string, exist_ok=True)


        # Generate a clear, sortable timestamp
        timestamp_string = datetime.now().strftime("%Y%m%d_%H%M%S")
        file_name_string = f"playerlog_{timestamp_string}_{player_id_string}.json"
        full_file_path_string = os.path.join(log_directory_string, file_name_string)

        # Construct the log payload
        log_payload_dict = {
            "timestamp": timestamp_string,
            "player_id": player_id_string,
            "extracted_data": {
                "action_dict": extracted_action_dict,
                "start_round_vote": extracted_start_round_boolean,
                "note_share_memo": extracted_memo_string
            },
            "raw_input_prompt": raw_input_prompt,
            "raw_llm_output": raw_output_string,
        }

        # Write the structured log to disk
        with open(full_file_path_string, 'w', encoding='utf-8') as log_file:
            json.dump(log_payload_dict, log_file, indent=4)

        print(f"[Logger] Player {player_id_string} turn logged to: {full_file_path_string}")

    except Exception as logging_error:
        print(f"[Critical Error] Failed to log player turn output for {player_id_string}: {logging_error}")
        traceback.print_exc()

