def write_action_extraction_failure_log_file(
    player_id_string: str,
    raw_text_output_string: str,
    prompt_text_string: str,
    game_timestamp_string: str,
    round_number_int: int,
    extraction_failure_directory_path: str = "logs/extraction_failures",
) -> str | None:
    """
    Persist a record of an action-extraction failure to disk.

    This function is called when the raw LLM output could not be parsed into a
    valid action dictionary by `extract_last_player_action_dict_from_raw_text`.
    Silently swallowing such failures is forbidden by project rules: this
    function ensures the offending raw output is preserved for later debugging.

    Args:
        player_id_string (str):
            The identifier of the bot whose turn produced the unparseable output
            (e.g. 'a', 'b'). Used in the log file body for traceability.
        raw_text_output_string (str):
            The exact raw text returned by the LLM API that the extractor
            failed to parse into an action dictionary.
        prompt_text_string (str):
            The full prompt that was sent to the LLM. Logged so that the
            failure can be reproduced.
        game_timestamp_string (str):
            The timestamp identifier of the current game session. Logged for
            cross-referencing with the per-turn logs.
        round_number_int (int):
            The current round number. Logged for cross-referencing.
        extraction_failure_directory_path (str):
            Directory in which to write the failure log file. Defaults to
            'logs/extraction_failures'. Created if it does not exist.

    Returns:
        str | None:
            The absolute path of the written log file on success, or None if
            writing the file failed (in which case a traceback is printed but
            no exception is raised, so the caller can continue safely).
    """
    # Build a filesystem-safe timestamp for the filename. We include
    # microseconds to avoid collisions when two failures happen in the same
    # second (which is plausible in fast multi-bot games).
    failure_timestamp_string = datetime.now().strftime("%Y%m%d_%H%M%S_%f")

    # Construct the full output path. Note: the user-specified naming pattern
    # is 'action_extraction_failure_{timestamp}'. We append '.txt' to make
    # the file type explicit to operating systems and editors.
    failure_log_file_name_string = (
        f"action_extraction_failure_{failure_timestamp_string}.txt"
    )
    failure_log_full_path_string = os.path.join(
        extraction_failure_directory_path, failure_log_file_name_string
    )

    try:
        # Ensure the target directory exists; create parents as needed.
        os.makedirs(extraction_failure_directory_path, exist_ok=True)

        # Write a structured, human-readable report. Sections are clearly
        # delimited so that grep/visual inspection is straightforward.
        with open(failure_log_full_path_string, "w", encoding="utf-8") as failure_log_file_handle:
            failure_log_file_handle.write("=== ACTION EXTRACTION FAILURE REPORT ===\n")
            failure_log_file_handle.write(f"failure_timestamp_string : {failure_timestamp_string}\n")
            failure_log_file_handle.write(f"player_id_string         : {player_id_string}\n")
            failure_log_file_handle.write(f"game_timestamp_string    : {game_timestamp_string}\n")
            failure_log_file_handle.write(f"round_number_int         : {round_number_int}\n")
            failure_log_file_handle.write("\n--- RAW LLM OUTPUT (could not be parsed into action dict) ---\n")
            failure_log_file_handle.write(raw_text_output_string if raw_text_output_string is not None else "<None>")
            failure_log_file_handle.write("\n\n--- PROMPT SENT TO LLM ---\n")
            failure_log_file_handle.write(prompt_text_string if prompt_text_string is not None else "<None>")
            failure_log_file_handle.write("\n=== END OF REPORT ===\n")

        return failure_log_full_path_string

    except Exception as failure_log_write_error:
        # We do NOT re-raise: failing to log a failure must not crash the game.
        # But we DO announce the problem clearly per project rules.
        print(
            f"[Logging Error] Could not write action-extraction failure log "
            f"to '{failure_log_full_path_string}' for player '{player_id_string}': "
            f"{failure_log_write_error}"
        )
        traceback.print_exc()
        return None

import random
import time

def pause(from_seconds, to_seconds):
    """Pause execution for a random duration between from_seconds and to_seconds."""
    pause_time = random.uniform(from_seconds, to_seconds)
    time.sleep(pause_time)

def execute_single_bot_turn_pipeline(
    use_this_api_service: str,  # mistral, anthropic, google
    use_this_model: str,
    player_id_string: str,
    prompt_text_string: str,
    game_timestamp_string: str = "default_game",
    round_number_int: int = 0
) -> tuple:
    """
    The orchestrator for a single bot's turn.
    It ties together the API call, the data extraction, and the logging mechanisms.

    Args:
        player_id_string (str): The identifier of the bot (e.g., 'a', 'b').
        prompt_text_string (str): The prompt string prepared for the LLM.
        game_timestamp_string (str): The timestamp of the current game session.
        round_number_int (int): The current round number.

    Returns:
        tuple: A tuple containing:
            - action_dict (dict): The safely extracted action dictionary.
            - vote_start_round_boolean (bool): True if the bot wants to execute the round.
            - memo_str (str): The safely extracted memo string.

    Failure logging:
        If the LLM returns text but `extract_last_player_action_dict_from_raw_text`
        cannot extract a valid action dict, this function will:
          1. Print a clearly-labeled warning to stdout.
          2. Persist the failing raw output and prompt to
             `logs/extraction_failures/action_extraction_failure_{timestamp}.txt`
             via `write_action_extraction_failure_log_file`.
          3. Substitute the safe `fallback_action_dict` so the game can continue.
        Extraction failures are NEVER silently swallowed.
    """
    # 1. Establish safe default fallback values in case of complete pipeline failure
    fallback_action_dict = {
        "player_id": player_id_string,
        "action_type": "skip_turn",
        "throw_from_coord": None, "throw_to_coord": None,
        "move_from_coord": None, "move_to_coord": None
    }
    vote_start_round_boolean = False
    memo_string = ""

    try:

        # pause to break traffic to api
        pause(from_seconds=2, to_seconds=5)

        if use_this_api_service == 'mistral':

            # 2v1 Raw API Interaction
            raw_text_output_string = simple_ask_mistral_cloud(prompt_text_string, use_this_model)

        elif use_this_api_service == 'anthropic':

            if not isinstance(ANTHROPIC_APIKEY, str) or len(ANTHROPIC_APIKEY) == 0:
                raise ValueError(
                    "key missing or empty"
                )

            raw_text_output_string = generate_text_from_anthropic_api(
                user_prompt_text=prompt_text_string,
                anthropic_api_key=ANTHROPIC_APIKEY,
                anthropic_model_name=use_this_model,
                maximum_output_tokens=9000,
                sampling_temperature=0.9,
                optional_system_instruction_text="You are a skillful team-player on an RPG dungeon crawl.",
            )


        elif use_this_api_service == 'google':

            # 2v2 Raw API Interaction
            if not isinstance(GAS_APIKEY, str) or len(GAS_APIKEY) == 0:
                raise ValueError(
                    "key missing or empty"
                )

            raw_text_output_string = generate_single_text_response_from_google_ai_studio(
                user_prompt_text=prompt_text_string,
                google_ai_studio_api_key=GAS_APIKEY,
                gemini_model_name=use_this_model,
                maximum_output_tokens=9000,
                sampling_temperature=0.2,
            )

        else:
            raise ValueError(f"Unsupported API service: {use_this_api_service}")

        if not raw_text_output_string:
            # Empty/None response: not an extraction failure per se (there was
            # nothing to extract from). Warn loudly and fall back.
            print(
                f"[Pipeline Warning] Received empty response from API for player "
                f"{player_id_string}. Using defaults."
            )
            return fallback_action_dict, vote_start_round_boolean, memo_string

        # # inspection
        # print(f"raw_text_output_string -> {raw_text_output_string}")

        # 3. Extraction Logic
        # Attempt to parse a structured action dict out of the raw LLM text.
        extracted_action_dict_or_none = extract_last_player_action_dict_from_raw_text(
            raw_text_output_string
        )

        if extracted_action_dict_or_none:
            # Happy path: extractor succeeded, use the parsed action dict.
            final_action_dict = extracted_action_dict_or_none
        else:
            # FAILURE PATH: extractor returned None/empty. This used to be silently
            # swallowed. We now (a) announce the failure on stdout and (b) persist
            # the failing raw output to disk for offline analysis, before falling
            # back to the safe default action dict.
            print(
                f"[Extraction Failure] Could not extract an action dict from the "
                f"LLM output for player '{player_id_string}' (round {round_number_int}, "
                f"game '{game_timestamp_string}'). Falling back to skip_turn. "
                f"Raw output is being written to logs/extraction_failures/."
            )

            written_failure_log_path_or_none = write_action_extraction_failure_log_file(
                player_id_string=player_id_string,
                raw_text_output_string=raw_text_output_string,
                prompt_text_string=prompt_text_string,
                game_timestamp_string=game_timestamp_string,
                round_number_int=round_number_int,
            )

            if written_failure_log_path_or_none is not None:
                print(f"[Extraction Failure] Failure log written to: {written_failure_log_path_or_none}")
            else:
                print("[Extraction Failure] WARNING: failure log could NOT be written; see traceback above.")

            final_action_dict = fallback_action_dict

        # Force player ID to match reality, preventing identity spoofing
        # by the LLM (it cannot impersonate a different player).
        final_action_dict['player_id'] = player_id_string

        # Planning memo = raw output
        final_memo_string = str(raw_text_output_string)

        # Start-round vote signal detection.
        final_vote_start_round_boolean = detect_start_round_true_signal_in_raw_text(
            raw_text_output_string
        )

        # 4. Logging Mechanism (per-turn structured log; separate from failure log)
        log_player_turn_output(
            player_id_string=player_id_string,
            raw_output_string=raw_text_output_string,
            raw_input_prompt=prompt_text_string,
            extracted_action_dict=final_action_dict,
            extracted_memo_string=final_memo_string,
            extracted_start_round_boolean=final_vote_start_round_boolean,
            game_timestamp_string=game_timestamp_string,
            round_number_int=round_number_int
        )

        # 5. Return Clean Data
        return final_action_dict, final_vote_start_round_boolean, final_memo_string

    except Exception as pipeline_orchestration_error:
        print(
            f"[Critical Error] The single bot turn pipeline failed for "
            f"{player_id_string}: {pipeline_orchestration_error}"
        )
        traceback.print_exc()
        return fallback_action_dict, vote_start_round_boolean, memo_string

