def create_zip_archive_from_directory(source_directory_path: str, output_zip_file_path: str) -> bool:
    """
    Compresses a specified directory into a zip archive.

    This function takes a source directory path and an output zip file path,
    and creates a zip archive containing the contents of the source directory.
    It uses the built-in shutil library for safe and cross-platform archiving.

    Args:
        source_directory_path (str): The absolute or relative path to the directory to be zipped.
        output_zip_file_path (str): The absolute or relative path (including filename without .zip extension)
                                    where the archive will be saved.

    Returns:
        bool: True if the archiving process was successful, False otherwise.
    """
    try:
        # Validate that the source directory actually exists before attempting to zip it
        if not os.path.isdir(source_directory_path):
            print(f"[Error] The source directory does not exist or is not a directory: '{source_directory_path}'")
            return False

        # Ensure the parent directory of the output path exists
        output_parent_directory = os.path.dirname(output_zip_file_path)
        if output_parent_directory and not os.path.exists(output_parent_directory):
            os.makedirs(output_parent_directory, exist_ok=True)

        print(f"Attempting to compress directory: '{source_directory_path}'")
        print(f"Destination archive: '{output_zip_file_path}.zip'")

        # Create the zip archive
        # shutil.make_archive appends the '.zip' extension automatically
        shutil.make_archive(
            base_name=output_zip_file_path,
            format='zip',
            root_dir=source_directory_path
        )

        print("[Success] Directory successfully compressed.")
        return True

    except Exception as compression_error:
        # Production-safe error catching with full traceback reporting
        print(f"[Critical Error] Failed to compress the directory: {compression_error}")
        traceback.print_exc()
        return False


zip_timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

create_zip_archive_from_directory(
    source_directory_path="logs",
    output_zip_file_path=f"zipped_{zip_timestamp}",
    )

