def _extract_round_integer_suffix(round_subdirectory_name: str) -> int:
    """
    Extract the integer N from a round subdirectory name like 'round_<N>'.

    Parameters
    ----------
    round_subdirectory_name : str
        The basename of a round subdirectory, e.g. "round_3".

    Returns
    -------
    int
        The integer suffix N from "round_<N>".

    Raises
    ------
    ValueError
        If the input does not match the expected pattern.
    """
    # Strict regex match: must be "round_" followed by one or more digits, no extras.
    pattern_match_object = re.match(r"^round_(\d+)$", round_subdirectory_name)
    if pattern_match_object is None:
        raise ValueError(
            f"Subdirectory name does not match expected pattern 'round_<integer>': "
            f"{round_subdirectory_name!r}"
        )
    return int(pattern_match_object.group(1))


def _find_sorted_round_subdirectory_paths(game_log_dir_path: str) -> list[Path]:
    """
    Find all 'round_<N>' subdirectories inside the game log directory and
    return them sorted in natural-integer order (round_2 before round_10).

    Parameters
    ----------
    game_log_dir_path : str
        Absolute or relative path to the game log directory containing round_* subdirs.

    Returns
    -------
    list[Path]
        Sorted list of pathlib.Path objects, one per matching round subdirectory.

    Raises
    ------
    FileNotFoundError
        If game_log_dir_path does not exist or is not a directory.
    RuntimeError
        If zero round_<N> subdirectories are found.
    """
    game_log_dir_path_object = Path(game_log_dir_path)
    if not game_log_dir_path_object.is_dir():
        raise FileNotFoundError(
            f"Game log directory does not exist or is not a directory: "
            f"{game_log_dir_path_object!s}"
        )

    # Collect immediate child directories whose names match 'round_<N>'.
    matched_round_subdirectory_paths: list[Path] = []
    for child_path_object in game_log_dir_path_object.iterdir():
        if child_path_object.is_dir() and re.match(r"^round_\d+$", child_path_object.name):
            matched_round_subdirectory_paths.append(child_path_object)

    if len(matched_round_subdirectory_paths) == 0:
        raise RuntimeError(
            f"No 'round_<N>' subdirectories found in: {game_log_dir_path_object!s}"
        )

    # Sort by extracted integer suffix (natural order).
    matched_round_subdirectory_paths.sort(
        key=lambda single_round_path: _extract_round_integer_suffix(single_round_path.name)
    )
    return matched_round_subdirectory_paths


def _find_sorted_player_json_file_paths(round_subdirectory_path: Path) -> list[Path]:
    """
    Locate and sort all player JSON log files in a round subdirectory.

    Sorting is by filename (which embeds a chronological timestamp), giving
    chronological player order.

    Parameters
    ----------
    round_subdirectory_path : Path
        Path to a single round subdirectory.

    Returns
    -------
    list[Path]
        Chronologically-sorted list of player JSON file paths. May be empty
        (caller decides whether that is an error).
    """
    player_json_file_glob_pattern: str = "playerlog_*.json"
    matched_player_json_file_path_strings: list[str] = sorted(
        glob.glob(str(round_subdirectory_path / player_json_file_glob_pattern))
    )
    return [Path(p) for p in matched_player_json_file_path_strings]


def _find_single_gm_text_file_path(round_subdirectory_path: Path) -> Path:
    """
    Locate the most recent GM '.txt' file in a round subdirectory.
    (Updated to handle multiple files per round by returning the latest chronological file).

    Parameters
    ----------
    round_subdirectory_path : Path
        Path to a single round subdirectory.

    Returns
    -------
    Path
        Path to the most recent GM text file.

    Raises
    ------
    RuntimeError
        If zero matching files are found.
    """
    try:
        # Glob for the standard GM filename pattern.
        gm_text_file_glob_pattern: str = "gm_generic_round_dungeon_so_far_*.txt"
        matched_gm_file_path_strings: list[str] = sorted(
            glob.glob(str(round_subdirectory_path / gm_text_file_glob_pattern))
        )

        if len(matched_gm_file_path_strings) == 0:
            raise RuntimeError(
                f"No GM file matching {gm_text_file_glob_pattern!r} found in "
                f"round directory: {round_subdirectory_path!s}"
            )

        # Return the most recent one (last in the chronologically sorted list)
        return Path(matched_gm_file_path_strings[-1])

    except Exception as file_discovery_error:
        print(f"[Critical Error] Failed to discover GM text file in {round_subdirectory_path}: {file_discovery_error}")
        traceback.print_exc()
        raise


def _extract_timestamp_from_gm_filename(gm_text_file_path: Path) -> str:
    """
    Extract the timestamp portion from a GM filename like
    'gm_generic_round_dungeon_so_far_<timestamp>.txt'.

    Parameters
    ----------
    gm_text_file_path : Path
        Path to the GM text file.

    Returns
    -------
    str
        The extracted timestamp string, or an empty string if it cannot be parsed.
    """
    # Pattern: capture everything between the prefix and '.txt'.
    timestamp_match_object = re.match(
        r"^gm_generic_round_dungeon_so_far_(.+)\.txt$",
        gm_text_file_path.name,
    )
    if timestamp_match_object is None:
        return ""
    return timestamp_match_object.group(1)


def _extract_timestamp_from_player_filename(player_json_file_path: Path) -> str:
    """
    Extract the timestamp portion from a player filename like
    'playerlog_<timestamp>_<id>.json'.

    Parameters
    ----------
    player_json_file_path : Path
        Path to the player JSON file.

    Returns
    -------
    str
        The extracted timestamp string, or an empty string if it cannot be parsed.
    """
    timestamp_match_object = re.match(
        r"^playerlog_(\d+_\d+)_[^.]+\.json$",
        player_json_file_path.name,
    )
    if timestamp_match_object is None:
        return ""
    return timestamp_match_object.group(1)


def _read_text_file_contents(file_path: Path) -> str:
    """
    Read a UTF-8 text file and return its full contents as a string.

    Parameters
    ----------
    file_path : Path
        Path to the text file.

    Returns
    -------
    str
        Full file contents.

    Raises
    ------
    RuntimeError
        On any I/O or decoding failure, with the original traceback included.
    """
    try:
        with open(file_path, mode="r", encoding="utf-8") as text_file_handle:
            return text_file_handle.read()
    except Exception as caught_exception:
        raise RuntimeError(
            f"Failed to read text file: {file_path!s}\n"
            f"Original error: {caught_exception!r}\n"
            f"Traceback:\n{traceback.format_exc()}"
        ) from caught_exception


def _read_and_parse_player_json_file(player_json_file_path: Path) -> dict:
    """
    Read a player JSON log file and parse it into a Python dict.

    Parameters
    ----------
    player_json_file_path : Path
        Path to the player JSON file.

    Returns
    -------
    dict
        Parsed JSON object as a Python dict.

    Raises
    ------
    RuntimeError
        On any I/O or JSON parsing failure, with the original traceback included.
    """
    try:
        with open(player_json_file_path, mode="r", encoding="utf-8") as json_file_handle:
            parsed_player_json_object = json.load(json_file_handle)
    except Exception as caught_exception:
        raise RuntimeError(
            f"Failed to read or parse player JSON file: {player_json_file_path!s}\n"
            f"Original error: {caught_exception!r}\n"
            f"Traceback:\n{traceback.format_exc()}"
        ) from caught_exception

    if not isinstance(parsed_player_json_object, dict):
        raise RuntimeError(
            f"Player JSON file did not contain a top-level JSON object/dict: "
            f"{player_json_file_path!s} (got type: {type(parsed_player_json_object).__name__})"
        )
    return parsed_player_json_object


def _redact_and_split_player_dict(
    parsed_player_json_dict: dict,
) -> tuple[dict, str | None]:
    """
    Produce a display-ready copy of a parsed player JSON dict by:
      (a) Removing the 'raw_input_prompt' field (top-level and, defensively,
          also from 'extracted_data' if nested there) — completely omitted
          from the report.
      (b) Removing 'extracted_data.note_share_memo' from the dict so it can
          be rendered separately as readable prose (with real newlines)
          rather than as a JSON-escaped single-line string. A short
          placeholder string is inserted in its place inside the dict so the
          reader can see where in the structure the memo originated.

    The original input dict is NOT mutated; a deep copy is made internally.

    Generalisation note (v3)
    ------------------------
    The set of fields removed under (a) is now driven by the module-level
    constant PLAYER_JSON_FIELDS_TO_REDACT_FROM_DISPLAY (a tuple of field
    name strings). Each listed field is popped at the top level of the
    player dict AND from 'extracted_data' if it appears there. This
    generalises the previous behaviour (which only handled
    'raw_input_prompt') so that additional noisy fields (e.g.
    'raw_llm_output') can be redacted by editing the constant without
    modifying this function.

    Parameters
    ----------
    parsed_player_json_dict : dict
        The parsed JSON object from a single playerlog_*.json file. Expected
        (but not required) to contain an 'extracted_data' sub-dict and an
        optional 'raw_input_prompt' field.

    Returns
    -------
    tuple[dict, str | None]
        Two-element tuple:
          - redacted_player_dict_for_json_display : dict
                The deep-copied, redacted dict, suitable for json.dumps()
                pretty-printing in the report.
          - extracted_note_share_memo_text_or_none : str | None
                The original memo text (verbatim, including real '\\n'
                characters) if 'extracted_data.note_share_memo' was present
                AND was a string; otherwise None.

    Raises
    ------
    TypeError
        If parsed_player_json_dict is not a dict.

    Notes
    -----
    - If 'note_share_memo' is present but is not a string (unexpected schema),
      it is left untouched in the dict and None is returned for the memo
      text. This avoids silent data loss while still producing output.
    - This function is purely structural — no regex/string replacement on
      dumped JSON — so other fields containing legitimate '\\n' escapes are
      not affected.
    """
    # Defensive type check on input.
    if not isinstance(parsed_player_json_dict, dict):
        raise TypeError(
            f"_redact_and_split_player_dict expected a dict, got "
            f"{type(parsed_player_json_dict).__name__}"
        )

    # Deep-copy to avoid mutating the caller's data.
    redacted_player_dict_for_json_display: dict = copy.deepcopy(parsed_player_json_dict)

    # (a) Remove every field listed in PLAYER_JSON_FIELDS_TO_REDACT_FROM_DISPLAY
    # from the top level of the dict. .pop(..., None) is a no-op if absent.
    for single_field_name_to_redact in PLAYER_JSON_FIELDS_TO_REDACT_FROM_DISPLAY:
        redacted_player_dict_for_json_display.pop(single_field_name_to_redact, None)

    # Initialise the memo output as None; will be populated if found and valid.
    extracted_note_share_memo_text_or_none: str | None = None

    # Inspect 'extracted_data' if it exists and is a dict.
    extracted_data_sub_dict = redacted_player_dict_for_json_display.get("extracted_data")
    if isinstance(extracted_data_sub_dict, dict):
        # Defensive: also drop every redacted field name if nested here.
        for single_field_name_to_redact in PLAYER_JSON_FIELDS_TO_REDACT_FROM_DISPLAY:
            extracted_data_sub_dict.pop(single_field_name_to_redact, None)

        # (b) Pull out 'note_share_memo' for separate rendering.
        if "note_share_memo" in extracted_data_sub_dict:
            candidate_memo_value = extracted_data_sub_dict["note_share_memo"]
            if isinstance(candidate_memo_value, str):
                # Remove from JSON dict and stash for separate rendering.
                extracted_note_share_memo_text_or_none = candidate_memo_value
                extracted_data_sub_dict["note_share_memo"] = (
                    "<rendered separately below as 'Shared Memo'>"
                )
            # If not a string, leave as-is (no silent data loss); memo stays None.

    return redacted_player_dict_for_json_display, extracted_note_share_memo_text_or_none


def _find_single_player_pov_map_file_path(round_subdirectory_path: Path, player_id_string: str) -> Path | None:
    """
    Locate the specific GM POV map file for a player in a round subdirectory.

    Parameters
    ----------
    round_subdirectory_path : Path
        Path to a single round subdirectory.
    player_id_string : str
        The identifier of the player (e.g., 'a', 'b').

    Returns
    -------
    Path | None
        Path to the player's POV map text file, or None if not found.
    """
    pov_map_file_glob_pattern = f"gm_{player_id_string}_pov_map_*.txt"
    matched_pov_file_path_strings = sorted(
        glob.glob(str(round_subdirectory_path / pov_map_file_glob_pattern))
    )

    if len(matched_pov_file_path_strings) == 0:
        return None

    # Return the first match (there should typically only be one per player per round)
    return Path(matched_pov_file_path_strings[0])


def _find_all_player_pov_map_file_paths(
    round_subdirectory_path: Path,
    player_id_string: str,
) -> list[Path]:
    """
    Locate all GM POV map files for a given player inside a single round
    subdirectory, sorted chronologically by filename.

    POV map filenames are expected to follow the pattern:
        gm_<player_id>_pov_map_<timestamp>.txt

    Parameters
    ----------
    round_subdirectory_path : Path
        Path to a single round subdirectory (e.g. .../round_3/).
    player_id_string : str
        The identifier of the player (e.g., 'a', 'b').

    Returns
    -------
    list[Path]
        A list of Path objects pointing at the player's POV map text files
        in this round, sorted chronologically (lexicographic sort on the
        filename, which is correct because timestamps are zero-padded).
        Returns an empty list if no POV maps exist for this player.

    Raises
    ------
    RuntimeError
        If POV-map file discovery itself fails (e.g. the directory cannot
        be read). "No matching files" is NOT an error and returns [].
    """
    try:
        # Glob pattern matches every POV-map snapshot for this player in this round.
        pov_map_file_glob_pattern_string = f"gm_{player_id_string}_pov_map_*.txt"
        matched_pov_file_path_strings_list = sorted(
            glob.glob(str(round_subdirectory_path / pov_map_file_glob_pattern_string))
        )
        return [Path(path_string) for path_string in matched_pov_file_path_strings_list]

    except Exception as pov_file_discovery_error:
        # Discovery failure is distinct from "no files found"; surface it
        # rather than hiding it behind an empty list.
        traceback.print_exc()
        raise RuntimeError(
            f"Failed to discover POV map files for player "
            f"{player_id_string!r} in {round_subdirectory_path}: "
            f"{pov_file_discovery_error}"
        ) from pov_file_discovery_error


def _build_html_for_single_round(
    round_integer_index: int,
    round_subdirectory_path: Path,
) -> str:
    """
    Build the HTML fragment for a single round of play.

    The fragment contains, in order:
      1. A round-level anchor and <h2> header.
      2. The GM narrative for the round (timestamped), rendered from the
         single GM text file located in the round subdirectory.
      3. For each player, in chronological order of their JSON log:
           a. A player heading with timestamp.
           b. Every POV map snapshot the GM produced for that player during
              this round, in chronological order. If there is more than one,
              each is labelled "(Iteration N)".
           c. The player's JSON log, with 'raw_input_prompt' redacted and
              'note_share_memo' split out, pretty-printed with indent=4.
           d. If present, the player's shared memo as readable prose
              (preserving real newlines).
      4. A trailing <hr> separator.

    Parameters
    ----------
    round_integer_index : int
        The integer N parsed from the directory name 'round_<N>'.
    round_subdirectory_path : Path
        Path to the round subdirectory containing the GM file, the player
        JSON files, and any per-player POV map files for this round.

    Returns
    -------
    str
        HTML fragment for this round, including its anchor element. Safe
        to concatenate directly into a larger HTML document; all
        externally-sourced text is passed through html.escape().

    Raises
    ------
    RuntimeError
        If GM file discovery/read fails, or if any player JSON file cannot
        be discovered, read, or parsed. POV-map *read* failures are
        downgraded to warnings printed to stdout and do not interrupt
        rendering of the rest of the round (one corrupt POV snapshot
        should not destroy the whole report).
    """
    try:
        html_fragment_parts_list: list[str] = []

        # ---- Round anchor + header --------------------------------------
        round_anchor_identifier_string: str = f"round_{round_integer_index}"
        html_fragment_parts_list.append(
            f'<h2 id="{round_anchor_identifier_string}">'
            f'Round {round_integer_index}</h2>\n'
        )

        # ---- GM section -------------------------------------------------
        # There is exactly one GM text file per round; locate, timestamp, read.
        gm_text_file_path_object = _find_single_gm_text_file_path(round_subdirectory_path)
        gm_timestamp_string = _extract_timestamp_from_gm_filename(gm_text_file_path_object)
        gm_text_contents_string = _read_text_file_contents(gm_text_file_path_object)

        gm_timestamp_label_html_string: str = (
            f'<span class="timestamp-label">[{html.escape(gm_timestamp_string)}]</span>'
            if gm_timestamp_string
            else ""
        )
        html_fragment_parts_list.append(
            f'<h3 class="gm-heading">The GM says:{gm_timestamp_label_html_string}</h3>\n'
        )
        html_fragment_parts_list.append(
            f"<pre>{html.escape(gm_text_contents_string)}</pre>\n"
        )

        # ---- Player sections in chronological order ---------------------
        player_json_file_paths_list = _find_sorted_player_json_file_paths(round_subdirectory_path)
        for single_player_json_file_path_object in player_json_file_paths_list:
            parsed_player_json_dictionary = _read_and_parse_player_json_file(
                single_player_json_file_path_object
            )

            # Prefer the player_id from inside the JSON; fall back to the
            # filename stem so a malformed/missing player_id still renders.
            player_id_string_from_json = parsed_player_json_dictionary.get("player_id")
            if (
                not isinstance(player_id_string_from_json, str)
                or len(player_id_string_from_json) == 0
            ):
                player_id_string_from_json = single_player_json_file_path_object.stem

            player_timestamp_string = _extract_timestamp_from_player_filename(
                single_player_json_file_path_object
            )
            player_timestamp_label_html_string: str = (
                f'<span class="timestamp-label">[{html.escape(player_timestamp_string)}]</span>'
                if player_timestamp_string
                else ""
            )

            # Player heading.
            html_fragment_parts_list.append(
                f"<h3>Player {html.escape(player_id_string_from_json)}:"
                f"{player_timestamp_label_html_string}</h3>\n"
            )

            # ---- All POV map snapshots for this player in this round ----
            # Render each chronological POV map. If multiple exist, label
            # them "(Iteration N)". A read failure on one map is logged
            # and skipped; it does NOT abort the round.
            player_pov_map_paths_list = _find_all_player_pov_map_file_paths(
                round_subdirectory_path,
                player_id_string_from_json,
            )
            pov_map_count_integer = len(player_pov_map_paths_list)
            for map_index_integer, player_pov_map_path_object in enumerate(player_pov_map_paths_list):
                try:
                    pov_map_contents_string = _read_text_file_contents(player_pov_map_path_object)
                    pov_iteration_label_string = (
                        f" (Iteration {map_index_integer + 1})"
                        if pov_map_count_integer > 1
                        else ""
                    )
                    html_fragment_parts_list.append(
                        f'<h4 class="memo-heading">'
                        f'Player {html.escape(player_id_string_from_json)} '
                        f'— POV Map{pov_iteration_label_string}:</h4>\n'
                    )
                    html_fragment_parts_list.append(
                        f"<pre>{html.escape(pov_map_contents_string)}</pre>\n"
                    )
                except Exception as pov_map_read_error:
                    # Non-fatal: log full traceback so the warning is actionable.
                    print(
                        f"[Warning] Could not read POV map for player "
                        f"{player_id_string_from_json!r} at "
                        f"{player_pov_map_path_object}: {pov_map_read_error}"
                    )
                    traceback.print_exc()

            # ---- Redact and split the player JSON for display -----------
            # Removes 'raw_input_prompt' and pulls 'note_share_memo' out so
            # the memo can be rendered as prose with real newlines instead
            # of as escaped \n inside the JSON block.
            (
                redacted_player_dictionary_for_json_display,
                extracted_note_share_memo_text_or_none,
            ) = _redact_and_split_player_dict(parsed_player_json_dictionary)

            player_json_pretty_printed_string = json.dumps(
                redacted_player_dictionary_for_json_display, indent=4
            )
            html_fragment_parts_list.append(
                f"<pre>{html.escape(player_json_pretty_printed_string)}</pre>\n"
            )

            # ---- Shared memo as readable prose, if present --------------
            if extracted_note_share_memo_text_or_none is not None:
                html_fragment_parts_list.append(
                    f'<h4 class="memo-heading">'
                    f'Player {html.escape(player_id_string_from_json)} '
                    f'— Shared Memo:</h4>\n'
                )
                html_fragment_parts_list.append(
                    f"<pre>{html.escape(extracted_note_share_memo_text_or_none)}</pre>\n"
                )

        html_fragment_parts_list.append("<hr>\n")
        return "".join(html_fragment_parts_list)

    except Exception as build_html_error:
        # Print full traceback before re-raising so the failing round is
        # clearly identified in the operator's log even if the caller
        # catches the RuntimeError.
        print(
            f"[Critical Error] Failed to build HTML for round "
            f"{round_integer_index} at {round_subdirectory_path}: "
            f"{build_html_error}"
        )
        traceback.print_exc()
        raise RuntimeError(
            f"HTML build failed for round {round_integer_index} "
            f"at {round_subdirectory_path}"
        ) from build_html_error

def _build_table_of_contents_html(round_integer_indices_list: list[int]) -> str:
    """
    Build a small table of contents linking to each round anchor.

    Parameters
    ----------
    round_integer_indices_list : list[int]
        Sorted list of round integer indices.

    Returns
    -------
    str
        HTML fragment for the table of contents.
    """
    toc_html_parts_list: list[str] = ['<div class="toc">\n', "<h2>Table of Contents</h2>\n", "<ul>\n"]
    for round_integer_index in round_integer_indices_list:
        toc_html_parts_list.append(
            f'<li><a href="#round_{round_integer_index}">Round {round_integer_index}</a></li>\n'
        )
    toc_html_parts_list.append("</ul>\n</div>\n")
    return "".join(toc_html_parts_list)


