def game_script_maker(
    game_log_dir_path: str,
    output_html_path: str,
) -> str:
    """
    Convert a structured RPG game log directory tree into a single self-contained
    dark-mode HTML "screenplay" report.

    The report contains, in order:
      1. A title line naming the game directory.
      2. A table of contents linking to each round anchor.
      3. For each round (sorted by integer suffix, natural order):
           - A round header ("Round N") with anchor id="round_N".
           - The GM's blurb (entire .txt file contents) under "The GM says:".
           - Each player's JSON log (pretty-printed, indent=4) under
             "Player <player_id> says:", in chronological filename order.
      Filenames' timestamps are displayed in small grey text next to each
      GM/Player heading.

    Parameters
    ----------
    game_log_dir_path : str
        Path to a single game directory, e.g. "/logs/game_20260426_123928".
        Must contain one or more 'round_<N>' subdirectories.
    output_html_path : str
        Path where the generated HTML report will be written. Parent directories
        will be created if they do not exist.

    Returns
    -------
    str
        Absolute path of the written HTML file.

    Raises
    ------
    FileNotFoundError
        If game_log_dir_path does not exist or is not a directory.
    RuntimeError
        For any file discovery, reading, parsing, or writing failure. The
        message includes the original traceback for diagnostics.

    Notes
    -----
    - No JavaScript is used; the report is a single static HTML file.
    - JSON content is left as-standard (escaped \\n preserved) per spec.
    - Player order within each round follows filename chronology (which matches
      a, b, c, d, e order when timestamps were sequential).
    """
    # ---- Validate inputs and gather round directories. ---------------------
    sorted_round_subdirectory_paths_list = _find_sorted_round_subdirectory_paths(
        game_log_dir_path
    )
    sorted_round_integer_indices_list: list[int] = [
        _extract_round_integer_suffix(single_round_path.name)
        for single_round_path in sorted_round_subdirectory_paths_list
    ]

    # ---- Build per-round HTML fragments. -----------------------------------
    accumulated_round_html_fragments_list: list[str] = []
    for single_round_subdirectory_path, single_round_integer_index in zip(
        sorted_round_subdirectory_paths_list,
        sorted_round_integer_indices_list,
    ):
        try:
            round_html_fragment_string = _build_html_for_single_round(
                round_integer_index=single_round_integer_index,
                round_subdirectory_path=single_round_subdirectory_path,
            )
        except Exception as caught_exception:
            raise RuntimeError(
                f"Failed building HTML for round {single_round_integer_index} "
                f"at {single_round_subdirectory_path!s}\n"
                f"Original error: {caught_exception!r}\n"
                f"Traceback:\n{traceback.format_exc()}"
            ) from caught_exception
        accumulated_round_html_fragments_list.append(round_html_fragment_string)

    # ---- Assemble the full HTML document. ----------------------------------
    game_directory_basename_string: str = os.path.basename(
        os.path.normpath(game_log_dir_path)
    )
    table_of_contents_html_string = _build_table_of_contents_html(
        sorted_round_integer_indices_list
    )

    full_html_document_string: str = (
        "<!DOCTYPE html>\n"
        '<html lang="en">\n'
        "<head>\n"
        '<meta charset="UTF-8">\n'
        f"<title>Game Screenplay: {html.escape(game_directory_basename_string)}</title>\n"
        f"{DARK_MODE_CSS_STYLE_BLOCK}\n"
        "</head>\n"
        "<body>\n"
        f"<h1>Game: {html.escape(game_directory_basename_string)}</h1>\n"
        f"{table_of_contents_html_string}"
        "<hr>\n"
        f"{''.join(accumulated_round_html_fragments_list)}"
        "</body>\n"
        "</html>\n"
    )

    # ---- Write to disk. ----------------------------------------------------
    output_html_path_object = Path(output_html_path)
    try:
        # Ensure parent directory exists.
        output_html_path_object.parent.mkdir(parents=True, exist_ok=True)
        with open(output_html_path_object, mode="w", encoding="utf-8") as output_file_handle:
            output_file_handle.write(full_html_document_string)
    except Exception as caught_exception:
        raise RuntimeError(
            f"Failed to write HTML report to: {output_html_path_object!s}\n"
            f"Original error: {caught_exception!r}\n"
            f"Traceback:\n{traceback.format_exc()}"
        ) from caught_exception

    return str(output_html_path_object.resolve())


