"""## Basic Dungeon Floor Hallway Mapper

Possible Rules:
1. each level of dungeon you need N treasure-keys to go down the stairs to the next level

2. ...
a program to have the party move through dungeon
and only be able to see straight for N spaces where + where they hvae been.

possibly


S is end-stairs

P is party

e.g. for each dungeon floor, the seed can be the number of the level (by default)

and the random seed for the room can be the level and the coordinates for that room on that floor



"""

# Terse Version
"""
dungeon_halls_map.py — v2
- Thick walls (parameterized) so doors fit IN walls.
- Door rule: wall cell with exactly one corridor neighbor; opposite side is wall.
"""
import random
from collections import deque


def dungeon_halls_map(
    width=20,
    height=20,
    random_seed=None,
    wall_thickness=2,      # NEW: walls are this many cells thick
    loopiness=0.12,        # 0 = perfect maze; >0 adds loops
    door_density=0.30,     # fraction of eligible wall-cells that become doors
    min_door_spacing=4,    # Manhattan distance between doors
    special_room_count=3,  # doors upgraded to 'O'
    algorithm='dfs',       # 'dfs' or 'prim'
    corridor_char='.',
    wall_char='#',
    door_char='O',
    special_char='X',      # maybe traps, whatever GM/DM wants
    start_char='P',        # Party You Are Here
    end_char='S',          # Stairs (down)
):
    rng = random.Random(random_seed)
    WT = max(1, wall_thickness)
    CT = 1
    P  = WT + CT                       # cell pitch
    cw = max(2, (width  - WT) // P)
    ch = max(2, (height - WT) // P)
    W  = cw * P + WT
    H  = ch * P + WT

    g = [[wall_char] * W for _ in range(H)]
    visited = [[False] * cw for _ in range(ch)]

    def cpos(cr, cc):                  # cell -> grid corridor cell
        return WT + cr * P, WT + cc * P

    def carve_cell(cr, cc):
        r, c = cpos(cr, cc); g[r][c] = corridor_char

    def carve_between(cr, cc, nr, nc): # carve corridor + wall-gap between two cells
        r1, c1 = cpos(cr, cc)
        r2, c2 = cpos(nr, nc)
        if r1 == r2:
            for c in range(min(c1, c2), max(c1, c2) + 1):
                g[r1][c] = corridor_char
        else:
            for r in range(min(r1, r2), max(r1, r2) + 1):
                g[r][c1] = corridor_char

    # ---------- carve maze ----------
    if algorithm == 'dfs':
        sr, sc = rng.randrange(ch), rng.randrange(cw)
        visited[sr][sc] = True; carve_cell(sr, sc)
        stack = [(sr, sc)]
        while stack:
            cr, cc = stack[-1]
            nbrs = [(cr+dr, cc+dc) for dr, dc in ((-1,0),(1,0),(0,-1),(0,1))
                    if 0 <= cr+dr < ch and 0 <= cc+dc < cw
                    and not visited[cr+dr][cc+dc]]
            if not nbrs:
                stack.pop(); continue
            nr, nc = rng.choice(nbrs)
            visited[nr][nc] = True
            carve_between(cr, cc, nr, nc)
            stack.append((nr, nc))

    elif algorithm == 'prim':
        sr, sc = rng.randrange(ch), rng.randrange(cw)
        visited[sr][sc] = True; carve_cell(sr, sc)
        frontier = []
        def push(cr, cc):
            for dr, dc in ((-1,0),(1,0),(0,-1),(0,1)):
                nr, nc = cr+dr, cc+dc
                if 0 <= nr < ch and 0 <= nc < cw and not visited[nr][nc]:
                    frontier.append((nr, nc, cr, cc))
        push(sr, sc)
        while frontier:
            i = rng.randrange(len(frontier))
            nr, nc, fr, fc = frontier.pop(i)
            if visited[nr][nc]: continue
            visited[nr][nc] = True
            carve_between(fr, fc, nr, nc)
            push(nr, nc)
    else:
        raise ValueError(f"unknown algorithm: {algorithm}")

    # ---------- braiding (loops) ----------
    if loopiness > 0:
        cells = [(cr, cc) for cr in range(ch) for cc in range(cw)]
        rng.shuffle(cells)
        for cr, cc in cells:
            for dr, dc in ((1, 0), (0, 1)):
                nr, nc = cr+dr, cc+dc
                if not (0 <= nr < ch and 0 <= nc < cw): continue
                r1, c1 = cpos(cr, cc); r2, c2 = cpos(nr, nc)
                mr, mc = (r1+r2)//2, (c1+c2)//2
                if g[mr][mc] == wall_char and rng.random() < loopiness:
                    carve_between(cr, cc, nr, nc)

    # ---------- start / end (graph diameter) ----------
    def bfs_far(src):
        dist = {src: 0}; q = deque([src]); far = src
        while q:
            r, c = q.popleft()
            if dist[(r, c)] > dist[far]: far = (r, c)
            for dr, dc in ((-1,0),(1,0),(0,-1),(0,1)):
                nr, nc = r+dr, c+dc
                if (0 <= nr < H and 0 <= nc < W
                        and g[nr][nc] == corridor_char
                        and (nr, nc) not in dist):
                    dist[(nr, nc)] = dist[(r, c)] + 1
                    q.append((nr, nc))
        return far

    src = next((r, c) for r in range(H) for c in range(W)
               if g[r][c] == corridor_char)
    a = bfs_far(src); b = bfs_far(a)

    # ---------- doors ----------
    # eligible = wall cell with exactly ONE corridor neighbor (4-dir),
    # and the cell on the OPPOSITE side is also wall (so a room can lie beyond).
    eligible = []
    for r in range(1, H - 1):
        for c in range(1, W - 1):
            if g[r][c] != wall_char: continue
            corr_dirs = [(dr, dc) for dr, dc in ((-1,0),(1,0),(0,-1),(0,1))
                         if g[r+dr][c+dc] == corridor_char]
            if len(corr_dirs) != 1: continue
            dr, dc = corr_dirs[0]
            orr, occ = r - dr, c - dc
            if g[orr][occ] != wall_char: continue
            eligible.append((r, c))

    rng.shuffle(eligible)
    placed = []
    target = int(len(eligible) * door_density)
    for r, c in eligible:
        if len(placed) >= target: break
        if any(abs(pr-r) + abs(pc-c) < min_door_spacing for pr, pc in placed):
            continue
        g[r][c] = door_char
        placed.append((r, c))

    rng.shuffle(placed)
    for r, c in placed[:special_room_count]:
        g[r][c] = special_char

    g[a[0]][a[1]] = start_char
    g[b[0]][b[1]] = end_char

    return [''.join(row) for row in g]

