dungeon_halls_map(
    width=20,
    height=20,
    random_seed=42,
    wall_thickness=2,      # Walls are this many cells thick
    loopiness=0.12,        # 0 = perfect maze; >0 adds loops
    door_density=0.30,     # fraction of eligible wall-cells that become doors
    min_door_spacing=4,    # Manhattan distance between doors
    special_room_count=3,  # doors upgraded to 'O'
    algorithm='dfs',       # 'dfs' or 'prim'
    corridor_char='.',
    wall_char='#',
    door_char='O',
    special_char='X',      # maybe traps, whatever the GM/DM wants
    start_char='P',        # Party You Are Here
    end_char='S',          # Stairs (down)
)

"""
dungeon_halls_map.py — v2

Generates a 2D ASCII dungeon / maze map suitable for tabletop RPG use,
roguelike prototyping, or procedural-content experiments.

Design notes
------------
- Walls are *thick* (parameterized via `wall_thickness`) so that doors
  can sit IN a wall cell rather than only between two corridor cells.
- A door candidate is a wall cell with exactly ONE corridor neighbor
  (in the 4-cardinal sense), AND the cell directly OPPOSITE that
  corridor is also a wall. Conceptually: the corridor approaches the
  door from one side, and a wall (which a future room could occupy)
  lies on the other side.
"""

import random
from collections import deque


def dungeon_halls_map(
    width=20,
    height=20,
    random_seed=None,
    wall_thickness=2,       # walls are this many cells thick
    loopiness=0.12,         # 0 = perfect maze; >0 adds loops (braiding)
    door_density=0.30,      # fraction of eligible wall-cells that become doors
    min_door_spacing=4,     # Manhattan distance enforced between doors
    special_room_count=3,   # number of doors upgraded to `special_char`
    algorithm='dfs',        # maze carving algorithm: 'dfs' or 'prim'
    corridor_char='.',
    wall_char='#',
    door_char='O',
    special_char='X',       # e.g. traps, treasure, GM/DM-defined feature
    start_char='P',         # Party / "You Are Here"
    end_char='S',           # Stairs (down)
):
    """
    Generate a procedurally-carved dungeon-corridor map and return it as
    a list of single-line strings (one string per grid row).

    Parameters
    ----------
    width : int
        Requested overall grid width in characters. The actual returned
        width may be slightly smaller because the layout snaps to whole
        corridor-cell + wall-thickness "pitches"; see Returns.
    height : int
        Requested overall grid height in characters. Same snapping
        caveat as `width`.
    random_seed : int | None
        Seed for the local `random.Random` instance. `None` produces a
        nondeterministic map; any integer produces a reproducible map.
    wall_thickness : int
        Number of cells of wall between adjacent corridor cells. Must
        be >= 1; values < 1 are clamped up to 1. Thicker walls leave
        room for doors to sit "inside" the wall rather than only at a
        corridor-to-corridor boundary.
    loopiness : float
        Braiding factor in [0.0, 1.0+]. A perfect maze (the default
        carve output) has exactly one path between any two cells. After
        carving, each interior wall-segment between two corridor cells
        is removed with probability `loopiness`, introducing loops /
        alternate routes. 0.0 keeps a perfect maze; ~0.1–0.2 yields a
        comfortably loopy dungeon; 1.0 collapses most of the maze into
        an open hall.
    door_density : float
        Fraction in [0.0, 1.0] of *eligible* wall cells that will be
        turned into doors. Eligibility is described in the module
        docstring.
    min_door_spacing : int
        Minimum Manhattan distance enforced between any two placed
        doors. Prevents door clusters.
    special_room_count : int
        Number of already-placed doors that will be re-tagged as
        `special_char` (e.g. trapped door, secret room, vault).
    algorithm : str
        Maze carving algorithm. One of:
          - 'dfs'  : recursive-backtracker / depth-first search; tends
                     to produce long winding corridors.
          - 'prim' : randomized Prim's; tends to produce a more uniform
                     branchy texture.
    corridor_char, wall_char, door_char, special_char, start_char, end_char : str
        Single-character glyphs used to render each tile type.

    Returns
    -------
    list[str]
        A list of strings, one string per row of the generated map.
        All rows have the same length. To render as a single block:

            generated_map_rows_list = dungeon_halls_map(...)
            generated_map_string = '\\n'.join(generated_map_rows_list)
            print(generated_map_string)

        Tile glyph legend (defaults shown):
            '#' wall_char       : impassable wall
            '.' corridor_char   : walkable corridor / floor
            'O' door_char       : door embedded in a wall
            'X' special_char    : "special" door (trap/secret/etc.)
            'P' start_char      : start position (party marker)
            'S' end_char        : end position (stairs down)

        The start ('P') and end ('S') tiles are placed at the two
        endpoints of an approximate graph diameter (longest shortest
        path) of the corridor network, so the player has a meaningful
        traversal distance.

    Raises
    ------
    ValueError
        If `algorithm` is neither 'dfs' nor 'prim'.

    Notes
    -----
    - The dimensions of the returned grid are
          actual_width  = corridor_grid_columns * cell_pitch + wall_thickness
          actual_height = corridor_grid_rows    * cell_pitch + wall_thickness
      where  cell_pitch = wall_thickness + 1  (one corridor cell + wall).
      `actual_width` may be <= `width` (and similarly for height) due to
      this snapping.
    - This function is pure with respect to the supplied `random_seed`:
      the same seed + same parameters always yields the same map.
    """

    # ------------------------------------------------------------------
    # Random number generator local to this call (does not disturb the
    # global `random` module state).
    # ------------------------------------------------------------------
    random_number_generator = random.Random(random_seed)

    # ------------------------------------------------------------------
    # Geometry setup.
    #
    # The grid is conceptually a lattice of "corridor cells" separated
    # by walls. Each corridor cell is `corridor_thickness_cells` wide
    # (always 1 here) and adjacent corridor cells are separated by
    # `wall_thickness_cells` of wall.
    #
    # `cell_pitch` is the stride from one corridor cell to the next:
    #     wall | corridor | wall | corridor | wall | ...
    # ------------------------------------------------------------------
    wall_thickness_cells = max(1, wall_thickness)        # clamp to >= 1
    corridor_thickness_cells = 1                          # one-cell-wide corridors
    cell_pitch = wall_thickness_cells + corridor_thickness_cells

    # How many corridor cells fit along each axis (at least 2x2 of them).
    corridor_grid_columns = max(2, (width  - wall_thickness_cells) // cell_pitch)
    corridor_grid_rows    = max(2, (height - wall_thickness_cells) // cell_pitch)

    # Final pixel/character dimensions of the rendered map. We add a
    # trailing wall_thickness so the map is bordered by wall on all sides.
    total_grid_width  = corridor_grid_columns * cell_pitch + wall_thickness_cells
    total_grid_height = corridor_grid_rows    * cell_pitch + wall_thickness_cells

    # The map itself, initialised entirely as wall. Carving punches
    # corridor characters into this grid.
    dungeon_grid = [
        [wall_char] * total_grid_width
        for _ in range(total_grid_height)
    ]

    # Tracks which corridor cells have already been visited by the
    # carving algorithm.
    visited_corridor_cells = [
        [False] * corridor_grid_columns
        for _ in range(corridor_grid_rows)
    ]

    # ------------------------------------------------------------------
    # Helpers to translate between "corridor-cell coordinates" (cr, cc)
    # — used by the maze algorithms — and "grid-character coordinates"
    # (r, c) — used to write into `dungeon_grid`.
    # ------------------------------------------------------------------
    def corridor_cell_to_grid_position(corridor_row, corridor_column):
        """
        Translate a corridor-cell index (corridor_row, corridor_column)
        into the (grid_row, grid_column) of its single corridor character
        in `dungeon_grid`.
        """
        grid_row    = wall_thickness_cells + corridor_row    * cell_pitch
        grid_column = wall_thickness_cells + corridor_column * cell_pitch
        return grid_row, grid_column

    def carve_corridor_cell(corridor_row, corridor_column):
        """
        Punch a single corridor character into `dungeon_grid` at the
        position of corridor-cell (corridor_row, corridor_column).
        """
        grid_row, grid_column = corridor_cell_to_grid_position(
            corridor_row, corridor_column
        )
        dungeon_grid[grid_row][grid_column] = corridor_char

    def carve_corridor_between_cells(
        from_corridor_row, from_corridor_column,
        to_corridor_row,   to_corridor_column,
    ):
        """
        Punch a contiguous corridor — including the wall segment
        between them — connecting two adjacent corridor cells. The two
        cells must be axis-aligned neighbors in corridor-cell space.
        """
        from_grid_row, from_grid_column = corridor_cell_to_grid_position(
            from_corridor_row, from_corridor_column
        )
        to_grid_row, to_grid_column = corridor_cell_to_grid_position(
            to_corridor_row, to_corridor_column
        )

        if from_grid_row == to_grid_row:
            # Horizontal carve: same row, sweep all columns between them.
            for grid_column in range(
                min(from_grid_column, to_grid_column),
                max(from_grid_column, to_grid_column) + 1,
            ):
                dungeon_grid[from_grid_row][grid_column] = corridor_char
        else:
            # Vertical carve: same column, sweep all rows between them.
            for grid_row in range(
                min(from_grid_row, to_grid_row),
                max(from_grid_row, to_grid_row) + 1,
            ):
                dungeon_grid[grid_row][from_grid_column] = corridor_char

    # ------------------------------------------------------------------
    # MAZE CARVING
    # ------------------------------------------------------------------
    if algorithm == 'dfs':
        # Recursive-backtracker (iterative). Pick a random start cell,
        # repeatedly walk to a random unvisited neighbor; when stuck,
        # backtrack via the explicit stack.
        start_corridor_row    = random_number_generator.randrange(corridor_grid_rows)
        start_corridor_column = random_number_generator.randrange(corridor_grid_columns)
        visited_corridor_cells[start_corridor_row][start_corridor_column] = True
        carve_corridor_cell(start_corridor_row, start_corridor_column)

        depth_first_stack = [(start_corridor_row, start_corridor_column)]
        while depth_first_stack:
            current_corridor_row, current_corridor_column = depth_first_stack[-1]

            # Collect axis-aligned neighbors that have not yet been visited.
            unvisited_neighbors = [
                (current_corridor_row + delta_row,
                 current_corridor_column + delta_column)
                for delta_row, delta_column in ((-1, 0), (1, 0), (0, -1), (0, 1))
                if 0 <= current_corridor_row    + delta_row    < corridor_grid_rows
                and 0 <= current_corridor_column + delta_column < corridor_grid_columns
                and not visited_corridor_cells[
                    current_corridor_row    + delta_row
                ][   current_corridor_column + delta_column]
            ]

            if not unvisited_neighbors:
                # Dead end -> backtrack.
                depth_first_stack.pop()
                continue

            chosen_neighbor_row, chosen_neighbor_column = random_number_generator.choice(
                unvisited_neighbors
            )
            visited_corridor_cells[chosen_neighbor_row][chosen_neighbor_column] = True
            carve_corridor_between_cells(
                current_corridor_row, current_corridor_column,
                chosen_neighbor_row,  chosen_neighbor_column,
            )
            depth_first_stack.append((chosen_neighbor_row, chosen_neighbor_column))

    elif algorithm == 'prim':
        # Randomized Prim's: maintain a "frontier" of (unvisited cell,
        # visited cell that touches it) edges; repeatedly pick a random
        # frontier edge and carve through it.
        start_corridor_row    = random_number_generator.randrange(corridor_grid_rows)
        start_corridor_column = random_number_generator.randrange(corridor_grid_columns)
        visited_corridor_cells[start_corridor_row][start_corridor_column] = True
        carve_corridor_cell(start_corridor_row, start_corridor_column)

        frontier_edges = []  # each entry: (neighbor_row, neighbor_col, from_row, from_col)

        def push_frontier_neighbors_of(
            current_corridor_row, current_corridor_column
        ):
            """
            Add every unvisited 4-neighbor of (current_corridor_row,
            current_corridor_column) onto the frontier list, tagged
            with the cell they came FROM.
            """
            for delta_row, delta_column in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                neighbor_corridor_row    = current_corridor_row    + delta_row
                neighbor_corridor_column = current_corridor_column + delta_column
                if (
                    0 <= neighbor_corridor_row    < corridor_grid_rows
                    and 0 <= neighbor_corridor_column < corridor_grid_columns
                    and not visited_corridor_cells[
                        neighbor_corridor_row
                    ][   neighbor_corridor_column]
                ):
                    frontier_edges.append((
                        neighbor_corridor_row,
                        neighbor_corridor_column,
                        current_corridor_row,
                        current_corridor_column,
                    ))

        push_frontier_neighbors_of(start_corridor_row, start_corridor_column)

        while frontier_edges:
            # Pop a random edge from the frontier (random index, swap-free pop).
            frontier_index = random_number_generator.randrange(len(frontier_edges))
            (
                neighbor_corridor_row,
                neighbor_corridor_column,
                origin_corridor_row,
                origin_corridor_column,
            ) = frontier_edges.pop(frontier_index)

            # The neighbor may have been visited via some other edge
            # popped earlier; if so, skip.
            if visited_corridor_cells[neighbor_corridor_row][neighbor_corridor_column]:
                continue

            visited_corridor_cells[neighbor_corridor_row][neighbor_corridor_column] = True
            carve_corridor_between_cells(
                origin_corridor_row,   origin_corridor_column,
                neighbor_corridor_row, neighbor_corridor_column,
            )
            push_frontier_neighbors_of(neighbor_corridor_row, neighbor_corridor_column)

    else:
        raise ValueError(
            f"unknown algorithm: {algorithm!r} "
            f"(expected 'dfs' or 'prim')"
        )

    # ------------------------------------------------------------------
    # BRAIDING (loop introduction).
    #
    # The carve above produces a "perfect maze" — one path between any
    # two cells. For dungeons we typically want some loops so the player
    # can take alternate routes. For each pair of axis-adjacent corridor
    # cells whose between-wall is still solid, knock that wall out with
    # probability `loopiness`.
    # ------------------------------------------------------------------
    if loopiness > 0:
        all_corridor_cells = [
            (corridor_row, corridor_column)
            for corridor_row    in range(corridor_grid_rows)
            for corridor_column in range(corridor_grid_columns)
        ]
        random_number_generator.shuffle(all_corridor_cells)

        for current_corridor_row, current_corridor_column in all_corridor_cells:
            # Only check south and east neighbors to avoid double-checking pairs.
            for delta_row, delta_column in ((1, 0), (0, 1)):
                neighbor_corridor_row    = current_corridor_row    + delta_row
                neighbor_corridor_column = current_corridor_column + delta_column
                if not (
                    0 <= neighbor_corridor_row    < corridor_grid_rows
                    and 0 <= neighbor_corridor_column < corridor_grid_columns
                ):
                    continue

                from_grid_row, from_grid_column = corridor_cell_to_grid_position(
                    current_corridor_row, current_corridor_column
                )
                to_grid_row, to_grid_column = corridor_cell_to_grid_position(
                    neighbor_corridor_row, neighbor_corridor_column
                )

                # Inspect the midpoint character: if it is still wall,
                # this pair is currently NOT directly connected.
                midpoint_grid_row    = (from_grid_row    + to_grid_row)    // 2
                midpoint_grid_column = (from_grid_column + to_grid_column) // 2

                if (
                    dungeon_grid[midpoint_grid_row][midpoint_grid_column] == wall_char
                    and random_number_generator.random() < loopiness
                ):
                    carve_corridor_between_cells(
                        current_corridor_row,  current_corridor_column,
                        neighbor_corridor_row, neighbor_corridor_column,
                    )

    # ------------------------------------------------------------------
    # START / END placement (approximate graph diameter via double BFS).
    #
    # 1. Pick any corridor cell as a seed.
    # 2. BFS from the seed; record the farthest corridor cell reachable.
    # 3. BFS again from that farthest cell; the new farthest cell is one
    #    end of an approximate longest shortest path.
    # The two endpoints become start ('P') and end ('S').
    # ------------------------------------------------------------------
    def breadth_first_find_farthest_corridor_cell(source_grid_position):
        """
        Run a 4-connected BFS over corridor characters in `dungeon_grid`,
        starting at `source_grid_position` (a (grid_row, grid_column)
        tuple), and return the (grid_row, grid_column) of the corridor
        cell with the greatest BFS distance from the source.
        """
        distance_from_source = {source_grid_position: 0}
        breadth_first_queue = deque([source_grid_position])
        farthest_cell_so_far = source_grid_position

        while breadth_first_queue:
            current_grid_row, current_grid_column = breadth_first_queue.popleft()

            if (
                distance_from_source[(current_grid_row, current_grid_column)]
                > distance_from_source[farthest_cell_so_far]
            ):
                farthest_cell_so_far = (current_grid_row, current_grid_column)

            for delta_row, delta_column in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                neighbor_grid_row    = current_grid_row    + delta_row
                neighbor_grid_column = current_grid_column + delta_column
                if (
                    0 <= neighbor_grid_row    < total_grid_height
                    and 0 <= neighbor_grid_column < total_grid_width
                    and dungeon_grid[neighbor_grid_row][neighbor_grid_column] == corridor_char
                    and (neighbor_grid_row, neighbor_grid_column) not in distance_from_source
                ):
                    distance_from_source[(neighbor_grid_row, neighbor_grid_column)] = (
                        distance_from_source[(current_grid_row, current_grid_column)] + 1
                    )
                    breadth_first_queue.append((neighbor_grid_row, neighbor_grid_column))

        return farthest_cell_so_far

    # Find any corridor character to seed the diameter search.
    breadth_first_search_source = next(
        (grid_row, grid_column)
        for grid_row    in range(total_grid_height)
        for grid_column in range(total_grid_width)
        if dungeon_grid[grid_row][grid_column] == corridor_char
    )
    farthest_from_arbitrary_seed   = breadth_first_find_farthest_corridor_cell(
        breadth_first_search_source
    )
    diameter_opposite_endpoint     = breadth_first_find_farthest_corridor_cell(
        farthest_from_arbitrary_seed
    )

    # ------------------------------------------------------------------
    # DOOR placement.
    #
    # A wall cell is "eligible" to become a door if and only if:
    #   - it currently shows wall_char, AND
    #   - exactly ONE of its 4 neighbors is corridor_char (i.e. a single
    #     corridor approaches it), AND
    #   - the cell directly OPPOSITE that corridor neighbor is also
    #     wall_char (so a future room could plausibly lie on the far
    #     side of the door).
    #
    # We then shuffle, greedily place up to `door_density * eligible`
    # doors while honoring `min_door_spacing` (Manhattan).
    # ------------------------------------------------------------------
    eligible_door_positions = []
    for grid_row in range(1, total_grid_height - 1):
        for grid_column in range(1, total_grid_width - 1):
            if dungeon_grid[grid_row][grid_column] != wall_char:
                continue

            corridor_neighbor_directions = [
                (delta_row, delta_column)
                for delta_row, delta_column in ((-1, 0), (1, 0), (0, -1), (0, 1))
                if dungeon_grid[grid_row + delta_row][grid_column + delta_column] == corridor_char
            ]
            if len(corridor_neighbor_directions) != 1:
                continue

            corridor_delta_row, corridor_delta_column = corridor_neighbor_directions[0]
            opposite_grid_row    = grid_row    - corridor_delta_row
            opposite_grid_column = grid_column - corridor_delta_column
            if dungeon_grid[opposite_grid_row][opposite_grid_column] != wall_char:
                continue

            eligible_door_positions.append((grid_row, grid_column))

    random_number_generator.shuffle(eligible_door_positions)

    placed_door_positions = []
    target_door_count = int(len(eligible_door_positions) * door_density)

    for candidate_grid_row, candidate_grid_column in eligible_door_positions:
        if len(placed_door_positions) >= target_door_count:
            break

        # Reject candidates that are too close to any already-placed door.
        too_close_to_existing_door = any(
            abs(placed_grid_row - candidate_grid_row)
            + abs(placed_grid_column - candidate_grid_column)
            < min_door_spacing
            for placed_grid_row, placed_grid_column in placed_door_positions
        )
        if too_close_to_existing_door:
            continue

        dungeon_grid[candidate_grid_row][candidate_grid_column] = door_char
        placed_door_positions.append((candidate_grid_row, candidate_grid_column))

    # ------------------------------------------------------------------
    # SPECIAL door upgrades.
    # Re-tag a random subset of the placed doors as `special_char`
    # (e.g. trapped, locked, secret, vault, GM/DM-defined).
    # ------------------------------------------------------------------
    random_number_generator.shuffle(placed_door_positions)
    for special_grid_row, special_grid_column in placed_door_positions[:special_room_count]:
        dungeon_grid[special_grid_row][special_grid_column] = special_char

    # ------------------------------------------------------------------
    # Stamp the start ('P') and end ('S') tiles at the diameter endpoints.
    # ------------------------------------------------------------------
    dungeon_grid[farthest_from_arbitrary_seed[0]][farthest_from_arbitrary_seed[1]] = start_char
    dungeon_grid[diameter_opposite_endpoint[0]][diameter_opposite_endpoint[1]] = end_char

    # ------------------------------------------------------------------
    # Final return: list of strings, one per row.
    # ------------------------------------------------------------------
    return [''.join(row_characters) for row_characters in dungeon_grid]


