"""
fog_walk_dungeon.py  (v2)

Interactive fog-of-war walker for ASCII dungeon maps produced by
`dungeon_halls_map(...)` (see your generator module).

What changed from v1
--------------------
1. No more "(press Enter to continue)" prompts on blocked / unknown moves.
   Instead, a `status_message_text` is printed under the map on the next
   redraw. The game never pauses except at the single Move> prompt.
2. Multi-level descent: when `go_down_stairs=True` and a
   `next_level_generator_function` is supplied, stepping onto the
   `end_char` ('S') generates a fresh dungeon and continues seamlessly.
3. New visibility sub-rule: "see one-space into a hall, and the wall
   facing them" — implemented as a 1-cell perpendicular peek beside
   every visible cardinal-ray cell (and beside the player), plus a
   second perpendicular cell IF the first peek lands on an open
   hallway (so you see the wall capping that one-cell glance).
4. Returns a structured summary dict with per-level and total stats.

Visibility model (in detail)
----------------------------
From the party's current cell:

  - Cast four cardinal rays (N, S, E, W). Each ray reveals up to
    `steps_seen_ahead` cells. The first wall along the ray is
    revealed (you can SEE the wall) and stops that ray.
  - At every revealed non-wall cell along each ray (and at the
    party's own cell), reveal the two perpendicular flanking cells
    (1 step left and 1 step right of the ray). This is what shows
    you the corridor walls AND a 1-cell peek into any side opening.
  - If a perpendicular peek cell is itself open hallway, also reveal
    one more cell in that perpendicular direction. This is "the wall
    facing them" — exactly one extra cell, so you do NOT see deeper
    around the corner.

This satisfies all of:
  * "straight up to N spaces, including walls along straight ahead"
  * "one-space into a hall, and the wall facing them"
  * "cannot see around corners" (max two perpendicular cells, only
    when the first is an opening; never extends along the side hall)

Walkability
-----------
By default the party may step onto:
    {hallway_char, end_char, *door_chars}
plus the player's own marker (so the start cell is valid). Override
this with the `walkable_chars` parameter. Walls are never walkable
unless explicitly added.
"""

# import os
# import sys
# import traceback


def fog_walk_dungeon(
    ascii_map,
    fog_char='~',
    steps_seen_ahead=3,
    forget_breadcrumbs=False,
    hallway_char='.',
    wall_char='#',
    player_char='P',
    end_char='S',
    door_chars=('O', 'X'),
    walkable_chars=None,
    go_down_stairs=True,
    next_level_generator_function=None,
    max_levels=None,
    go_north='w',
    go_south='s',
    go_east='d',
    go_west='a',
    quit_command='q',
    clear_terminal=True,
):
    """
    Run an interactive fog-of-war walk over an ASCII dungeon map,
    optionally descending to fresh dungeon levels when the party
    reaches the stairs cell.

    Parameters
    ----------
    ascii_map : str | list[str]
        The starting dungeon map. Either a single string with rows
        separated by '\\n', or a list of strings (one per row). Rows
        of unequal length are right-padded with spaces to the longest
        row.
    fog_char : str, optional
        Single character drawn for any cell that is not currently
        visible (and, if `forget_breadcrumbs` is True, also for any
        cell not currently visible regardless of history).
        Default '~'.
    steps_seen_ahead : int, optional
        Maximum number of cells the party can see in each cardinal
        direction. The first wall along a ray is revealed and stops
        the ray. Must be >= 0. Default 3.
    forget_breadcrumbs : bool, optional
        If True, only currently-visible cells are drawn; previously
        seen cells revert to fog. If False (default), any cell ever
        seen on the current level remains revealed for that level.
        Note: revealed memory does NOT carry across descents.
    hallway_char : str, optional
        Character representing walkable corridor floor. Default '.'.
    wall_char : str, optional
        Character representing an opaque, impassable wall. Walls
        block both movement and line of sight. Default '#'.
    player_char : str, optional
        Character marking the party. The map MUST contain at least
        one such cell on every level (the first found is used).
        Default 'P'.
    end_char : str, optional
        Character marking the goal cell (stairs down). Default 'S'.
    door_chars : tuple[str, ...], optional
        Door / special-door characters. Used only when building the
        default `walkable_chars` set. Default ('O', 'X').
    walkable_chars : Iterable[str] | None, optional
        Characters the party is allowed to step onto. If None
        (default), built from {hallway_char, end_char, *door_chars}.
        The player_char is always walkable so the start cell works.
    go_down_stairs : bool, optional
        If True (default), reaching `end_char` triggers a level
        descent IF `next_level_generator_function` is supplied.
        If False, reaching `end_char` ends the walk with outcome
        'reached_end'.
    next_level_generator_function : callable | None, optional
        A zero-argument callable returning the next level as a
        str (rows joined by '\\n') or a list[str]. Required for
        multi-level descent. If None and `go_down_stairs` is True,
        the first descent simply ends the game with 'reached_end'.
    max_levels : int | None, optional
        If set, after completing this many levels (i.e. stepping on
        stairs `max_levels` times) the game ends successfully with
        outcome 'reached_max_levels'. None (default) means unlimited.
    go_north, go_south, go_east, go_west : str, optional
        Single-character movement commands. Defaults: w / s / d / a.
    quit_command : str, optional
        Single-character command to exit cleanly. Default 'q'.
    clear_terminal : bool, optional
        If True (default), attempt to clear the screen between
        frames using IPython.display.clear_output (notebook) or the
        platform 'clear'/'cls' (CLI). Best-effort; never fatal.

    Returns
    -------
    dict
        Summary with keys:
          'outcome'                : 'reached_end' | 'reached_max_levels'
                                   | 'quit' | 'input_closed' | 'error'
          'total_move_count'       : int, moves across all levels
          'levels_cleared'         : int, stairs reached count
          'final_level_index'      : int, 1-based current level
          'final_row'              : int
          'final_col'              : int
          'final_revealed_count'   : int
          'error_traceback'        : str | None

    Raises
    ------
    TypeError
        If `ascii_map` is neither str nor list[str], or
        `next_level_generator_function` is provided but not callable.
    ValueError
        If the parsed map is empty / zero-width, `player_char` is
        missing on a generated level, or `steps_seen_ahead` < 0.
    """

    # ----------------------------------------------------------------
    # Parameter validation with explicit, helpful error messages.
    # ----------------------------------------------------------------
    if not isinstance(steps_seen_ahead, int):
        raise TypeError(
            f"steps_seen_ahead must be int, got "
            f"{type(steps_seen_ahead).__name__}"
        )
    if steps_seen_ahead < 0:
        raise ValueError(
            f"steps_seen_ahead must be >= 0, got {steps_seen_ahead}"
        )
    for parameter_name, parameter_value in (
        ('fog_char', fog_char),
        ('hallway_char', hallway_char),
        ('wall_char', wall_char),
        ('player_char', player_char),
        ('end_char', end_char),
        ('go_north', go_north),
        ('go_south', go_south),
        ('go_east', go_east),
        ('go_west', go_west),
        ('quit_command', quit_command),
    ):
        if not isinstance(parameter_value, str) or len(parameter_value) != 1:
            raise ValueError(
                f"{parameter_name} must be a single-character string, "
                f"got {parameter_value!r}"
            )
    if (next_level_generator_function is not None
            and not callable(next_level_generator_function)):
        raise TypeError(
            "next_level_generator_function must be callable or None, "
            f"got {type(next_level_generator_function).__name__}"
        )
    if max_levels is not None:
        if not isinstance(max_levels, int) or max_levels < 1:
            raise ValueError(
                f"max_levels must be a positive int or None, got {max_levels!r}"
            )

    # ----------------------------------------------------------------
    # Build the walkable-character set.
    # ----------------------------------------------------------------
    if walkable_chars is None:
        walkable_chars_set = {hallway_char, end_char}
        for door_character in door_chars:
            walkable_chars_set.add(door_character)
    else:
        walkable_chars_set = set(walkable_chars)
    # The player's own marker is always walkable (start cell).
    walkable_chars_set.add(player_char)

    # ----------------------------------------------------------------
    # Helper: parse a map (str or list[str]) into a mutable 2-D grid.
    # Returns (grid_list_of_lists, height, width).
    # ----------------------------------------------------------------
    def parse_ascii_map_into_grid(map_input):
        """
        Convert `map_input` (str or list[str]) into a uniformly-padded
        2-D list of single-character cells, plus its height and width.
        Trailing fully-empty rows are stripped. Ragged rows are
        space-padded to the longest row width.
        """
        if isinstance(map_input, str):
            split_rows_list = map_input.split('\n')
        elif isinstance(map_input, list):
            for entry_index, entry_value in enumerate(map_input):
                if not isinstance(entry_value, str):
                    raise TypeError(
                        f"map row [{entry_index}] is "
                        f"{type(entry_value).__name__}, expected str"
                    )
            split_rows_list = list(map_input)
        else:
            raise TypeError(
                f"ascii_map must be str or list[str], got "
                f"{type(map_input).__name__}"
            )

        # Strip trailing fully-empty rows.
        while split_rows_list and split_rows_list[-1] == '':
            split_rows_list.pop()

        if len(split_rows_list) == 0:
            raise ValueError("ascii_map is empty after parsing.")

        grid_height_local = len(split_rows_list)
        grid_width_local = max(len(row_text) for row_text in split_rows_list)
        if grid_width_local == 0:
            raise ValueError("ascii_map has zero-width rows.")

        padded_grid_local = [
            list(row_text.ljust(grid_width_local))
            for row_text in split_rows_list
        ]
        return padded_grid_local, grid_height_local, grid_width_local

    # ----------------------------------------------------------------
    # Helper: locate the player's starting cell on a fresh grid.
    # Replaces the player marker with hallway_char so the player is a
    # pure visual overlay during render.
    # ----------------------------------------------------------------
    def locate_and_normalize_player(dungeon_grid_param,
                                    grid_height_param,
                                    grid_width_param):
        """
        Find the first cell equal to `player_char` in `dungeon_grid_param`,
        replace it with `hallway_char` (so renders can overlay 'P'),
        and return (player_row, player_col).
        """
        for scan_row_index in range(grid_height_param):
            for scan_col_index in range(grid_width_param):
                if dungeon_grid_param[scan_row_index][scan_col_index] == player_char:
                    dungeon_grid_param[scan_row_index][scan_col_index] = hallway_char
                    return scan_row_index, scan_col_index
        raise ValueError(
            f"Player character {player_char!r} not found anywhere in the map."
        )

    # ----------------------------------------------------------------
    # Helper: best-effort screen clear (notebook + CLI). Non-fatal.
    # We use clear_output(wait=False) to avoid the wait=True race that
    # can interact poorly with input() in some Jupyter front-ends.
    # ----------------------------------------------------------------
    def clear_screen_safely():
        """Best-effort visual clear; failure is swallowed by design."""
        if not clear_terminal:
            return
        try:
            from IPython.display import clear_output as ipython_clear_output
            ipython_clear_output(wait=False)
            return
        except Exception:
            pass
        try:
            os.system('cls' if os.name == 'nt' else 'clear')
            return
        except Exception:
            sys.stdout.write('\n' * 2)
            sys.stdout.flush()

    # ----------------------------------------------------------------
    # State that spans levels.
    # ----------------------------------------------------------------
    current_ascii_map = ascii_map
    total_move_count = 0
    levels_cleared_count = 0
    current_level_index = 1
    error_traceback_text = None
    outcome_label = 'quit'

    # State that gets re-initialized per level (declared here so that
    # the final return summary can reference them after errors).
    dungeon_grid = []
    grid_height = 0
    grid_width = 0
    player_row_index = 0
    player_col_index = 0
    revealed_cells_set = set()

    try:
        # ------------------------------------------------------------
        # Outer loop: one iteration per dungeon level.
        # ------------------------------------------------------------
        while True:
            # Parse / set up this level.
            dungeon_grid, grid_height, grid_width = parse_ascii_map_into_grid(
                current_ascii_map
            )
            player_row_index, player_col_index = locate_and_normalize_player(
                dungeon_grid, grid_height, grid_width
            )
            revealed_cells_set = set()
            level_move_count = 0
            status_message_text = (
                f"Welcome to level {current_level_index}. "
                f"Find the stairs ({end_char})."
            )

            # --------------------------------------------------------
            # Helper: compute currently-visible cell set from the
            # party's current position. Closes over dungeon_grid /
            # grid_height / grid_width / steps_seen_ahead.
            # --------------------------------------------------------
            def compute_currently_visible_cells(party_row, party_col):
                """
                Return the set of (row, col) cells currently within line
                of sight, per the visibility model in this module's
                docstring.
                """
                visible_cells_local_set = {(party_row, party_col)}

                # Helper to test grid bounds.
                def in_bounds(row_check, col_check):
                    return (0 <= row_check < grid_height
                            and 0 <= col_check < grid_width)

                # Always reveal the four cells immediately adjacent to
                # the party (so nearby walls and 1-cell peeks into side
                # openings always show, even if steps_seen_ahead is 0).
                for adj_dr, adj_dc in ((-1, 0), (1, 0), (0, -1), (0, 1)):
                    adj_r = party_row + adj_dr
                    adj_c = party_col + adj_dc
                    if in_bounds(adj_r, adj_c):
                        visible_cells_local_set.add((adj_r, adj_c))
                        # If that neighbor is open hallway, peek one more
                        # cell perpendicular to nothing (same direction)
                        # — i.e. the "wall facing them" if they glance in.
                        if (dungeon_grid[adj_r][adj_c] != wall_char):
                            adj2_r = adj_r + adj_dr
                            adj2_c = adj_c + adj_dc
                            if in_bounds(adj2_r, adj2_c):
                                # Only add it if the immediate neighbor
                                # was an opening (otherwise we'd be
                                # seeing past a wall).
                                if dungeon_grid[adj_r][adj_c] != wall_char:
                                    # Note: the cardinal-ray pass below
                                    # will also handle this; we keep it
                                    # here so the rule still holds when
                                    # steps_seen_ahead == 0.
                                    visible_cells_local_set.add(
                                        (adj2_r, adj2_c)
                                    )

                # Cardinal rays: up to steps_seen_ahead cells in each
                # of the four directions, stopping at (and including)
                # the first wall.
                cardinal_directions = ((-1, 0), (1, 0), (0, -1), (0, 1))
                for ray_dr, ray_dc in cardinal_directions:
                    for step_offset in range(1, steps_seen_ahead + 1):
                        ray_r = party_row + ray_dr * step_offset
                        ray_c = party_col + ray_dc * step_offset
                        if not in_bounds(ray_r, ray_c):
                            break
                        visible_cells_local_set.add((ray_r, ray_c))
                        ray_cell_char = dungeon_grid[ray_r][ray_c]
                        if ray_cell_char == wall_char:
                            # Wall is visible but blocks further sight.
                            break

                        # Reveal the two perpendicular flanking cells of
                        # this visible non-wall ray cell. These are the
                        # corridor walls / 1-cell side-passage peeks.
                        # 90-degree rotations of (ray_dr, ray_dc):
                        perpendicular_pair = (
                            (ray_dc, ray_dr),
                            (-ray_dc, -ray_dr),
                        )
                        for perp_dr, perp_dc in perpendicular_pair:
                            peek1_r = ray_r + perp_dr
                            peek1_c = ray_c + perp_dc
                            if not in_bounds(peek1_r, peek1_c):
                                continue
                            visible_cells_local_set.add((peek1_r, peek1_c))
                            # If the 1-step peek is open hallway / door,
                            # reveal exactly ONE more cell perpendicular
                            # — "the wall facing them". This must NEVER
                            # extend further: that would be seeing
                            # around the corner.
                            peek1_char = dungeon_grid[peek1_r][peek1_c]
                            if peek1_char != wall_char:
                                peek2_r = peek1_r + perp_dr
                                peek2_c = peek1_c + perp_dc
                                if in_bounds(peek2_r, peek2_c):
                                    visible_cells_local_set.add(
                                        (peek2_r, peek2_c)
                                    )

                return visible_cells_local_set

            # --------------------------------------------------------
            # Helper: render the current frame to a single string.
            # --------------------------------------------------------
            def render_current_view(party_row, party_col):
                """
                Build the string-rendering of the dungeon under the
                current fog rules, with the player overlaid at
                (party_row, party_col).
                """
                currently_visible_set = compute_currently_visible_cells(
                    party_row, party_col
                )
                if not forget_breadcrumbs:
                    revealed_cells_set.update(currently_visible_set)
                    cells_to_draw_set = revealed_cells_set
                else:
                    cells_to_draw_set = currently_visible_set

                rendered_row_strings_list = []
                for render_row_index in range(grid_height):
                    row_character_list = []
                    for render_col_index in range(grid_width):
                        if (render_row_index == party_row
                                and render_col_index == party_col):
                            row_character_list.append(player_char)
                        elif (render_row_index, render_col_index) in cells_to_draw_set:
                            row_character_list.append(
                                dungeon_grid[render_row_index][render_col_index]
                            )
                        else:
                            row_character_list.append(fog_char)
                    rendered_row_strings_list.append(
                        ''.join(row_character_list)
                    )
                return '\n'.join(rendered_row_strings_list)

            # --------------------------------------------------------
            # Inner loop: one iteration per move attempt on this level.
            # --------------------------------------------------------
            level_descended = False
            while True:
                clear_screen_safely()
                print(render_current_view(player_row_index, player_col_index))
                print(
                    f"Level {current_level_index}   "
                    f"Moves this level: {level_move_count}   "
                    f"Total moves: {total_move_count}"
                )
                print(
                    f"Move: {go_north}=N  {go_south}=S  "
                    f"{go_east}=E  {go_west}=W   "
                    f"Quit: {quit_command}"
                )
                if status_message_text:
                    print(f"> {status_message_text}")

                # Single input per frame. No other input() calls.
                try:
                    user_input_text = input("Move> ")
                except EOFError:
                    print("\n[input stream closed]")
                    outcome_label = 'input_closed'
                    return _build_summary(
                        outcome_label, total_move_count,
                        levels_cleared_count, current_level_index,
                        player_row_index, player_col_index,
                        revealed_cells_set, error_traceback_text,
                    )

                user_input_text = user_input_text.strip().lower()
                if user_input_text == '':
                    status_message_text = "(empty input — type a move key)"
                    continue

                command_character = user_input_text[0]

                if command_character == quit_command:
                    print("Quitting fog walk.")
                    outcome_label = 'quit'
                    return _build_summary(
                        outcome_label, total_move_count,
                        levels_cleared_count, current_level_index,
                        player_row_index, player_col_index,
                        revealed_cells_set, error_traceback_text,
                    )

                # Translate command to movement delta.
                move_delta_row = 0
                move_delta_col = 0
                if command_character == go_north:
                    move_delta_row = -1
                elif command_character == go_south:
                    move_delta_row = 1
                elif command_character == go_west:
                    move_delta_col = -1
                elif command_character == go_east:
                    move_delta_col = 1
                else:
                    status_message_text = (
                        f"Unknown command {command_character!r}. "
                        f"Use {go_north}/{go_south}/{go_east}/{go_west} "
                        f"or {quit_command}."
                    )
                    continue

                candidate_row = player_row_index + move_delta_row
                candidate_col = player_col_index + move_delta_col

                # Bounds check.
                if not (0 <= candidate_row < grid_height
                        and 0 <= candidate_col < grid_width):
                    status_message_text = "Blocked: edge of map."
                    continue

                # Walkability check.
                target_cell_character = dungeon_grid[candidate_row][candidate_col]
                if target_cell_character not in walkable_chars_set:
                    status_message_text = (
                        f"Blocked: cannot enter {target_cell_character!r}."
                    )
                    continue

                # Commit the move.
                player_row_index = candidate_row
                player_col_index = candidate_col
                level_move_count += 1
                total_move_count += 1
                status_message_text = ""

                # Stairs handling.
                if target_cell_character == end_char:
                    levels_cleared_count += 1

                    # Final reveal/render of this level before descent.
                    clear_screen_safely()
                    print(render_current_view(
                        player_row_index, player_col_index
                    ))
                    print(
                        f"Reached stairs on level {current_level_index} "
                        f"in {level_move_count} moves."
                    )

                    # Stop conditions for descent.
                    reached_max_levels = (
                        max_levels is not None
                        and levels_cleared_count >= max_levels
                    )
                    if reached_max_levels:
                        outcome_label = 'reached_max_levels'
                        return _build_summary(
                            outcome_label, total_move_count,
                            levels_cleared_count, current_level_index,
                            player_row_index, player_col_index,
                            revealed_cells_set, error_traceback_text,
                        )

                    if not go_down_stairs or next_level_generator_function is None:
                        outcome_label = 'reached_end'
                        return _build_summary(
                            outcome_label, total_move_count,
                            levels_cleared_count, current_level_index,
                            player_row_index, player_col_index,
                            revealed_cells_set, error_traceback_text,
                        )

                    # Generate the next level. Catch and report any
                    # generator failure with a clear message.
                    try:
                        generated_next_map = next_level_generator_function()
                    except Exception:
                        error_traceback_text = traceback.format_exc()
                        print(
                            "next_level_generator_function raised an "
                            "exception while generating the next level:"
                        )
                        print(error_traceback_text)
                        outcome_label = 'error'
                        return _build_summary(
                            outcome_label, total_move_count,
                            levels_cleared_count, current_level_index,
                            player_row_index, player_col_index,
                            revealed_cells_set, error_traceback_text,
                        )

                    # Brief inline prompt so the player can see "you
                    # reached the stairs" before descending. This is
                    # the ONE intentional pause besides Move>.
                    try:
                        input("(press Enter to descend to the next level) ")
                    except EOFError:
                        outcome_label = 'input_closed'
                        return _build_summary(
                            outcome_label, total_move_count,
                            levels_cleared_count, current_level_index,
                            player_row_index, player_col_index,
                            revealed_cells_set, error_traceback_text,
                        )

                    current_ascii_map = generated_next_map
                    current_level_index += 1
                    level_descended = True
                    break  # break inner loop -> outer loop re-inits

                # Otherwise just keep walking on this level.
                # (Loop continues.)

            # If we got here without descending, something logical
            # broke. As a safety, exit cleanly.
            if not level_descended:
                outcome_label = 'quit'
                return _build_summary(
                    outcome_label, total_move_count,
                    levels_cleared_count, current_level_index,
                    player_row_index, player_col_index,
                    revealed_cells_set, error_traceback_text,
                )

    except KeyboardInterrupt:
        print("\n[interrupted by user]")
        outcome_label = 'quit'
    except Exception:
        # Capture and report any unexpected exception. We never silently
        # swallow errors — they go to stdout and into the summary.
        error_traceback_text = traceback.format_exc()
        outcome_label = 'error'
        print("An unexpected error occurred during fog_walk_dungeon:")
        print(error_traceback_text)

    return _build_summary(
        outcome_label, total_move_count,
        levels_cleared_count, current_level_index,
        player_row_index, player_col_index,
        revealed_cells_set, error_traceback_text,
    )


# --------------------------------------------------------------------
# Module-level helper: build the canonical summary dict. Kept outside
# the main function so all return paths share one definition.
# --------------------------------------------------------------------
def _build_summary(
    outcome_label_param,
    total_move_count_param,
    levels_cleared_count_param,
    current_level_index_param,
    final_row_param,
    final_col_param,
    revealed_cells_set_param,
    error_traceback_text_param,
):
    """
    Construct the summary dict returned by `fog_walk_dungeon` from
    its current state. See `fog_walk_dungeon` docstring for keys.
    """
    return {
        'outcome': outcome_label_param,
        'total_move_count': total_move_count_param,
        'levels_cleared': levels_cleared_count_param,
        'final_level_index': current_level_index_param,
        'final_row': final_row_param,
        'final_col': final_col_param,
        'final_revealed_count': len(revealed_cells_set_param),
        'error_traceback': error_traceback_text_param,
    }

# Cell 1: your dungeon_halls_map(...) is already defined above.

# Cell 2: define a zero-arg generator function with whatever
#         dungeon parameters you want; fog_walk_dungeon will call
#         it each time the party descends stairs.
def make_next_dungeon_level():
    """Return a fresh dungeon map as a list[str] for the next level."""
    return dungeon_halls_map(
        width=15,
        height=15,
        random_seed=None,        # None => fresh randomness each level
        wall_thickness=2,
        loopiness=0.12,
        door_density=0.30,
        min_door_spacing=4,
        special_room_count=3,
        algorithm='prim',
    )

# Cell 3: build the first level and start walking.
first_level_map_rows_list = make_next_dungeon_level()
first_level_map_string = '\n'.join(first_level_map_rows_list)

# walk_summary_dict = fog_walk_dungeon(
#     ascii_map=first_level_map_string,
#     fog_char='~',
#     steps_seen_ahead=4,
#     forget_breadcrumbs=False,
