def run_v2_5_bot_iterator(
        use_this_api_service: str,
        use_this_model: str,
        random_seed: int = 42,
        max_game_rounds: int = 5,
        pov_pillar_view: bool = False,
):
    """
    5-bot iterator loop that aggregates notes,
    manages the rolling timeline of board states, and evaluates game-end conditions.
    It uses the LLM API pipeline `execute_single_bot_turn_pipeline`.

    Args:
        use_this_api_service (str): API service name ('mistral', 'anthropic',
            'google').
        use_this_model (str): Model identifier string.
        random_seed (int): Deterministic seed for room generation.
        max_game_rounds (int): Maximum number of rounds before forcing end.
        pov_pillar_view (bool): If True, players see only their pillar-limited
            point-of-view map.
    """
    try:
        print(f"\n=== Starting 5-Bot Iterator (Seed: {random_seed}) ===")

        HISTORY_OF_ROOMS_PER_PLAYER = {
            "a": [],
            "b": [],
            "c": [],
            "d": [],
            "e": [],
        }

        # Resolve the logs base directory ONCE for this game run.
        # Everything downstream builds on this single value.
        project_logs_base_directory_path = resolve_project_logs_base_directory()
        print(
            f"Logs base directory resolved to: "
            f"{project_logs_base_directory_path}"
        )

        game_timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

        # Per-game directory derived from the base
        this_game_log_directory_path = os.path.join(
            project_logs_base_directory_path,
            f"game_{game_timestamp}",
        )
        os.makedirs(this_game_log_directory_path, exist_ok=True)

        optional_limited_view_pillar_mode_blurb = """
# Limited Sight
In this room, your line of sight is limited by thick pillars
at the corner or each floor-space. You are only able to see objects
that are directly North, South, East, and West of where you stand.

Communication with other players can bridge this Point-of-View challenge.

"""

        # 1. Initialize deterministic room and master state
        initial_room_array, initial_room_metadata = generate_deterministic_dungeon_room(random_seed, 1, 1, 1)
        master_state = build_initial_roomstory_statedictionary(
            initial_room_array,
            initial_room_metadata,
        )
        master_state['room_metadata_dict'] = initial_room_metadata

        # Export the initial start state to a JSON file

        # # colab only
        # start_state_path = f"/content/logs/game_{game_timestamp}/start_state.json"
        # os.makedirs(os.path.dirname(start_state_path), exist_ok=True)
        # try:
        #     with open(start_state_path, 'w', encoding='utf-8') as f:
        #         json.dump(master_state, f, indent=4)
        #     print(f"[Logger] Saved initial state to {start_state_path}")
        # except Exception as e:
        #     print(f"[Logger Error] Could not save start state: {e}")
        # colab or local paths OK


        start_state_path = os.path.join(
            this_game_log_directory_path, "start_state.json"
        )
        # Parent already exists, but exist_ok=True is safe
        os.makedirs(os.path.dirname(start_state_path), exist_ok=True)
        with open(start_state_path, 'w', encoding='utf-8') as start_state_file_handle:
            json.dump(master_state, start_state_file_handle, indent=4)
        print(f"[Logger] Saved initial state to {start_state_path}")


        bot_ids = ['a', 'b', 'c', 'd', 'e']
        generic_map_timeline_list = []  # Will hold up to 5 stringified board states

        continue_game = True
        current_round = 0

        # Print boot-strap pre-first of round state
        print("\n=== Map ===")
        print(extract_stringified_pov_option_room(master_state['room_array'], room_meta))
        print("\n=== Legend ===")
        print(extract_dynamic_legend(master_state))

        shared_memos = ""   # blank only on the very first iteration of round 1

        # 2. Main Game Loop
        while continue_game and current_round < max_game_rounds:

            # # round_log_path (adjust round counter to be 1-based not zero based)


            # # only colab
            # round_log_dir_path = f"/content/logs/game_{game_timestamp}/round_{current_round + 1}/"

            # colab or local paths OK
            round_log_dir_path = os.path.join(
                this_game_log_directory_path,
                f"round_{current_round + 1}",
            )

            current_round += 1
            print(f"\n{'='*40}\n=== ROUND {current_round} ===\n{'='*40}")

            continue_round_planning = True
            planning_iterator_counter = 0

            round_actions_list = []

            # Generic Maps: bootstrap
            if not generic_map_timeline_list:
                current_board_str = f"Round {current_round} Board:\n{extract_stringified_room_array(master_state['room_array'], room_meta)}"
                generic_map_timeline_list.append(current_board_str)

            # 3. Planning Loop
            while continue_round_planning and planning_iterator_counter < MAX_PLANNING_ITERATIONS:
                planning_iterator_counter += 1
                print(f"  [Planning Iteration {planning_iterator_counter}]")

                start_round_votes = 0
                round_actions_list = []  # reset for current iteration
                current_iteration_memos = ""

                # generic prompt (says 'a', but fine for all players)
                # Build the strictly formatted prompt with dynamic f-string populations
                generic_botprompt = build_dynamic_bot_prompt(
                    player_id="a",
                    round_number=current_round,
                    planning_iterator_counter=planning_iterator_counter,
                    generic_map_timeline_list=generic_map_timeline_list,
                    shared_memos_string=shared_memos,  # previous planning-iter's memos
                    room_story_state_dict=master_state,
                    pov_pillar_view=False,
                )

                # make sure generic prompt has opted-for POV blurb
                if pov_pillar_view:
                    generic_botprompt = generic_botprompt + optional_limited_view_pillar_mode_blurb

                # write generic
                write_generic_gm_dungeonsofar_log_file(
                    generic_botprompt,
                    round_log_dir_path,
                    )

                # Poll each bot
                for pid in bot_ids:
                    # Build the strictly formatted prompt with dynamic f-string populations
                    bot_prompt = build_dynamic_bot_prompt(
                        player_id=pid,
                        round_number=current_round,
                        planning_iterator_counter=planning_iterator_counter,
                        generic_map_timeline_list=HISTORY_OF_ROOMS_PER_PLAYER[pid],
                        shared_memos_string=shared_memos,  # previous planning-iter's memos
                        room_story_state_dict=master_state,
                        pov_pillar_view=pov_pillar_view,
                    )

                    # get location of player for (optional) point of view
                    # limited sight ('pillar obscured view')
                    player_coordinates_tuple = get_player_id_coordinates(
                        pid,
                        master_state,
                    )

                    # get room map (optional limited view)
                    pov_string_map = extract_stringified_pov_option_room(
                        master_state["room_array"],
                        master_state["room_metadata_dict"],
                        player_coordinates_tuple,
                        pov_pillar_view,
                    )

                    # # inspection
                    # print("====================================================================================================")
                    # print(pid)
                    # print(f"player_coordinates_tuple {player_coordinates_tuple}\n")
                    # print(f"pov_string_map {pov_string_map}")
                    # print(f"len HISTORY_OF_ROOMS_PER_PLAYER[pid]  {len(HISTORY_OF_ROOMS_PER_PLAYER[pid])}")
                    # print("\n\n\n")
                    # # print(bot_prompt)
                    # print("====================================================================================================")

                    # Execute the LLM API pipeline
                    action_data, vote_start, memo = execute_single_bot_turn_pipeline(
                        use_this_api_service, #str,  # mistral, anthropic, google
                        use_this_model,
                        pid,
                        bot_prompt,
                        game_timestamp_string=game_timestamp,
                        round_number_int=current_round
                    )

                    round_actions_list.append(action_data)

                    # # Individual Maps: bootstrap first
                    # if not HISTORY_OF_ROOMS_PER_PLAYER[pid]:
                    #     HISTORY_OF_ROOMS_PER_PLAYER[pid].append(pov_string_map)

                    # Individual Maps
                    if HISTORY_OF_ROOMS_PER_PLAYER[pid]:
                        if HISTORY_OF_ROOMS_PER_PLAYER[pid][-1] != pov_string_map:
                            HISTORY_OF_ROOMS_PER_PLAYER[pid].append(pov_string_map)

                    else: # bootstrap: add first map
                        HISTORY_OF_ROOMS_PER_PLAYER[pid].append(pov_string_map)


                    if len(HISTORY_OF_ROOMS_PER_PLAYER[pid]) > 5:
                        print(f"HISTORY_OF_ROOMS_PER_PLAYER pop for {pid}")
                        HISTORY_OF_ROOMS_PER_PLAYER[pid].pop(0)  # Keep only the last 5

                    if pov_pillar_view:
                        # for all players show their POV map
                        list_write_gm_player_pov_dungeon_map_logfile(
                            HISTORY_OF_ROOMS_PER_PLAYER[pid],
                            round_log_dir_path,
                            pid,
                            )
                    else:
                        write_gm_player_pov_dungeon_map_log_file(
                            pov_string_map,
                            round_log_dir_path,
                            pid,
                            )

                    # Defensive: handle None / empty memos
                    memo_text = (memo or "").strip() or "(no memo)"
                    current_iteration_memos += f"Player {pid} memo: {memo_text}\n\n"


                    if vote_start:
                        start_round_votes += 1

                # Manage Memo-Share Pad
                # REPLACE (don't append): next iteration sees only the latest round-table conversation
                shared_memos = current_iteration_memos.rstrip() + "\n"

                # Vote To End Planning: Check Votes: Any, one, single Yes vote ends planning.
                if start_round_votes >= 1:
                    print(f"  -> Votes to stop planning ({start_round_votes}/5 votes): Executing round.")
                    continue_round_planning = False

            # 4. Execution Phase
            print("\n[Executing Player Actions...]")
            master_state = update_dungeon_room_array_one_round(
                this_round_player_actions_list=round_actions_list,
                room_story_state_dict=master_state,
                starting_move_index_from_0_integer=0
            )

            print("[Executing NPC Actions...]")
            master_state = NPC_actions(master_state)

            print("[Calculating Resonance...]")
            item_rep, map_rep = calculate_cell_resonance_maps_reports(master_state['room_array'], room_meta)
            master_state = apply_resonance_energy_to_state(master_state, item_rep)

            print("[Executing Elemental Absorption...]")
            master_state = process_elemental_absorption(master_state)

            print("[Cleaning up Absorbed Entities...]")
            master_state = cleanup_absorbed_entities(master_state)

            # 5. Update the Rolling Timeline (Max 5 boards)
            current_board_str = f"Round {current_round} Board:\n{extract_stringified_room_array(master_state['room_array'], room_meta)}"

            # Generic Maps
            if generic_map_timeline_list:
                if generic_map_timeline_list[-1] != current_board_str:
                    generic_map_timeline_list.append(current_board_str)
            else: # bootstrap: add first map
                generic_map_timeline_list.append(current_board_str)


            if len(generic_map_timeline_list) > 5:
                generic_map_timeline_list.pop(0)  # Keep only the last 5


            # 7. Print end of round state
            print("\n=== Map ===")
            print(extract_stringified_pov_option_room(master_state['room_array'], room_meta))
            print("\n=== Legend ===")
            print(extract_dynamic_legend(master_state))

            # 8. Game End Conditions
            game_end_status = check_for_end_of_game(master_state)
            print(f"\nEnd of Round {current_round} Status: {game_end_status}")

            if game_end_status in ['solved puzzle', 'lost']:
                continue_game = False
                break

        if continue_game:
            print(f"\n=== Game Over: Max Rounds ({max_game_rounds}) Reached. Status: lost ===")
        else:
            print(f"\n=== Game Over. Final Status: {game_end_status} ===")

        # Use e.g.
        script_timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

        # # colab only
        # game_path = f"/content/logs/game_{game_timestamp}"
        # game_script_maker(
        #     game_path,
        #     f"/content/rpg_screenplay_{script_timestamp}.html",
        # )

        # # zip game files
        # zip_timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        # create_zip_archive_from_directory(
        #     source_directory_path="/content/logs",
        #     output_zip_file_path=f"/content/zipped_{zip_timestamp}",
        #     )


        # Colab or local paths OK
        game_script_maker(
            this_game_log_directory_path,
            os.path.join(
                project_logs_base_directory_path,
                f"rpg_screenplay_{script_timestamp}.html",
            ),
        )

        zip_timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        create_zip_archive_from_directory(
            source_directory_path=project_logs_base_directory_path,
            output_zip_file_path=os.path.join(
                project_logs_base_directory_path,
                f"zipped_{zip_timestamp}",
            ),
        )

    except Exception as e:
        print(f"[Critical Error] 5-bot iterator crashed: {e}")
        traceback.print_exc()

"""## Manual-Iterator-Version


"""

def interactive_game_loop_per_round_iterator(
    random_seed_integer: int,
    number_of_treasures_integer: int = 1,
    number_of_npc_integer: int = 1,
    types_of_npc_integer: int = 1,
    max_rounds: int = 100
):
    """
    An interactive version of the puzzle simulation that prompts the user for moves.

    This function spins up a game environment based on a provided seed, and then
    enters a loop asking the user to provide the desired action for each player
    character sequentially. It automatically skips players who have exited or
    been absorbed. Once all 5 actions are gathered, it applies them via the
    engine and continues to the next round until the game is won, lost, or hits
    the maximum round limit.

    It dynamically constructs and passes the new `one_player_action_data_dict` structure
    directly to the engine, including the new prompts for throwing from inventory vs grid.

    Args:
        random_seed_integer (int): Seed for deterministic room generation.
        number_of_treasures_integer (int, optional): Amount of treasure. Defaults to 1.
        number_of_npc_integer (int, optional): Amount of NPCs. Defaults to 1.
        types_of_npc_integer (int, optional): Types of NPCs. Defaults to 1.
        max_rounds (int, optional): Max allowed rounds. Defaults to 100.
    """
    try:
        print(f"\n=== Starting Interactive Puzzle (Seed: {random_seed_integer}) ===")

        # 1. Generate Room deterministically
        room_array, manual_mode_room_meta = generate_deterministic_dungeon_room(
            random_seed_integer,
            number_of_treasures_integer,
            number_of_npc_integer,
            types_of_npc_integer
        )

        # 2. Build the master state structure
        state_dict = build_initial_roomstory_statedictionary(room_array, manual_mode_room_meta)
        if not state_dict:
            print("Failed to initialize state.")
            return

        state_dict['room_metadata_dict'] = manual_mode_room_meta

        players = ['a', 'b', 'c', 'd', 'e']
        game_end_status = 'still playing'
        current_round = 0

        # 3. Print exit location to help the user plan
        try:
            door_location_name = manual_mode_room_meta.get('door_location')
            door_coords = manual_mode_room_meta.get('door_relative_position')

            print(f"For Seed {random_seed_integer}:")
            print(f"The exit is on the '{door_location_name}' wall at coordinates (row, col): {door_coords}")

        except Exception as e:
            print(f"Error finding door location: {e}")
            traceback.print_exc()

        # 4. Main Game Loop
        while game_end_status == 'still playing' and current_round < max_rounds:
            print(f"\n{'='*40}\n=== ROUND {current_round + 1} ===\n{'='*40}")

            # Print the Legend to remind the user what is on the board
            generate_legend(state_dict)

            # Visualize the start of the round
            visualize_game_timeline({current_round: state_dict}, manual_mode_room_meta)

            round_action_dicts = []

            # Collect 5 moves (one for each player character)
            for turn_idx, player in enumerate(players):

                # Check if player exited or has been absorbed
                player_id_int = manual_mode_room_meta.get('player_turn_map', {}).get(player, player)
                p_state = state_dict['object_state']['player_character_state'].get(str(player_id_int), {})

                if p_state.get('exited_room') or p_state.get('absorbed'):
                    print(f"\nPlayer {player} is not active (Exited/Absorbed). Auto-skipping.")
                    round_action_dicts.append({
                        'player_id': player,
                        'action_type': 'skip_turn'
                    })
                    continue

                # Prompt the user for an action
                print(f"\n--- Player '{player}'s Turn ---")
                print(f"Available Actions for {player}: [1] move_self, [2] throw, [3] exit_room, [0] skip/rest")
                choice = input(f"Select action for Player '{player}' (0-3): ").strip()

                # Initialize the base action dict
                action_dict = {'player_id': player}

                # Process the choice and gather any needed coordinates
                if choice == '1':
                    action_dict['action_type'] = 'move_self'
                    try:
                        fr, fc = map(int, input("From Row, Col (e.g. '4 5'): ").split())
                        tr, tc = map(int, input("To Row, Col (e.g. '4 6'): ").split())
                        action_dict['move_from_coord'] = [fr, fc]
                        action_dict['move_to_coord'] = [tr, tc]
                    except:
                        print("Invalid input, skipping turn.")
                        action_dict['action_type'] = 'skip_turn'
                elif choice == '2':
                    action_dict['action_type'] = 'throw'
                    try:
                        throw_mode = input("Throw from [1] Board or [2] Inventory? ").strip()
                        if throw_mode == '1':
                            fr, fc = map(int, input("Throw From Row, Col: ").split())
                            tr, tc = map(int, input("Throw To Row, Col: ").split())
                            action_dict['throw_from_coord'] = [fr, fc]
                            action_dict['throw_to_coord'] = [tr, tc]
                            action_dict['throw_inventory_index'] = None
                        elif throw_mode == '2':
                            inv_idx = int(input("Inventory Index to throw (e.g. 0): ").strip())
                            tr, tc = map(int, input("Throw To Row, Col: ").split())
                            action_dict['throw_from_coord'] = None
                            action_dict['throw_to_coord'] = [tr, tc]
                            action_dict['throw_inventory_index'] = inv_idx
                        else:
                            print("Invalid mode. Skipping.")
                            action_dict['action_type'] = 'skip_turn'
                    except:
                        print("Invalid input, skipping turn.")
                        action_dict['action_type'] = 'skip_turn'
                elif choice == '3':
                    action_dict['action_type'] = 'exit_room'
                    try:
                        fr, fc = map(int, input("Player Row, Col: ").split())
                        action_dict['move_from_coord'] = [fr, fc]
                    except:
                        print("Invalid input, skipping turn.")
                        action_dict['action_type'] = 'skip_turn'
                elif choice == '4' or choice == '0':
                    action_dict['action_type'] = 'skip_turn'
                else:
                    print(f"Skipping turn for {player}.")
                    action_dict['action_type'] = 'skip_turn'

                round_action_dicts.append(action_dict)

            # Execute Player Moves phase
            print("\n[Executing Player Actions...]")
            state_dict = update_dungeon_room_array_one_round(
                this_round_player_actions_list=round_action_dicts,
                room_story_state_dict=state_dict,
                starting_move_index_from_0_integer=0
            )

            # Execute NPC Actions phase
            print("[Executing NPC Actions...]")
            state_dict = NPC_actions(state_dict)

            # Execute Resonance phase
            print("[Calculating Resonance...]")
            item_rep, map_rep = calculate_cell_resonance_maps_reports(state_dict['room_array'], manual_mode_room_meta)
            state_dict = apply_resonance_energy_to_state(state_dict, item_rep)

            # Execute Elemental Absorption
            print("[Executing absorptions...]")
            process_elemental_absorption(state_dict)

            # Cleanup zero energy absorbed items
            state_dict = cleanup_absorbed_entities(state_dict)

            # Check End Conditions
            game_end_status = check_for_end_of_game(state_dict)
            print(f"\nEnd of Round {current_round + 1} Status: {game_end_status}")
            current_round += 1

        print(f"\n=== Game Over! Final Status: {game_end_status} ===")

    except Exception as e:
        print(f"Interactive loop crashed: {e}")
        traceback.print_exc()

