def build_game_plan_test_mode_prompt(
    room_story_state_dict: dict,
    past_time_results_timeline_str:str = None,
) -> str:
    """
    Constructs the prompt for a specific bot, dynamically injecting the exact current
    game state, timeline, and shared notes without hard-coding or dumping raw dicts.

    Args:
        player_id (str): The identifier of the bot (e.g., 'a', 'b', 'c', 'd', 'e').
        round_number (int): Current round of the game.
        planning_iterator_counter (int): The current planning iteration within the round.
        generic_map_timeline_list (list): The last N (up to 5) stringified board states.
        shared_memos_string (str): Concatenated notes from all bots in previous iterations.
        room_story_state_dict (dict): The master state dictionary.

    Returns:
        str: The fully populated prompt string ready for the LLM.
    """
    try:
        # 1. Extract clean state representations
        room_metadata = room_story_state_dict.get('room_metadata_dict', {})
        room_array = room_story_state_dict.get('room_array', [])

        # --- Extract Door Location for Prompt ---
        # Safely retrieve the door location and coordinates from the metadata
        door_location_name_string = room_story_state_dict["room_metadata_dict"].get('door_location', 'Unknown')
        door_coordinates_tuple = room_story_state_dict["room_metadata_dict"].get('door_relative_position', 'Unknown')

        # Format the information into a clear, readable string
        door_information_blurb = f"The exit door is located on the '{door_location_name_string}' wall at coordinates (row, col): {door_coordinates_tuple}."

        # get location of player for (optional) point of view
        # limited sight ('pillar obscured view')
        player_coordinates_tuple = get_player_id_coordinates(
            player_id_string,
            room_story_state_dictionary,
        )

        # get room map (optional limited view)
        stringified_map = extract_stringified_pov_option_room(
            room_array,
            room_metadata,
            player_coordinates_tuple,
            pov_pillar_obscured_view=False,
        )

        dynamic_legend = extract_dynamic_legend(room_story_state_dict)

        # 2. Define the static rules (strictly unchanged as requested)
        rules_instructions_blurb = f"""# Task/Rules/Instructions:

You are player {player_id}, take your action:
1. State your action for this round in valid json (default is skip_turn)
2. To end planning and start this round,
say (in addition to your action): ```json\n"start_round": true\n```

## Rules:
1.  Binary Goal:
- The whole party defeats monster(s) and leaves the room with treasure, or not.

2. "Five elements" Resonance Governs Interaction & Energy:
- Everything in dungeon is an 'object' with resonance
- Element-Resonance-Effects are area-of-effect: 8 neighbor-spaces around object/player
- Help-resonance generates +1 energy for the helped, no cost to helper.
- Harm-resonance subtracts & transfers -1 energy from harmed to harmer.
- Energy is >= 0

3. Elemental Resonance:
   - Helps: water->forest->fire->void->ice->water
   - Harms: water->fire->ice->forest->void->water

4. Players have one action per turn:
- The action-sequence ("initiative") for players is always a-e
  (alphabetical == chronological).
- What is randomized per room is the integer-id,
  so the placement of player in the room,
  and their elemental alignment.

5. Player-Character-Action Options:
- 'move': Move one space. including diagonal (8 neighbor-spaces)
- 'throw': Relocate adjacent (8 neighbor-spaces) object/player,
    or inventory item, to any empty space
- 'exit_room': Must be at door to exit
- 'skip_turn': No cost

6. Action Cost:
- Player action (move/throw/exit) costs/requires 1-energy
- Monster/npc require >=1 energy to move, but movement costs nothing

7. Absorption: Absorb object into your inventory
- If absorbed object has inventory items, they move to your inventory
- If object-A helps object-B, but object-A has no energy,
   then object-B 'absorbs, carries' object-A as an inventory-item.
- Absorption costs nothing: (like resonance-effect) absorption happens \
  with no 'action' required.
- This is how 'monsters' are removed from the board.
- This is how treasure is collected.

8. Format & Example json For Action:
{one_player_dict_example}

9. Monster/NPC Behavior:
- For a given type of NPC, you do not know what their actions will be.
You will need to re-try a room based on a past record and timeline.

A past timeline from this same random-seed:
{past_time_results_timeline_str}

## Output that you need to produce:
- A successful game plan.
"""

        # 2. Construct the dynamic gamestate blurb
        gamestate_blurb = f"""Round: {round_number}

=== Starting Room-State Map ===
{stringified_map}

=== Exit Location ===
{door_information_blurb}

=== Legend (Starting State) ===
{dynamic_legend}

"""

        # 6. Assemble final prompt
        game_plan_instructions_prompt = f"""# Game-Plan-Test Mode:
Produce a complete game place including each player's actions in one \
list of player-action-dictionaires. This will be evaluted for the binary goal \
as pass or fail.

{rules_instructions_blurb}

Game State:
{gamestate_blurb}
"""
        return game_plan_instructions_prompt

    except Exception as e:
        print(f"[Critical Error] Failed to build dynamic prompt for bot {player_id}: {e}")
        traceback.print_exc()
        return ""

"""
Whole Game Prompt Generator & Evaluator

This cell provides tools to:
1. Generate the complete, comprehensive prompt (rules + current state) for a given seed.
2. Evaluate a submitted 'whole game' plan strictly as PASS or FAIL.
"""
import traceback
import math


def generate_whole_game_prompt(
    random_seed_integer: int = 42,
    number_of_treasures_integer: int = 1,
    number_of_npc_integer: int = 1,
    types_of_npc_integer: int = 1,
    past_time_results_timeline_str: str = None,
) -> str:
    """
    Generates a comprehensive instruction and state prompt for a whole-game solver.

    Args:
        random_seed_integer (int): The deterministic seed for room generation.
        number_of_treasures_integer (int): Quantity of treasures.
        number_of_npc_integer (int): Quantity of NPCs.
        types_of_npc_integer (int): Variety of NPC types.

    Returns:
        str: A fully formatted string containing all rules, the map, and the legend.
    """
    try:
        # Generate room and state
        room_array_list, room_metadata_dictionary = generate_deterministic_dungeon_room(
            random_seed_integer=random_seed_integer,
            number_of_treasures_integer=number_of_treasures_integer,
            number_of_npc_integer=number_of_npc_integer,
            types_of_npc_integer=types_of_npc_integer
        )

        if not room_array_list:
            return "[Error] Room generation failed."

        initial_state_dictionary = build_initial_roomstory_statedictionary(
            starting_room_array=room_array_list,
            starting_room_metadata_dict=room_metadata_dictionary
        )
        initial_state_dictionary['room_array'] = room_array_list
        initial_state_dictionary['room_metadata_dict'] = room_metadata_dictionary

        """
        def build_game_plan_test_mode_prompt(
            room_story_state_dict: dict,
            past_time_results_timeline_str:list = None,
        ) -> str:
        """
        # Build the final prompt block
        prompt_string = build_game_plan_test_mode_prompt(
            room_story_state_dict=initial_state_dictionary,
            past_time_results_timeline_str=past_time_results_timeline_str,
        )

        return prompt_string

    except Exception as prompt_generation_error:
        print(f"[Critical Error] Failed to generate whole game prompt: {prompt_generation_error}")
        traceback.print_exc()
        return ""


def evaluate_whole_game_plan(
    random_seed_integer: int,
    solution_action_dict_list: list
) -> tuple:
    """
    Evaluates a submitted 'whole game' plan and strictly returns PASS or FAIL.

    Args:
        random_seed_integer (int): The deterministic seed for room generation.
        solution_action_dict_list (list): The user's complete chronological plan of actions.

    Returns:
        (str, str, list)
        - str: 'PASS' if the puzzle is fully solved, 'FAIL' otherwise.
        - str: stringified timeline
        - list: history list
    """
    try:
        print(f"\n=== Evaluating Whole Game Strategy (Seed: {random_seed_integer}) ===")

        # Calculate the intended number of rounds based on the submitted moves
        total_moves_integer = len(solution_action_dict_list)
        max_rounds_integer = math.ceil(total_moves_integer / 5)
        if max_rounds_integer < 1:
            max_rounds_integer = 1

        # Execute the puzzle simulation pipeline
        final_game_status_string, string_formatted_timeline, raw_timeline, execution_error_string = execute_v4_puzzle_evaluation(
            random_seed_integer=random_seed_integer,
            number_of_treasures_integer=1,
            number_of_npc_integer=1,
            types_of_npc_integer=1,
            solution_action_dict_list=solution_action_dict_list,
            max_rounds_integer=max_rounds_integer
        )

        if execution_error_string:
            print(f"Execution Error Output: {execution_error_string}")

        # Strict evaluation: anything other than 'solved puzzle' is a FAIL.
        if final_game_status_string == 'solved puzzle':
            print("\n[Evaluation Result]: PASS")
            return "PASS", string_formatted_timeline, raw_timeline
        else:
            print(f"\n[Evaluation Result]: FAIL (Status reached: {final_game_status_string})")
            return "FAIL", string_formatted_timeline, raw_timeline

    except Exception as strategy_test_error:
        print(f"[Critical Error] Failed to evaluate whole game strategy: {strategy_test_error}")
        traceback.print_exc()
        return "ERROR"

